assist_settings_general_item_usb_update_error_removed_usb_stick = TextObject(cs_CZ="Zařízení USB bylo odebráno. Pro provedení aktualizace jej znovu připojte.", da_DK="USB-apparatet blev fjernet. Tilslut det igen for at udføre opdateringen.", de_DE="Das USB-Gerät wurde entfernt. Bitte schließe es erneut an, um das Update durchzuführen.", el_GR="Η συσκευή USB έχει αφαιρεθεί. Επανασυνδέστε την, για να πραγματοποιήσετε την αναβάθμιση.", en_GB="The USB device was removed. Please reconnect it to perform the update.", es_ES="El dispositivo USB se ha retirado. Vuelva a conectarlo para ejecutar la actualización.", fi_FI="USB-laite poistettiin. Liitä se uudelleen suorittaaksesi päivityksen.", fr_FR="Le périphérique USB a été retiré. Veuillez le reconnecter pour effectuer la mise à jour.", hu_HU="Az USB-eszközt eltávolították. Csatlakoztasd újra a frissítés elvégzéséhez.", it_IT="Il dispositivo USB è stato rimosso. Ricollegarlo per eseguire l'update.", nl_NL="Het USB-apparaat is verwijderd. Sluit het opnieuw aan om de update uit te voeren.", no_NO="USB-enheten ble fjernet. Sett den inn igjen for å utføre oppdateringen.", pl_PL="Urządzenie USB zostało odłączone. Aby przeprowadzić aktualizację, podłącz je ponownie.", pt_PT="O aparelho USB foi eliminado. Por favor, volta a ligá-lo para realizar a atualização.", ru_RU="USB-устройство было извлечено. Подключите его снова, чтобы выполнить обновление.", sv_SE="USB-enheten har avlägsnats. Anslut den igen för att genomföra uppdateringen.", tr_TR="USB aygıtı çıkarıldı. Lütfen güncellemeyi uygulamak için yeniden bağla.")
assist_settings_general_item_usb_update_error_unknown = TextObject(bs_BA="Došlo je do nepoznate greške.", cs_CZ="Vyskytla se neznámá chyba.", da_DK="Ukendt fejl opstået", de_DE="Es ist ein unbekannter Fehler aufgetreten.", el_GR="Προέκυψε ένα άγνωστο σφάλμα.", en_GB="An unknown error has occurred.", es_ES="Se ha producido un error desconocido.", fi_FI="Tuntematon virhe.", fr_FR="Une erreur inconnue s'est produite.", hr_HR="Pojavila se nepoznata greška.", hu_HU="Ismeretlen hiba lépett fel.", it_IT="Si è verificato un errore sconosciuto.", nl_NL="Er is een onbekende fout opgetreden.", no_NO="Det har oppstått en ukjent feil.", pl_PL="Wystąpił nieznany błąd.", pt_PT="Ocorreu um erro desconhecido.", ro_RO="A apărut o eroare necunoscută.", ru_RU="Произошла неизвестная ошибка.", sk_SK="Vyskytla sa neznáma chyba", sl_SI="Prišlo je do neznane napake.", sr_RS="Došlo je do nepoznate greške.", sv_SE="Ett okänt fel har uppstått.", tr_TR="Bilinmeyen bir hata oluştu.", uk_UA="Сталася невідома помилка.")
assist_settings_general_item_usb_update_error_validation_failed = TextObject(cs_CZ="Jazykové údaje jsou nesprávné.", da_DK="Sprogdataene er fejlbehæftede.", de_DE="Die Sprachdaten sind fehlerhaft.", el_GR="Τα φωνητικά δεδομένα είναι ελαττωματικά.", en_GB="The language data are corrupt.", es_ES="Los datos de voz son incorrectos.", fi_FI="Kielitiedot ovat virheelliset.", fr_FR="Les données linguistiques sont erronées.", hu_HU="A hangadatok hibásak.", it_IT="I dati vocali sono errati.", nl_NL="De taalgegevens zijn foutief.", no_NO="Det er feil i språkdataene.", pl_PL="Dane językowe są nieprawidłowe.", pt_PT="Os dados de voz apresentam erros.", ru_RU="Голосовые данные неправильные.", sv_SE="Fel på språkdatan.", tr_TR="Dil verileri hatalı.")
assist_settings_general_item_usb_update_overwrite_mathing_version_files = TextObject(cs_CZ="Chcete přepsat jazykové údaje stejnou verzí?", da_DK="Vil du overskrive de talte data med den samme version?", de_DE="Möchtest du die Sprachdaten mit der gleichen Version überschreiben?", el_GR="Θέλετε να αντικαταστήσετε τα δεδομένα ομιλίας με την ίδια έκδοση;", en_GB="Would you like to overwrite the language data with the same version?", es_ES="¿Desea sobrescribir los datos de voz con la misma versión?", fi_FI="Haluatko korvata puhetiedot samalla versiolla?", fr_FR="Souhaitez-vous écraser les données linguistiques avec la même version?", hu_HU="Ugyanazzal a változattal szeretnéd felülírni a hangadatokat?", it_IT="Sovrascrivere i dati vocali con la stessa versione?", nl_NL="Wil je de taalgegevens met dezelfde versie overschrijven?", no_NO="Vil du at stemmedataene overskrives med samme versjon?", pl_PL="Czy chccesz zastąpić dane głosowe tą samą wersją?", pt_PT="Queres gravar os dados de voz com a mesma versão?", ru_RU="Хотите перезаписать голосовые данные той же версии?", sv_SE="Vill du skriva över språkdatan med samma version?", tr_TR="Dil verilerinin üzerine aynı sürümü yazmak ister misin?")
assist_settings_general_item_usb_update_progress = TextObject(cs_CZ="Aktualizace jazykových dat (%1 %)", da_DK="Opdatering af talte data (%1 %)", de_DE="Aktualisierung der Sprachdaten (%1 %)", el_GR="Ενημέρωση των δεδομένων ομιλίας (%1 %)", en_GB="Speech data update (%1 %)", es_ES="Actualizar datos de voz (%1 %)", fi_FI="Puhetietojen päivitys (%1 %)", fr_FR="Actualisation des données linguistiques (%1 %)", hu_HU="Hangadatok frissítése (%1 %)", it_IT="Aggiornamento dei dati vocali (%1%)", nl_NL="Actualisering van taalgegevens (%1 %)", no_NO="Oppdatering av stemmedata (%1 %)", pl_PL="Aktualizacja danych językowych (%1 %)", pt_PT="Atualização dos dados de voz (%1 %)", ru_RU="Обновление голосовых данных (%1 %)", sv_SE="Uppdatering av språkdata (%1 %)", tr_TR="Ses verilerinin güncellenmesi (%1 %)")
assist_settings_general_item_usb_update_success = TextObject(cs_CZ="Aktualizace jazykových dat proběhla úspěšně.", da_DK="Opdatering af talte data blev gennemført korrekt.", de_DE="Die Aktualisierung der Sprachdaten war erfolgreich.", el_GR="Η ενημέρωση των δεδομένων γλώσσας ήταν επιτυχής.", en_GB="The speech data was updated successfully.", es_ES="Los datos de voz se han actualizado correctamente.", fi_FI="Puhetietojen päivitys onnistui.", fr_FR="La mise à jour des données linguistiques a été réalisée avec succès.", hu_HU="A hangadatok frissítése sikeres volt.", it_IT="L'aggiornamento dei dati vocali è riuscito.", nl_NL="De taalgegevens zijn bijgewerkt.", no_NO="Stemmedataene ble oppdatert.", pl_PL="Aktualizacja danych głosowych powiodła się.", pt_PT="A atualização dos dados de voz foi bem sucedida.", ru_RU="Обновление голосовых данных прошло успешно.", sv_SE="Uppdateringen av språkdata lyckades.", tr_TR="Dil verilerinin güncellenmesi başarılı oldu.")
