assist_settings_general_usb_update_not_finished = TextObject(cs_CZ="Potřebná jazyková data se právě aktualizují. Audi assistant není\nmomentálně k dispozici. Zkuste to prosím znovu později.", da_DK="De nødvendige talte data opdateres stadig.\nAudi assistant er ikke til rådighed p.t. Forsøg igen senere.", de_DE="Die Sprachdaten werden aktualisiert. Der Audi assistant steht\nzurzeit nicht zur Verfügung. Bitte versuche es später noch einmal", el_GR="Γίνεται ενημέρωση των φωνητικών δεδομένων. Η Audi assistant\nπρος το παρόν δεν είναι διαθέσιμη. Προσπαθήστε ξανά αργότερα.", en_GB="The speech data are still being updated. The Audi assistant is\ncurrently unavailable. Please try again later.", es_ES="Actualizando los datos de voz. El Audi assistant no está\ndisponible actualmente. Inténtelo de nuevo más tarde", fi_FI="Tarvittavia puhetietoja päivitetään edelleen. Audi assistant ei ole\ntällä hetkellä käytettävissä. Yritä myöhemmin uudelleen.", fr_FR="Actualisation des données linguistiques en cours. Audi assistant\nnon disponible actuellement. Réessayez ultérieurement", hu_HU="A hangadatok frissítése még folyamatban van. Az Audi assistant\njelenleg nem áll rendelkezésre. Próbáld újra később", it_IT="L'aggiornamento dei dati vocali necessari è in corso. L'Audi\nassistant non è disponibile al momento. Riprovare più tardi.", nl_NL="De taalgegevens worden bijgewerkt. De Audi assistant is\nmomenteel niet beschikbaar. Probeer het later opnieuw", no_NO="Stemmedataene blir oppdatert. Audi assistant er ikke\ntilgjengelig nå. Prøv igjen senere", pl_PL="Dane głosowe są aktualizowane. Audi assistant jest obecnie\nniedostępny. Spróbuj ponownie później", pt_PT="Os dados de voz serão atualizados. O Audi assistant não está\ndisponível de momento.Por favor, volta a tentar mais tarde", ru_RU="Необходимые голосовые данные все еще обновляются. Audi\nassistant сейчас недоступен. Повторите попытку позже.", sv_SE="Språkdata uppdateras. Audi assistant är för närvarande\ninte tillgänglig. Försök igen senare", tr_TR="Dil verileri güncelleniyor. Audi assistant şu anda mevcut değil.\nLütfen daha sonra tekrar dene")
assist_settings_general_usb_update_user_cancel = TextObject(cs_CZ="Instalace byla přerušena.", da_DK="Installation blev afbrudt.", de_DE="Die Installation wurde abgebrochen.", el_GR="Η εγκατάσταση διακόπηκε.", en_GB="The installation has been cancelled.", es_ES="La instalación se ha cancelado.", fi_FI="Asennus keskeytyi.", fr_FR="L'installation a été annulée.", hu_HU="A telepítés megszakadt.", it_IT="L'installazione è stata interrotta.", nl_NL="De installatie is geannuleerd.", no_NO="Installeringen er avbrutt.", pl_PL="Instalowanie zostało anulowane.", pt_PT="A instalação foi interrompida.", ru_RU="Установка была прервана.", sv_SE="Installationen avbröts.", tr_TR="Kurulum iptal edildi.")
assist_settings_help_car_item_batterie = TextObject(cs_CZ="„Deaktivuj varování rychlostního limitu.“", da_DK="\"Deaktiver hastighedsgrænseadvarsel.\"", de_DE="„Deaktiviere die Tempolimitwarnung.“", el_GR="«Απενεργοποιήστε την προειδοποίηση ορίου ταχύτητας».", en_GB="\"Deactivate the speed limit warning.\"", es_ES="\"Desactiva el aviso del límite de velocidad.\"", fi_FI="\"Deaktivoi nopeusvaroitus.\"", fr_FR="«Désactive l'alerte de survitesse.»", hu_HU="„Kapcsold ki a sebességkorlátozás-figyelmeztetést.”", it_IT="\"Disattiva l'avvertimento limite di velocità.\"", nl_NL="\"Snelheidslimietwaarschuwing deactiveren.\"", no_NO="«Deaktiver fartsgrensevarslingen.»", pl_PL="„Wyłącz ostrzeganie o ograniczeniu prędkości.”", pt_PT="\"Desativar a advertência da velocidade.\"", ru_RU="«Отключи предупреждение об ограничении скорости».", sv_SE="”Avaktivera hastighetsbegränsningsvarningen.”", tr_TR="\"Hız sınırı uyarısını devre dışı bırak.\"")
assist_settings_help_car_item_batterie_aiscreen = TextObject(cs_CZ="„Ahoj Audi, deaktivuj varování\nrychlostního limitu.“", da_DK="\"Hey Audi, deaktiver\nhastighedsgrænseadvarslen.\"", de_DE="„Hey Audi, deaktiviere die\nTempolimitwarnung.“", el_GR="«Γεια Audi, απενεργοποίησε την\nπροειδοποίηση ορίου ταχύτητας.\"", en_GB="\"Hey Audi, deactivate the speed\nlimit warning.\"", es_ES="\"Hey, Audi, desactiva el aviso del\nlímite de velocidad.\"", fi_FI="\"Hei Audi, deaktivoi\nnopeusvaroitus.\"", fr_FR="«Hey Audi, désactive l'alerte de\nsurvitesse.»", hu_HU="„Hey Audi, kapcsold ki a\nsebességkorlátozás-figyelmez.t.“", it_IT="\"Ehi Audi, disattiva l'avvertimento\nlimite di velocità.\"", nl_NL="\"Hé Audi, deactiveer de\nsnelheidslimietwaarschuwing.\"", no_NO="«Hey Audi, deaktiver\nfartsgrensevarslingen.»", pl_PL="„Hey Audi, wyłącz ostrzeganie o\nograniczeniu prędkości.”", pt_PT="\"Olá Audi, desativa a advertência\nde velocidade.\"", ru_RU="«Отключи предупреждение об\nограничении скорости».", sv_SE="”Hej Audi, avaktivera\nhastighetsbegränsningsvarn.”", tr_TR="\"Hey Audi, hız sınırı uyarısını devre\ndışı bırak.\"")
assist_settings_help_car_item_batterie_desc = TextObject(cs_CZ="Zobrazí se nabídka asistence řidiče.", da_DK="Førerassistentmenuen bliver vist.", de_DE="Das Fahrerassistenzmenü wird angezeigt.", el_GR="Εμφανίζεται το μενού υποβοήθησης οδηγού.", en_GB="The driver assist menu will be shown.", es_ES="Mostrando el menú de asistencia al conductor.", fi_FI="Kuljettajan apujärjestelmien valikko tulee näkyviin.", fr_FR="Affichage du menu Aides au conducteur.", hu_HU="Megjelenik a Vezetőasszisztens menü.", it_IT="Viene visualizzato il menu dell'assistenza al conducente.", nl_NL="Het menu voor de bestuurdershulp wordt weergegeven.", no_NO="Førerassistentmenyen vises.", pl_PL="Wyświetlane jest menu asysty kierowcy.", pt_PT="O menu da assistência à condução será apresentado.", ru_RU="Отображается меню ассистентов водителя.", sv_SE="Förarassistansmenyn visas.", tr_TR="Sürücü asistanı menüsü gösterilir.")
assist_settings_help_car_item_distance = TextObject(cs_CZ="\"Jak daleko ještě dojedu?\"", da_DK="\"Hvor meget længere kan jeg køre?\"", de_DE="„Wie weit komme ich noch?“", el_GR="\"Πόσο μακριά μπορώ να πάω ακόμη;\"", en_GB="\"How much further can I go?\"", es_ES="\"¿Hasta dónde voy a llegar?\"", fi_FI="\"Kuinka pitkälle vielä pääsen?\"", fr_FR="«Combien de kilomètres puis-je encore parcourir?»", hu_HU="„Meddig juthatok el?”", it_IT="\"Quanta strada posso ancora fare?\"", nl_NL="\"Hoe ver kan ik nog rijden?\"", no_NO="«Hvor langt kan jeg kjøre?»", pl_PL="„Jak daleko jeszcze zajadę?”", pt_PT="\"Até onde é que ainda posso ir?\"", ru_RU="«Сколько я могу еще проехать?»", sv_SE="”Hur långt kommer jag?”", tr_TR="\"Daha ne kadar gidebilirim?\"")
assist_settings_help_car_item_distance_aiscreen = TextObject(cs_CZ="„Ahoj Audi, jak daleko ještě\ndojedu?“", da_DK="\"Hey Audi, hvor meget længere\nkan jeg køre?\"", de_DE="„Hey Audi, wie weit komme\nich noch?“", el_GR="\"Γεια σου Audi, πόσο μακριά\nμπορώ να πάω ακόμη;\"", en_GB="\"Hey Audi, how much further can I\ngo?\"", es_ES="\"Hey, Audi, ¿hasta dónde voy a\nllegar?\"", fi_FI="\"Hei Audi, kuinka pitkälle vielä\npääsen?\"", fr_FR="«Hey Audi, combien de kilomètres\npuis-je encore parcourir?»", hu_HU="„Hey Audi, meddig juthatok el?”", it_IT="\"Ehi Audi, quanta strada posso\nancora fare?\"", nl_NL="\"Hey Audi, hoe ver kan ik nog\nrijden?\"", no_NO="«Hey Audi, hvor langt kan jeg\nkjøre?»", pl_PL="„Hey Audi, jak daleko jeszcze\nzajadę?”", pt_PT="\"Olá Audi, até onde é que ainda\nposso ir?\"", ru_RU="«Привет Audi, сколько я могу еще\nпроехать?»", sv_SE="”Hej Audi, hur långt kommer jag?”", tr_TR="\"Hey Audi, daha ne kadar\ngidebilirim?\"")
assist_settings_help_car_item_distance_desc = TextObject(cs_CZ="Audi assistant Vám sdělí Váš zbytkový dojezd.", da_DK="Audi assistant giver dig besked om din resterende rækkevidde.", de_DE="Der Audi assistant teilt dir deine Restreichweite mit.", el_GR="Η Audi assistant θα σας ενημερώνει για την υπολειπόμενη αυτονομία σας.", en_GB="The Audi assistant will inform you of your remaining range.", es_ES="El Audi assistant le indicará la autonomía restante.", fi_FI="Audi assistant ilmoittaa sinulle jäljellä olevan toimintamatkan.", fr_FR="L'Audi assistant vous communique votre autonomie restante.", hu_HU="Az Audi assistant tájékoztat a fennmaradó hatótávolságról.", it_IT="L'Audi assistant comunica l'autonomia residua.", nl_NL="De Audi assistant laat je de resterende afstand weten.", no_NO="Audi assistant forteller deg hva gjenværende rekkevidde er.", pl_PL="Audi assistant komunikuje Ci pozostały zasięg.", pt_PT="O Audi assistant informa-te da tua autonomia.", ru_RU="Audi assistant сообщает вам оставшийся запас хода.", sv_SE="Audi assistant meddelar dig din återstående räckvidd.", tr_TR="Audi assistant sana kalan menzilini söyler.")
assist_settings_help_car_item_drive_select = TextObject(cs_CZ="\"Nastav drive select na comfort.\"", da_DK="\"Indstil drive select til comfort.\"", de_DE="„Stelle drive select auf comfort.“", el_GR="\"Ρύθμισε το drive select σε comfort.\"", en_GB="\"Set drive select to comfort.\"", es_ES="\"Ajusta drive select a comfort.\"", fi_FI="\"Valitse drive select -tila comfort.\"", fr_FR="«Règle le drive select sur comfort.»", hu_HU="„Állítsd a drive select-et comfort-ra.”", it_IT="\"Imposta drive select su comfort.\"", nl_NL="\"Stel drive select in op comfort.\"", no_NO="«Sett Drive select på comfort.»", pl_PL="„Ustaw drive select na comfort”.", pt_PT="\"Regula drive select para comfort.\"", ru_RU="«Установи drive select на comfort».", sv_SE="”Ställ drive select på comfort.”", tr_TR="\"Drive select'i comfort olarak ayarla.\"")
