assist_settings_help_car_item_hud = TextObject(cs_CZ="\"Ukaž šířku vozidla na displeji Head-up.\"", da_DK="\"Vis bilens bredde i head-up-displayet.\"", de_DE="„Zeige die Fahrzeugbreite im Head-up-Display an.“", el_GR="\"Εμφάνισε το πλάτος του οχήματος στην οθόνη head-up.\"", en_GB="\"Show the vehicle width on the head-up display.\"", es_ES="\"Muestra el ancho del vehículo en el Head-up Display.\"", fi_FI="\"Näytä auton leveys tuulilasinäytöllä.\"", fr_FR="«Affiche la largeur du véhicule dans l'affichage tête haute.»", hu_HU="„Mutasd meg a jármű szélességét a head-up kijelzőn.”", it_IT="\"Mostra la larghezza della vettura sull'head-up display.\"", nl_NL="\"Laat de voertuigbreedte op het head-up display zien.\"", no_NO="«Vis bilens bredde på head-up-displayet.»", pl_PL="„Pokaż szerokość pojazdu na wyświetlaczu przeziernym”.", pt_PT="\"Mostra a largura do veículo no Head-up Display.\"", ru_RU="«Покажи ширину автомобиля на проекционном дисплее».", sv_SE="”Visa fordonsbredden på Head up-displayen.”", tr_TR="\"Araç genişliğini Head-up ekranda göster.\"")
assist_settings_help_car_item_hud_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, ukaž šířku vozidla na\ndispleji Head-up.\"", da_DK="\"Hey Audi, vis bilens bredde i\nhead-up-displayet.\"", de_DE="„Zeige die Fahrzeugbreite im\nHead-up-Display an.“", el_GR="\"Εμφάνισε το πλάτος του οχήματος\nστην οθόνη head-up.\"", en_GB="\"Hey Audi, show the vehicle width\non the head-up display.\"", es_ES="\"Hey, Audi, muestra el ancho del\nvehículo en el Head-up Display.\"", fi_FI="\"Hei Audi, näytä auton leveys\ntuulilasinäytöllä.\"", fr_FR="«Affiche la largeur du véhicule\ndans l'affichage tête haute.»", hu_HU="„Hey Audi, mutasd meg a jármű\nszélességét a head-up kijelzőn.”", it_IT="\"Ehi Audi, mostra la larghezza\ndella vettura sull'head-up display.\"", nl_NL="\"Hey Audi, laat de voertuigbreedte\nop het head-up display zien.\"", no_NO="«Hey Audi, vis bilens bredde på\nhead-up-displayet.»", pl_PL="„Pokaż szerokość pojazdu na\nwyświetlaczu przeziernym”.", pt_PT="\"Olá Audi, mostra a largura do\nveículo no Head-up Display.\"", ru_RU="«Покажи ширину автомобиля на\nпроекционном дисплее».", sv_SE="”Hej Audi, visa fordonsbredden på\nHead up-displayen.”", tr_TR="\"Hey Audi, araç genişliğini\nHead-up ekranda göster.\"")
assist_settings_help_car_item_hud_desc = TextObject(cs_CZ="Šířka vozidla se zobrazí na displeji Head-up.", da_DK="Bilens bredde vises i head-up-displayet.", de_DE="Die Fahrzeugbreite erscheint im Head-up-Display.", el_GR="Το πλάτος του οχήματος θα εμφανιστεί στην οθόνη head-up.", en_GB="The vehicle width will appear on the head-up display.", es_ES="El ancho del vehículo aparece en el Head-up Display.", fi_FI="Auton leveys ilmestyy tuulilasinäytölle.", fr_FR="La largeur du véhicule est indiquée dans l'affichage tête haute.", hu_HU="A jármű szélessége megjelenik a head-up kijelzőn.", it_IT="La larghezza della vettura viene visualizzata sull'head-up display.", nl_NL="De voertuigbreedte verschijnt in het head-up display.", no_NO="Bilens bredde vises på head-up-displayet.", pl_PL="Szerokość pojazdu pojawia się na wyświetlaczu przeziernym.", pt_PT="A largura do veículo é apresentada no Head-up Display.", ru_RU="Ширина автомобиля отображается на проекционном дисплее.", sv_SE="Fordonets bredd visas på head up-displayen.", tr_TR="Araç genişliği Head-up ekranda belirir.")
assist_settings_help_car_item_light_assistant = TextObject(cs_CZ="\"Nastav vnitřní osvětlení na světlejší.\"", da_DK="\"Indstil kabinelyset lysere.\"", de_DE="„Stelle das Innenlicht heller.“", el_GR="\"Αύξησε τη φωτεινότητα του εσωτερικού φωτισμού.\"", en_GB="\"Make the interior lighting brighter.\"", es_ES="\"Pon la luz interior más clara.\"", fi_FI="\"Säädä sisävaloa kirkkaammaksi.\"", fr_FR="«Éclaircis l'éclairage intérieur.»", hu_HU="„Állítsd világosabbra a belső világítást.”", it_IT="\"Aumenta la luminosità delle luci interne.\"", nl_NL="\"Zet de binnenverlichting feller.\"", no_NO="«Gjør kupélyset lysere.»", pl_PL="„Ustaw jaśniejsze oświetlenie wewnętrzne”.", pt_PT="\"Regula a luz interior para mais clara.\"", ru_RU="«Сделай ярче свет в салоне».", sv_SE="”Öka ljusstyrkan för kupébelysningen.”", tr_TR="\"İç ışığı daha aydınlık yap.\"")
assist_settings_help_car_item_light_assistant_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, nastav vnitřní\nosvětlení na světlejší.\"", da_DK="\"Hey Audi, indstil kabinelyset\nlysere.\"", de_DE="„Hey Audi, stelle das Innenlicht\nheller.“", el_GR="\"Αύξησε τη φωτεινότητα του\nεσωτερικού φωτισμού.\"", en_GB="\"Hey Audi, make the interior\nlighting brighter.\"", es_ES="\"Hey, Audi, pon la luz interior más\nclara.\"", fi_FI="\"Hei Audi, säädä sisävaloa\nkirkkaammaksi.\"", fr_FR="«Hey Audi, éclaircis l'éclairage\nintérieur.»", hu_HU="„Hey Audi, állítsd világosabbra a\nbelső világítást.”", it_IT="\"Ehi Audi, aumenta la luminosità\ndelle luci interne.\"", nl_NL="\"Hey Audi, zet de\nbinnenverlichting feller.\"", no_NO="«Hey Audi, gjør kupélyset lysere.»", pl_PL="„Hey Audi, ustaw jaśniejsze\noświetlenie wewnętrzne”.", pt_PT="\"Olá Audi, regula a luz interior\npara mais clara.\"", ru_RU="«Привет Audi, сделай внутреннее\nосвещение светлее».", sv_SE="”Hej Audi, öka ljusstyrkan för\nkupébelysningen.”", tr_TR="\"Hey Audi, iç ışığı daha aydınlık\nyap.\"")
assist_settings_help_car_item_light_assistant_desc = TextObject(cs_CZ="Vnitřní osvětlení se nastaví na světlejší.", da_DK="Kabinelyset indstilles lysere.", de_DE="Die Innenraumbeleuchtung wird heller eingestellt.", el_GR="Ο εσωτερικός φωτισμός θα ρυθμιστεί σε μεγαλύτερη φωτεινότητα.", en_GB="The interior lighting will be made brighter.", es_ES="Ajustando una iluminación interior más clara.", fi_FI="Sisävalaistusta säädetään kirkkaammaksi.", fr_FR="Éclaircissement de l'éclairage de l'habitacle.", hu_HU="A belső világítás világosabbra állítva.", it_IT="L'illuminazione dell'abitacolo diventa più luminosa.", nl_NL="De binnenverlichting wordt feller gezet.", no_NO="Kupébelysningen blir lysere.", pl_PL="Zostaje ustawione jaśniejsze oświetlenie wnętrza.", pt_PT="A iluminação interior foi regulada para mais clara.", ru_RU="Освещение салона становится ярче.", sv_SE="Ökar kupébelysningens ljusstyrka.", tr_TR="İç aydınlatma daha parlak olarak ayarlanıyor.")
assist_settings_help_car_item_lowering_air_spring = TextObject(cs_CZ="\"Sniž vzduchové pružení.\"", da_DK="\"Sænk luftaffjedringen.\"", de_DE="„Senke die Luftfeder ab.“", el_GR="\"Χαμήλωσε την πνευματική ανάρτηση.\"", en_GB="\"Lower the air suspension.\"", es_ES="\"Baja la suspensión neumática.\"", fi_FI="\"Laske ilmajousitusta.\"", fr_FR="«Abaisse la suspension pneumatique.»", hu_HU="„Engedd le a légrugózást.”", it_IT="\"Abbassa le sospensioni pneumatiche.\"", nl_NL="\"Verlaag de luchtvering.\"", no_NO="«Senk luftfjæringen.»", pl_PL="„Obniż zawieszenie pneumatyczne”.", pt_PT="\"Baixa a suspensão pneumática.\"", ru_RU="«Опусти пневматическую подвеску».", sv_SE="”Sänk fjädringen.”", tr_TR="\"Havalı süspansiyonu indir.\"")
