assist_settings_help_car_item_menu_desc = TextObject(cs_CZ="Zobrazuje se nabídka vozidla.", da_DK="Bilmenuen bliver vist.", de_DE="Das Fahrzeugmenü wird angezeigt.", el_GR="Εμφανίζεται το μενού οχήματος.", en_GB="The vehicle menu will be displayed.", es_ES="Mostrando el menú del vehículo.", fi_FI="Auton valikko näytetään.", fr_FR="Affichage du menu Véhicule.", hu_HU="Megjelenik a járműmenü.", it_IT="Viene visualizzato il menù Vettura.", nl_NL="Het voertuigmenu wordt weergegeven.", no_NO="Bilmenyen vises.", pl_PL="Zostaje wyświetlone menu pojazdu.", pt_PT="O menu do veículo será apresentado.", ru_RU="Отображается меню автомобиля.", sv_SE="Fordonsmenyn visas.", tr_TR="Araç menüsü gösteriliyor.")
assist_settings_help_car_item_mirror = TextObject(cs_CZ="\"Ukaž mi nastavení mého podvozku.\"", da_DK="\"Vis mig mine undervognsindstillinger.\"", de_DE="„Zeig mir meine Fahrwerkeinstellungen.“", el_GR="\"Δείξε μου τις ρυθμίσεις ανάρτησής μου.\"", en_GB="\"Show me my suspension settings.\"", es_ES="\"Muéstrame mis ajustes del tren de rodaje.\"", fi_FI="\"Näytä alusta-asetukseni.\"", fr_FR="«Affiche-moi les réglages de la suspension.»", hu_HU="„Mutasd meg a futómű-beállításaimat.”", it_IT="\"Mostrami le impostazioni dell'assetto.\"", nl_NL="\"Laat me mijn onderstelinstellingen zien.\"", no_NO="«Vis meg understellsinnstillingene.»", pl_PL="„Pokaż mi moje ustawienia zawieszenia”.", pt_PT="\"Mostra-me os meus ajustes da suspensão.\"", ru_RU="\"Покажи мне настройки ходовой части\".", sv_SE="”Visa mig mina chassiinställningar.”", tr_TR="\"Bana yürüyen aksam ayarlarımı göster.\"")
assist_settings_help_car_item_mirror_desc = TextObject(cs_CZ="Zobrazují se nastavení podvozku", da_DK="Undervognsindstillingerne vises.", de_DE="Die Fahrwerkeinstellungen werden angezeigt.", el_GR="Θα εμφανιστούν οι ρυθμίσεις της ανάρτησης", en_GB="The suspension settings will be displayed", es_ES="Mostrando los ajustes del tren de rodaje", fi_FI="Alusta-asetukset tulevat näkyviin", fr_FR="Affichage des réglages de la suspension", hu_HU="Megjelennek a futómű-beállítások", it_IT="Vengono visualizzate le impostazioni dell'assetto", nl_NL="De onderstelinstellingen worden weergegeven", no_NO="Understellsinnstillingene vises", pl_PL="Zostają wyświetlone ustawienia zawieszenia", pt_PT="Os ajustes da suspensão serão apresentados", ru_RU="Отображаются настройки ходовой части", sv_SE="Chassiinställningarna visas", tr_TR="Yürüyen aksam ayarları gösterilir")
assist_settings_help_car_item_park = TextObject(cs_CZ="\"Zapni pomoc při parkování.\"", da_DK="\"Aktiver parkeringshjælpen.\"", de_DE="„Schalte die Einparkhilfe ein.“", el_GR="\"Ενεργοποίησε τη βοήθεια στάθμευσης.\"", en_GB="\"Switch the parking aid on.\"", es_ES="\"Activa la ayuda de aparcamiento.\"", fi_FI="\"Kytke pysäköintitutka päälle.\"", fr_FR="«Active l'aide au stationnement.»", hu_HU="„Kapcsold be a parkolássegítőt.”", it_IT="\"Attiva ausilio al parcheggio.\"", nl_NL="\"Schakel de parkeerhulp in.\"", no_NO="«Slå på parkeringshjelpen.»", pl_PL="„Włącz asystenta parkowania”.", pt_PT="\"Liga o auxiliar de estacionamento.\"", ru_RU="«Включи парковочный ассистент».", sv_SE="”Aktivera parkeringshjälpen.”", tr_TR="\"Park yardımını aç.\"")
assist_settings_help_car_item_park_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, zapni pomoc při\nparkování.\"", da_DK="\"Hey Audi, aktiver\nparkeringshjælpen.\"", de_DE="„Hey Audi, schalte die\nEinparkhilfe ein.“", el_GR="\"Γεια σου Audi, ενεργοποίησε τη\nβοήθεια στάθμευσης.\"", en_GB="\"Hey Audi, switch the parking aid\non.\"", es_ES="\"Hey, Audi, activa la ayuda de\naparcamiento.\"", fi_FI="\"Hei Audi, kytke pysäköintitutka\npäälle.\"", fr_FR="«Hey Audi, active l'aide au\nstationnement.»", hu_HU="„Hey Audi, kapcsold be a\nparkolássegítőt.”", it_IT="\"Ehi Audi, attiva ausilio al\nparcheggio.\"", nl_NL="\"Hey Audi, schakel de parkeerhulp\nin.\"", no_NO="«Hey Audi, slå på\nparkeringshjelpen.»", pl_PL="„Hey Audi, włącz asystenta\nparkowania”.", pt_PT="\"Olá Audi, liga o auxiliar de\nestacionamento.\"", ru_RU="«Привет Audi, включи\nпарковочный ассистент».", sv_SE="”Hej Audi, aktivera\nparkeringshjälpen.”", tr_TR="\"Hey Audi, park yardımını aç.\"")
assist_settings_help_car_item_park_desc = TextObject(cs_CZ="Pomoc při parkování se aktivuje.", da_DK="Parkeringshjælpen aktiveres.", de_DE="Die Einparkhilfe wird aktiviert.", el_GR="Θα ενεργοποιηθεί η βοήθεια στάθμευσης.", en_GB="The parking aid will be activated.", es_ES="Activando la ayuda de aparcamiento.", fi_FI="Pysäköintitutka aktivoidaan.", fr_FR="Activation de l'aide au stationnement.", hu_HU="A parkolássegítő aktiválásra kerül.", it_IT="Viene attivato l'ausilio al parcheggio.", nl_NL="De parkeerhulp wordt geactiveerd.", no_NO="Parkeringshjelpen aktiveres.", pl_PL="Asystent parkowania zostaje włączony.", pt_PT="O auxiliar de estacionamento será ativado.", ru_RU="Парковочный ассистент активируется.", sv_SE="Parkeringshjälpen aktiveras.", tr_TR="Park yardımı etkinleştiriliyor.")
assist_settings_help_car_item_percent = TextObject(cs_CZ="„Ukaž mi nastavení displeje.“", da_DK="\"Vis mig displayindstillingerne.\"", de_DE="„Zeige mir die Displayeinstellungen.“", el_GR="\"Δείξε μου τις ρυθμίσεις οθόνης.\"", en_GB="\"Show me the display settings.\"", es_ES="\"Muéstrame los ajustes de la pantalla.\"", fi_FI="\"Näytä näyttöasetukset.\"", fr_FR="«Affiche-moi les réglages de l'écran.»", hu_HU="„Mutasd a kijelzőbeállításokat.”", it_IT="\"Mostrami le impostazioni del display.\"", nl_NL="\"Laat mij de display-instellingen zien.\"", no_NO="«Vis meg displayinnstillingene.»", pl_PL="„Pokaż ustawienia ekranu.”", pt_PT="\"Mostra-me os ajustes do ecrã.\"", ru_RU="«Покажи настройки дисплея».", sv_SE="”Visa mig displayinställningarna.”", tr_TR="\"Bana ekran ayarlarını göster.\"")
assist_settings_help_car_item_percent_aiscreen = TextObject(cs_CZ="„Ahoj Audi, ukaž mi nastavení\ndispleje.“", da_DK="\"Hey Audi, vis mig\ndisplayindstillingerne.\"", de_DE="„Hey Audi, zeige mir die\nDisplayeinstellungen.“", el_GR="\"Γεια σου Audi, δείξε μου τις\nρυθμίσεις οθόνης.\"", en_GB="\"Hey Audi, show me the display\nsettings.\"", es_ES="\"Hey, Audi, muéstrame los ajustes\nde la pantalla.\"", fi_FI="\"Hei Audi, näytä näyttöasetukset.\"", fr_FR="«Hey Audi, affiche-moi les\nréglages de l'écran.»", hu_HU="„Hey Audi, mutasd a\nkijelzőbeállításokat.”", it_IT="\"Ehi Audi, mostrami le\nimpostazioni del display.\"", nl_NL="\"Hé Audi, laat mij de\ndisplay-instellingen zien.\"", no_NO="«Hey Audi, vis meg\ndisplayinnstillingene.»", pl_PL="„Hey Audi, pokaż ustawienia\nekranu.”", pt_PT="\"Olá Audi, mostra-me os ajustes\ndo ecrã.\"", ru_RU="«Привет Audi, покажи мне\nнастройки дисплея».", sv_SE="”Hej Audi, visa mig\ndisplayinställningarna.”", tr_TR="\"Hey Audi, bana ekran ayarlarını\ngöster.\"")
assist_settings_help_car_item_percent_desc = TextObject(cs_CZ="Zobrazí se nastavení displeje.", da_DK="Displayindstillingerne bliver vist.", de_DE="Die Displayeinstellungen werden angezeigt.", el_GR="Εμφανίζονται οι ρυθμίσεις οθόνης.", en_GB="The display settings will be shown", es_ES="Mostrando los ajustes de la pantalla.", fi_FI="Näyttöasetukset tulevat näkyviin.", fr_FR="Affichage des réglages de l'écran.", hu_HU="Megjelennek a kijelzőbeállítások.", it_IT="Vengono visualizzate le impostazioni del display.", nl_NL="De display-instellingen worden weergegeven.", no_NO="Displayinnstillingene vises.", pl_PL="Zostają wyświetlone ustawienia ekranu.", pt_PT="Os ajustes do ecrã serão apresentados.", ru_RU="Отображаются настройки дисплея.", sv_SE="Displayinställningarna visas.", tr_TR="Ekran ayarları gösterilir.")
assist_settings_help_car_item_speed = TextObject(cs_CZ="„Aktivuj centrální zamykání.“", da_DK="\"Aktiver centrallås.\"", de_DE="„Aktiviere die Zentralverriegelung.“", el_GR="\"Ενεργοποίησε το κεντρικό κλείδωμα.\"", en_GB="\"Activate central locking\"", es_ES="\"Activa el cierre centralizado.\"", fi_FI="\"Aktivoi keskuslukitus.\"", fr_FR="«Active le verrouillage centralisé.»", hu_HU="„Kapcsold be a központi zárat.”", it_IT="\"Attiva la chiusura centralizzata.\"", nl_NL="\"Activeer de centrale vergrendeling.\"", no_NO="«Aktiver sentrallåsen.»", pl_PL="„Włącz centralny zamek.”", pt_PT="\"Ativa o fecho centralizado.\"", ru_RU="«Активируй центральный замок».", sv_SE="”Aktivera centrallåset.”", tr_TR="\"Merkezi kilitlemeyi etkinleştir.\"")
assist_settings_help_car_item_speed_aiscreen = TextObject(cs_CZ="„Ahoj Audi, aktivuj centrální\nzamykání.“", da_DK="\"Hey Audi, aktiver centrallås.\"", de_DE="„Hey Audi, aktiviere die\nZentralverriegelung.“", el_GR="«Γεια Audi, ενεργοποίησε το\nκεντρικό κλείδωμα».", en_GB="\"Hey Audi, activate the central\nlocking.\"", es_ES="\"Hey, Audi, activa el cierre\ncentralizado.\"", fi_FI="\"Hei Audi, aktivoi keskuslukitus.\"", fr_FR="«Hey Audi, active le verrouillage\ncentralisé.»", hu_HU="„Hey Audi, kapcsold be a központi\nzárat.“", it_IT="\"Ehi Audi, attiva la chiusura\ncentralizzata.\"", nl_NL="\"Hey Audi, activeer de centrale\nvergrendeling.\"", no_NO="«Hey Audi, aktiver sentrallåsen.»", pl_PL="„Hey Audi, włącz centralny\nzamek.”", pt_PT="Olá Audi, ativa o fecho\ncentralizado.\"", ru_RU="«Привет Audi, активируй\nцентральный замок».", sv_SE="”Hej Audi, aktivera centrallåset.”", tr_TR="\"Hey Audi, merkezi kilitlemeyi\netkinleştir.\"")
assist_settings_help_car_item_speed_desc = TextObject(cs_CZ="Centrální zamykání se aktivuje pro všechny dveře.", da_DK="Centrallås til alle døre aktiveres.", de_DE="Die Zentralverriegelung für alle Türen wird aktiviert.", el_GR="Ενεργοποιείται το κεντρικό κλείδωμα για όλες τις πόρτες.", en_GB="The central locking has been activated for all doors.", es_ES="Activando el cierre centralizado en todas las puertas.", fi_FI="Kaikkien ovien keskuslukitus aktivoidaan.", fr_FR="Activation du verrouillage centralisé pour toutes les portes.", hu_HU="A központi zár minden ajtónál bekapcsolásra kerül.", it_IT="Viene attivata la chiusura centralizzata per tutte le porte.", nl_NL="De centrale vergrendeling voor alle deuren wordt geactiveerd.", no_NO="Sentrallåsen aktiveres for alle dørene.", pl_PL="Zostaje włączony centralny zamek dla wszystkich drzwi.", pt_PT="O fecho centralizado será ativado para todas as portas.", ru_RU="Активируется центральный замок всех дверей.", sv_SE="Centrallåset för alla dörrar aktiveras.", tr_TR="Merkezi kilitleme tüm kapılar için etkinleştiriliyor.")
assist_settings_help_car_item_warning = TextObject(cs_CZ="„Ukaž mi nastavení asistence řidiče.“", da_DK="\"Vis mig førerassistentindstillingerne.\"", de_DE="„Zeige mir die Fahrerassistenzeinstellungen.“", el_GR="\"Δείξε μου τις ρυθμίσεις υποβοήθησης οδηγού.\"", en_GB="\"Show me the driver assist settings.\"", es_ES="\"Muéstrame los ajustes de la asistencia al conductor.\"", fi_FI="\"Näytä kuljettajan apujärjestelmien asetukset.\"", fr_FR="«Affiche-moi les réglages des aides au conducteur.»", hu_HU="„Mutasd a vezetőasszisztens-beállításokat.”", it_IT="\"Mostrami le impostazioni dell'assistenza al conducente.\"", nl_NL="\"Laat mij de instellingen voor de bestuurdershulp zien.\"", no_NO="«Vis meg innstillingene for førerassistentsystemer.»", pl_PL="„Pokaż ustawienia asysty kierowcy.”", pt_PT="\"Mostra os ajustes da assistência de condução.\"", ru_RU="«Покажи настройки ассистирующих систем».", sv_SE="”Visa mig förarassistansinställningarna.”", tr_TR="\"Bana sürücü asistanı ayarlarını göster.\"")
assist_settings_help_car_item_warning_aiscreen = TextObject(cs_CZ="„Ahoj Audi, ukaž mi nastavení\nasistence řidiče.“", da_DK="\"Hey Audi, vis mig\nførerassistentindstillingerne.\"", de_DE="„Hey Audi, zeige mir die\nFahrerassistenzeinstellungen.“", el_GR="\"Γεια σου Audi, δείξε μου τις\nρυθμίσεις υποβοήθησης οδηγού.\"", en_GB="\"Hey Audi, show me the driver\nassist settings.\"", es_ES="\"Hey, Audi, muéstrame los ajustes\nde la asistencia al conductor.\"", fi_FI="\"Hei Audi, näytä kuljettajan\napujärjestelmien asetukset.\"", fr_FR="«Hey Audi, affiche-moi les\nréglages des aides au conducteur»", hu_HU="„Hey Audi, mutasd a\nvezetőasszisztens-beállításokat.”", it_IT="\"Ehi Audi, mostrami le impostazio-\nni dell'assistenza al conducente.\"", nl_NL="\"Hé Audi, laat mij de instellingen\nvoor de bestuurdershulp zien.\"", no_NO="«Hey Audi, vis meg innstillingene\nfor førerassistentsystemer.»", pl_PL="„Hey Audi, pokaż ustawienia\nasysty kierowcy.”", pt_PT="\"Olá Audi mostra-me os ajustes da\nassistência à condução.\"", ru_RU="«Покажи мне настройки\nассистирующих систем».", sv_SE="”Hej Audi, visa mig\nförarassistansinställningarna.”", tr_TR="\"Hey Audi, bana sürücü asistanı\nayarlarını göster.\"")
assist_settings_help_car_item_warning_desc = TextObject(cs_CZ="Zobrazí se nabídka asistence řidiče.", da_DK="Førerassistentmenuen bliver vist.", de_DE="Das Fahrerassistenzmenü wird angezeigt.", el_GR="Εμφανίζεται το μενού υποβοήθησης οδηγού.", en_GB="The driver assist menu will be shown.", es_ES="Mostrando el menú de asistencia al conductor.", fi_FI="Kuljettajan apujärjestelmien valikko tulee näkyviin.", fr_FR="Affichage du menu Aides au conducteur.", hu_HU="Megjelenik a Vezetőasszisztens menü.", it_IT="Viene visualizzato il menu dell'assistenza al conducente.", nl_NL="Het menu voor de bestuurdershulp wordt weergegeven.", no_NO="Førerassistentmenyen vises.", pl_PL="Wyświetlane jest menu asysty kierowcy.", pt_PT="O menu da assistência à condução será apresentado.", ru_RU="Отображается меню ассистентов водителя.", sv_SE="Förarassistansmenyn visas.", tr_TR="Sürücü asistanı menüsü gösterilir.")
assist_settings_help_car_item_warning_storage = TextObject(cs_CZ="\"Ukaž mi paměť výstrah.\"", da_DK="\"Vis mig advarselshukommelsen.\"", de_DE="„Zeige mir den Warnspeicher.“", el_GR="\"Δείξε μου τα αποθηκευμένα προειδοποιητικά μηνύματα.\"", en_GB="\"Show me the warning memory.\"", es_ES="\"Muéstrame la memoria de advertencia.\"", fi_FI="\"Näytä minulle varoitusmuisti.\"", fr_FR="«Affiche-moi la mémoire des avertissements.»", hu_HU="„Mutasd meg a figyelmeztetésmemóriát.”", it_IT="\"Mostrami la memoria avvertimenti.\"", nl_NL="\"Laat mij het waarschuwingsgeheugen zien.\"", no_NO="«Vis meg varselminnet.»", pl_PL="„Wyświetl pamięć ostrzeżeń”.", pt_PT="\"Mostra-me a memória de advertências.\"", ru_RU="«Покажи мне память предупреждений».", sv_SE="”Visa mig varningsminnet.”", tr_TR="\"Bana uyarı belleğini göster.\"")
assist_settings_help_car_item_warning_storage_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, ukaž mi paměť\nvýstrah.\"", da_DK="\"Hey Audi, vis mig\nadvarselshukommelsen.\"", de_DE="„Hey Audi, zeige mir\nden Warnspeicher.“", el_GR="\"Γεια σου Audi, δείξε μου τη μνήμη\nπροειδοποιητικών μηνυμάτων.\"", en_GB="\"Hey Audi, show me the warning\nmemory.\"", es_ES="\"Hey, Audi, muéstrame la\nmemoria de advertencia.\"", fi_FI="\"Hei Audi, näytä minulle\nvaroitusmuisti.\"", fr_FR="«Hey Audi, affiche-moi la mémoire\ndes avertissements.»", hu_HU="„Hey Audi, mutasd meg a\nfigyelmeztetésmemóriát.”", it_IT="\"Ehi Audi, mostrami la memoria\navvertimenti.\"", nl_NL="\"Hey Audi, laat mij het\nwaarschuwingsgeheugen zien.\"", no_NO="«Hey Audi, vis meg varselminnet.»", pl_PL="„Hey Audi, wyświetl pamięć\nostrzeżeń”.", pt_PT="\"Olá Audi, mostra-me a memória\nde advertências.\"", ru_RU="«Привет Audi, покажи мне\nпамять предупреждений».", sv_SE="”Hej Audi, visa mig\nvarningsminnet.”", tr_TR="\"Hey Audi, bana uyarı belleğini\ngöster.\"")
assist_settings_help_car_item_warning_storage_desc = TextObject(cs_CZ="Zobrazí se přehled varovných hlášení.", da_DK="Oversigt over advarsler vises.", de_DE="Die Übersicht der Warnmeldungen wird angezeigt.", el_GR="Θα εμφανιστεί η επισκόπηση των προειδοποιητικών μηνυμάτων.", en_GB="The overview of warning messages will be shown.", es_ES="Se muestra la lista de avisos.", fi_FI="Yhteenveto varoituksista näytetään.", fr_FR="Affichage de la vue d'ensemble des messages d'alerte.", hu_HU="Megjelenik a figyelmeztető üzenetek áttekintése.", it_IT="Viene visualizzato l'elenco degli avvertimenti.", nl_NL="Het overzicht van de waarschuwingsmeldingen wordt weergegeven.", no_NO="Oversikten over advarsler vises.", pl_PL="Zostaje wyświetlony przegląd komunikatów ostrzegawczych.", pt_PT="A lista das mensagens de advertência será apresentada.", ru_RU="Отображается список предупреждений.", sv_SE="Översikten för varningsminnet visas.", tr_TR="Uyarıların özeti gösteriliyor.")
assist_settings_help_climate_item_air_front_feet = TextObject(cs_CZ="\"Vzduch v celém vozidle do oblasti nohou.\"", da_DK="\"Luft til fodrummet overalt i bilen.\"", de_DE="„Luft überall im Fahrzeug auf den Fußbereich.“", el_GR="\"Αέρας παντού στο όχημα προς την περιοχή των ποδιών.\"", en_GB="\"Ventilation at foot level in entire vehicle.\"", es_ES="\"Aire a los pies en todas las plazas.\"", fi_FI="\"Ilmaa jalkatilaan kaikkialle autoon.\"", fr_FR="«De l'air dans tout le véhicule vers la zone des pieds.»", hu_HU="„Irányítsd a levegőt az egész járműben a lábtérre.”", it_IT="\"Aria in tutta la vettura nella zona dei piedi.\"", nl_NL="\"Overal in het voertuig ventilatie bij het voetengebied.\"", no_NO="«Før luften mot gulvet i hele bilen.»", pl_PL="„Nawiew w całym samochodzie na nogi”.", pt_PT="\"Ar em todo o veículo para a zona dos pés.\"", ru_RU="«Вентиляция во всем салоне автомобиля в области ног».", sv_SE="”Fläkt i golvutrymmet i hela bilen.”", tr_TR="\"Hava aracın her yerinde ayak alanına.\"")
assist_settings_help_climate_item_air_front_feet_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, vzduch v celém vozidle\ndo oblasti nohou.\"", da_DK="\"Hey Audi, luft til fodrummet\noveralt i bilen.\"", de_DE="„Hey Audi, Luft überall im\nFahrzeug auf den Fußbereich.“", el_GR="\"Αέρας παντού στο όχημα προς την\nπεριοχή των ποδιών.\"", en_GB="\"Hey Audi, ventilation at foot level\nin entire vehicle.\"", es_ES="\"Hey, Audi, aire a los pies en todas\nlas plazas.\"", fi_FI="\"Hei Audi, ilmaa jalkatilaan\nkaikkialle autoon.\"", fr_FR="«Hey Audi, de l'air dans tout le\nvéhicule vers la zone des pieds.»", hu_HU="„Hey Audi, irányítsd a levegőt az\negész járműben a lábtérre.”", it_IT="\"Ehi Audi, aria in tutta la vettura\nnella zona dei piedi.\"", nl_NL="\"Hey Audi, overal in het voertuig\nventilatie bij het voetengebied.\"", no_NO="«Hey Audi, før luften mot gulvet i\nhele bilen.»", pl_PL="„Hey Audi, nawiew w całym\nsamochodzie na nogi”.", pt_PT="\"Olá Audi, ar em todo o veículo\npara a zona dos pés.\"", ru_RU="«Вентиляция во всем салоне\nавтомобиля в области ног».", sv_SE="”Hej Audi, fläkt i golvutrymmet i\nhela bilen.”", tr_TR="\"Hey Audi, hava aracın her yerinde\nayak alanına.\"")
assist_settings_help_climate_item_air_front_feet_desc = TextObject(cs_CZ="Větrání se v celém vozidle nastaví do oblasti nohou.", da_DK="Ventilationen indstilles til fodrummet overalt i bilen.", de_DE="Die Lüftung wird überall im Fahrzeug auf den Fußbereich gestellt.", el_GR="Ο αερισμός θα ρυθμιστεί παντού στο όχημα προς την περιοχή των ποδιών.", en_GB="The ventilation will be set to foot level in the entire vehicle.", es_ES="La ventilación se ajusta a los pies en todas las plazas.", fi_FI="Jalkatilan tuuletus kytketään päälle kaikkialle autoon.", fr_FR="Réglage de la ventilation dans tout le véhicule vers la zone des pieds.", hu_HU="A szellőztetés az egész járműben a lábtérre irányul.", it_IT="Viene impostata la ventilazione nel vano piedi in tutta la vettura.", nl_NL="Overal in het voertuig wordt de ventilatie bij het voetengebied ingesteld.", no_NO="Ventilasjonen rettes mot gulvet i hele bilen.", pl_PL="Wentylacja w całym samochodzie zostaje ustawiona na strefę nóg.", pt_PT="A ventilação em todo o veículo será direcionada para a zona dos pés.", ru_RU="Вентиляция во всем салоне автомобиля устанавливается на зону ног", sv_SE="Fläkten i hela bilen ställs in på golvutrymmet.", tr_TR="Havalandırma aracın her yerinde ayak alanına ayarlanıyor.")
assist_settings_help_climate_item_automatic = TextObject(cs_CZ="\"Aktivuj automatickou klimatizaci.\"", da_DK="\"Aktiver det automatiske klimaanlæg.\"", de_DE="„Aktiviere die Klimaautomatik.“", el_GR="\"Ενεργοποίησε τον αυτόματο κλιματισμό.\"", en_GB="\"Activate automatic air conditioner.\"", es_ES="\"Enciende el climatizador automático.\"", fi_FI="\"Aktivoi automaatti-ilmastointi.\"", fr_FR="«Active la climatisation automatique.»", hu_HU="„Kapcsold be az automatikus klímát.”", it_IT="\"Attiva il climatizzatore automatico.\"", nl_NL="\"Activeer automatische airco.\"", no_NO="«Aktiver klimaautomatikken.»", pl_PL="„Włącz klimatyzację automatyczną”.", pt_PT="\"Ativa o ar condicionado automático.\"", ru_RU="«Включи климат-контроль».", sv_SE="”Aktivera den automatiska klimatanläggningen.”", tr_TR="\"Otomatik klimayı etkinleştir.\"")
assist_settings_help_climate_item_automatic_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, aktivuj automatickou\nklimatizaci.\"", da_DK="\"Hey Audi, aktiver det automatiske\nklimaanlæg.\"", de_DE="„Hey Audi, aktiviere die\nKlimaautomatik.“", el_GR="\"Γεια σου Audi, ενεργοποίησε τον\nαυτόματο κλιματισμό.\"", en_GB="\"Hey Audi, activate automatic air\nconditioner.\"", es_ES="\"Hey, Audi, enciende el\nclimatizador automático.\"", fi_FI="\"Hei Audi, aktivoi\nautomaatti-ilmastointi.\"", fr_FR="«Hey Audi, active la climatisation\nautomatique.»", hu_HU="„Hey Audi, kapcsold be az\nautomatikus klímát.”", it_IT="\"Ehi Audi, attiva il climatizzatore\nautomatico.\"", nl_NL="\"Hey Audi, activeer automatische\nairco.\"", no_NO="«Hey Audi, aktiver\nklimaautomatikken.»", pl_PL="„Hey Audi, włącz klimatyzację\nautomatyczną”.", pt_PT="\"Olá Audi, ativa o ar condicionado\nautomático.\"", ru_RU="«Привет Audi, включи\nклимат-контроль».", sv_SE="”Hej Audi, aktivera den\nautomatiska klimatanläggningen.”", tr_TR="\"Hey Audi, otomatik klimayı\netkinleştir.\"")
assist_settings_help_climate_item_automatic_desc = TextObject(cs_CZ="Automatická klimatizace se zapíná.", da_DK="Automatisk klimaanlæg aktiveres.", de_DE="Die Klimaautomatik wird eingeschaltet.", el_GR="Θα ενεργοποιηθεί ο αυτόματος κλιματισμός.", en_GB="The automatic air conditioner will be switched on.", es_ES="Encendiendo el climatizador automático.", fi_FI="Automaatti-ilmastointi kytketään päälle.", fr_FR="Activation de la climatisation automatique.", hu_HU="Az automatikus klímaberendezés bekapcsolásra kerül.", it_IT="Si accende il climatizzatore automatico.", nl_NL="De automatische airco wordt ingeschakeld.", no_NO="Klimaautomatikken blir slått på.", pl_PL="Zostaje włączona klimatyzacja automatyczna.", pt_PT="O ar condicionado automático será ligado.", ru_RU="Климат-контроль включается.", sv_SE="Den automatiska klimatanläggningen aktiveras.", tr_TR="Otomatik klima açılıyor.")
assist_settings_help_climate_item_back = TextObject(cs_CZ="\"Mám studená záda.\"", da_DK="\"Jeg fryser på ryggen.\"", de_DE="„Mein Rücken ist kalt.“", el_GR="\"Η πλάτη μου είναι κρύα.\"", en_GB="\"My back's cold.\"", es_ES="\"Tengo frío en la espalda.\"", fi_FI="\"Selkäni on kylmä.\"", fr_FR="«J'ai froid au dos.»", hu_HU="„Hideg a hátam.”", it_IT="\"Ho freddo alla schiena.\"", nl_NL="\"Mijn rug is koud.\"", no_NO="«Jeg er kald på ryggen.»", pl_PL="„Zimno mi w plecy”.", pt_PT="\"As minhas costas estão frias.\"", ru_RU="«Моя спина холодная».", sv_SE="”Min rygg är kall.”", tr_TR="\"Sırtım soğuk.\"")
assist_settings_help_climate_item_back_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, mám studená záda.\"", da_DK="\"Hey Audi, jeg fryser på ryggen.\"", de_DE="„Hey Audi, mein Rücken ist kalt.“", el_GR="\"Γεια σου Audi, η πλάτη μου είναι\nκρύα.\"", en_GB="\"Hey Audi, my back's cold.\"", es_ES="\"Hey, Audi, tengo frío en la\nespalda.\"", fi_FI="\"Hei Audi, selkäni on kylmä.\"", fr_FR="«Hey Audi, j'ai froid au dos.»", hu_HU="„Hey Audi, hideg a hátam.”", it_IT="\"Ehi Audi, ho freddo alla schiena.\"", nl_NL="\"Hey Audi, mijn rug is koud.\"", no_NO="«Hey Audi, jeg er kald på ryggen.»", pl_PL="„Hey Audi, zimno mi w plecy”.", pt_PT="\"Olá Audi, as minhas costas estão\nfrias.\"", ru_RU="«Привет Audi, мне холодно\nспине».", sv_SE="”Hej Audi, min rygg är kall.”", tr_TR="\"Hey Audi, sırtım soğuk.\"")
assist_settings_help_climate_item_back_desc = TextObject(cs_CZ="Vyhřívání sedadla mluvčího se aktivuje.", da_DK="Sædevarmen aktiveres for den talende.", de_DE="Die Sitzheizung des Sprechers wird aktiviert.", el_GR="Θα ενεργοποιηθεί η θέρμανση του καθίσματος του ομιλούντα.", en_GB="The seat heating will be activated for the person speaking.", es_ES="Calentando el asiento del usuario.", fi_FI="Puhujan istuinlämmitys aktivoidaan.", fr_FR="Activation du chauffage du siège du locuteur.", hu_HU="A beszélő ülésfűtése aktiválásra kerül.", it_IT="Viene attivato il riscaldamento del sedile di chi parla.", nl_NL="De stoelverwarming van de spreker wordt geactiveerd.", no_NO="Setevarmen aktiveres for den som snakker.", pl_PL="Zostaje aktywowane podgrzewanie siedzenia osoby mówiącej.", pt_PT="O aquecimento do banco do locutor será ativado.", ru_RU="Активируется обогрев сиденья говорящего.", sv_SE="Stolsvärmen aktiveras för talaren.", tr_TR="Konuşmacının koltuk ısıtması etkinleştiriliyor.")
assist_settings_help_climate_item_cold = TextObject(cs_CZ="\"Je mi zima.\"", da_DK="\"Jeg fryser.\"", de_DE="„Mir ist kalt.“", el_GR="\"Κρυώνω.\"", en_GB="\"I'm cold.\"", es_ES="\"Tengo frío.\"", fi_FI="\"Minulla on kylmä.\"", fr_FR="«J'ai froid.»", hu_HU="„Fázom.”", it_IT="\"Ho freddo.\"", nl_NL="\"Ik heb het koud.\"", no_NO="«Jeg fryser.»", pl_PL="„Jest mi zimno”.", pt_PT="\"Tenho frio.\"", ru_RU="«Мне холодно».", sv_SE="”Jag fryser.”", tr_TR="\"Ben üşüdüm.\"")
assist_settings_help_climate_item_cold_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, je mi zima.\"", da_DK="\"Hey Audi, jeg fryser.\"", de_DE="„Hey Audi, mir ist kalt.“", el_GR="\"Γεια σου Audi, κρυώνω.\"", en_GB="\"Hey Audi, I'm cold.\"", es_ES="\"Hey, Audi, tengo frío.\"", fi_FI="\"Hei Audi, minulla on kylmä.\"", fr_FR="«Hey Audi, j'ai froid.»", hu_HU="„Hey Audi, fázom.”", it_IT="\"Ehi Audi, ho freddo.\"", nl_NL="\"Hey Audi, ik heb het koud.\"", no_NO="«Hey Audi, jeg fryser.»", pl_PL="„Hey Audi, jest mi zimno”.", pt_PT="\"Olá Audi, tenho frio.\"", ru_RU="«Привет Audi, мне холодно».", sv_SE="”Hej Audi, jag fryser.”", tr_TR="\"Hey Audi, ben üşüdüm.\"")
assist_settings_help_climate_item_cold_desc = TextObject(cs_CZ="Funkce klimatizace mluvčího se odpovídajícím způsobem přizpůsobí.", da_DK="Den talendes klimafunktioner tilpasses i henhold til dette.", de_DE="Die Klimafunktionen des Sprechers werden entsprechend angepasst.", el_GR="Θα γίνει αντίστοιχη προσαρμογή των λειτουργιών κλιματισμού για τον ομιλούντα.", en_GB="The air conditioning functions will be adjusted for the person speaking.", es_ES="Adaptando la calefacción del usuario.", fi_FI="Puhujan ilmastointitoimintoja säädetään pyynnön mukaisesti.", fr_FR="Modification en conséquence des fonctions de la climatisation du locuteur.", hu_HU="A beszélő klímafunkciói ennek megfelelően kerülnek beállításra.", it_IT="Vengono modificate di conseguenza le funzioni di climatizzazione di chi parla.", nl_NL="De aircofuncties van de spreker worden aangepast zoals gewenst.", no_NO="Klimafunksjonene blir tilpasset ønsket til den som snakker.", pl_PL="Funkcje klimatyzacji rozmówcy zostają odpowiednio dostosowane.", pt_PT="As funções do ar condicionado do locutor sero adequadamente adaptadas.", ru_RU="Функции климата на стороне говорящего настраиваются соответствующим образом.", sv_SE="Klimatfunktionerna anpassas på motsvarande sätt för talaren.", tr_TR="Konuşmacının klima fonksiyonları uygun şekilde uyarlanıyor.")
assist_settings_help_climate_item_cold_feet = TextObject(cs_CZ="\"Mám studené nohy.\"", da_DK="\"Jeg fryser om mine fødder.\"", de_DE="„Meine Füße sind kalt.“", el_GR="\"Τα πόδια μου κρυώνουν.\"", en_GB="\"My feet are cold.\"", es_ES="\"Tengo frío en los pies.\"", fi_FI="\"Jalkani ovat kylmät.\"", fr_FR="«J'ai froid aux pieds.»", hu_HU="„Fázik a lábam.”", it_IT="\"Ho i piedi freddi.\"", nl_NL="\"Mijn voeten zijn koud.\"", no_NO="«Jeg er kald på føttene.»", pl_PL="„Zimno mi w stopy”.", pt_PT="\"Os meus pés estão frios.\"", ru_RU="«У меня мерзнут ноги».", sv_SE="”Mina fötter är kalla.”", tr_TR="\"Ayaklarım üşüdü.\"")
assist_settings_help_climate_item_cold_feet_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, mám studené nohy.\"", da_DK="\"Hey Audi, jeg fryser om mine\nfødder.\"", de_DE="„Hey Audi, meine Füße sind kalt.“", el_GR="\"Γεια σου Audi, τα πόδια μου\nκρυώνουν.\"", en_GB="\"Hey Audi, my feet are cold.\"", es_ES="\"Hey, Audi, tengo frío en los pies.\"", fi_FI="\"Hei Audi, jalkani ovat kylmät.\"", fr_FR="«Hey Audi, j'ai froid aux pieds.»", hu_HU="„Hey Audi, fázik a lábam.”", it_IT="\"Ehi Audi, ho i piedi freddi.\"", nl_NL="\"Hey Audi, mijn voeten zijn koud.\"", no_NO="«Hey Audi, jeg er kald på føttene.»", pl_PL="„Hey Audi, zimno mi w stopy”.", pt_PT="\"Olá Audi, os meus pés estão\nfrios.\"", ru_RU="«Привет Audi, у меня мерзнут\nноги».", sv_SE="”Hej Audi, mina fötter är kalla.”", tr_TR="\"Hey Audi, ayaklarım üşüdü.\"")
assist_settings_help_climate_item_cold_feet_desc = TextObject(cs_CZ="Nohy mluvčího se zahřívají.", da_DK="Den talendes fødder opvarmes.", de_DE="Die Füße des Sprechers werden gewärmt.", el_GR="Θα ζεσταθούν τα πόδια του ομιλούντα.", en_GB="The footwell for the person speaking will be heated.", es_ES="Calentando los pies del usuario.", fi_FI="Puhujan jalkoja lämmitetään.", fr_FR="Réchauffage des pieds du locuteur.", hu_HU="A beszélő lábainál melegítés történik.", it_IT="Vengono riscaldati i piedi di chi parla.", nl_NL="De voeten van de spreker worden verwarmd.", no_NO="Føttene til den som snakker, varmes.", pl_PL="Stopy rozmówcy zostają ogrzane.", pt_PT="Os pés do locutor serão aquecidos.", ru_RU="Выполняется обогрев ног говорящего.", sv_SE="Talarens fötter värms upp.", tr_TR="Konuşmacının ayakları ısıtılıyor.")
assist_settings_help_climate_item_fan = TextObject(cs_CZ="\"Přidej větrák.\"", da_DK="\"Øg blæserne.\"", de_DE="„Erhöhe das Gebläse.“", el_GR="\"Αύξησε την ένταση του ανεμιστήρα.\"", en_GB="\"Turn the blower up.\"", es_ES="\"Sube el ventilador.\"", fi_FI="\"Nosta puhallustehoa.\"", fr_FR="«Augmente la soufflante.»", hu_HU="„Állítsd erősebbre a ventilátort.”", it_IT="\"Aumenta la ventilazione.\"", nl_NL="\"Verhoog de aanjager.\"", no_NO="«Øk viftehastigheten.»", pl_PL="„Zwiększ nawiew”.", pt_PT="\"Aumenta a ventilação.\"", ru_RU="«Увеличь мощность вентилятора».", sv_SE="”Öka fläktstyrkan.”", tr_TR="\"Fanı arttır.\"")
assist_settings_help_climate_item_fan_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, přidej větrák.\"", da_DK="\"Hey Audi, øg blæserne.\"", de_DE="„Hey Audi, erhöhe das Gebläse.“", el_GR="\"Γεια σου Audi, αύξησε την ένταση\nτου ανεμιστήρα.\"", en_GB="\"Hey Audi, turn the blower up.\"", es_ES="\"Hey, Audi, sube el ventilador.\"", fi_FI="\"Hei Audi, nosta puhallustehoa.\"", fr_FR="«Hey Audi, augmente la\nsoufflante.»", hu_HU="„Hey Audi, állítsd erősebbre a\nventilátort.”", it_IT="\"Ehi Audi, aumenta la\nventilazione.\"", nl_NL="\"Hey Audi, verhoog de aanjager.\"", no_NO="«Hey Audi, øk viftehastigheten.»", pl_PL="„Hey Audi, zwiększ nawiew”.", pt_PT="\"Olá Audi, aumenta a ventilação.\"", ru_RU="«Привет Audi, увеличь мощность\nвентилятора».", sv_SE="”Hej Audi, öka fläktstyrkan.”", tr_TR="\"Hey Audi, fanı arttır.\"")
assist_settings_help_climate_item_fan_desc = TextObject(cs_CZ="Síla větráku se zvýší o jeden stupeň.", da_DK="Blæserhastigheden øges med et trin.", de_DE="Die Gebläsestärke wird um eine Stufe angehoben.", el_GR="Η ένταση του ανεμιστήρα θα αυξηθεί κατά μία βαθμίδα.", en_GB="The blower strength will be increased by one level.", es_ES="Subiendo un nivel la potencia del ventilador.", fi_FI="Puhaltimen tehoa nostetaan yksi taso.", fr_FR="Augmentation de la puissance de la soufflante d'un niveau.", hu_HU="A ventilátor teljesítménye egy fokozattal nő.", it_IT="La potenza del ventilatore viene aumentata di un livello.", nl_NL="De sterkte van de aanjager wordt een stand verhoogd.", no_NO="Viftehastigheten settes opp ett trinn.", pl_PL="Intensywność nawiewu została zwiększona o jeden stopień.", pt_PT="A intensidade da ventilação foi aumentada um nível.", ru_RU="Мощность вентилятора увеличивается на один уровень.", sv_SE="Fläktstyrkan höjs med ett steg.", tr_TR="Fan gücü bir kademe arttırılıyor.")
assist_settings_help_climate_item_lower_temperature = TextObject(cs_CZ="\"Sniž teplotu vpředu vpravo.\"", da_DK="\"Sænk temperaturen foran i højre side.\"", de_DE="„Senke die Temperatur vorne rechts.“", el_GR="\"Μείωσε τη θερμοκρασία εμπρός δεξιά.\"", en_GB="\"Lower the temperature at the front right.\"", es_ES="\"Baja la temperatura en la plaza delantera derecha.\"", fi_FI="\"Laske lämpötilaa edessä oikealla.\"", fr_FR="«Abaisse la température côté avant droit.»", hu_HU="„Csökkentsd a hőmérsékletet jobb oldalon elöl.”", it_IT="\"Abbassa la temperatura davanti a destra.\"", nl_NL="\"Verlaag de temperatuur rechts voor.\"", no_NO="«Senk temperaturen foran til høyre.»", pl_PL="„Obniż temperaturę z przodu z prawej strony”.", pt_PT="\"Baixa a temperatura na zona dianteira direita.\"", ru_RU="«Снизь температуру спереди справа».", sv_SE="”Sänk temperaturen höger fram.”", tr_TR="\"Ön sağdaki sıcaklığı azalt.\"")
assist_settings_help_climate_item_lower_temperature_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, sniž teplotu vpředu\nvpravo.\"", da_DK="\"Hey Audi, sænk temperaturen\nforan i højre side.\"", de_DE="„Hey Audi, senke die Temperatur\nvorne rechts.“", el_GR="\"Γεια σου Audi, μείωσε τη\nθερμοκρασία εμπρός δεξιά.\"", en_GB="\"Hey Audi, lower the temperature\nat the front right.\"", es_ES="\"Hey, Audi, baja la temperatura en\nla plaza delantera derecha.\"", fi_FI="\"Hei Audi, laske lämpötilaa edessä\noikealla.\"", fr_FR="«Hey Audi, abaisse la température\ncôté avant droit.»", hu_HU="„Hey Audi, csökkentsd a\nhőmérsékletet jobb oldalon elöl.”", it_IT="\"Ehi Audi, abbassa la temperatura\ndavanti a destra.\"", nl_NL="\"Hey Audi, verlaag de temperatuur\nrechts voor.\"", no_NO="«Hey Audi, senk temperaturen\nforan til høyre.»", pl_PL="„Hey Audi, obniż temperaturę z\nprzodu z prawej strony”.", pt_PT="\"Olá Audi, baixa a temperatura na\nzona dianteira direita.\"", ru_RU="«Снизь температуру в передней\nчасти салона справа».", sv_SE="”Hej Audi, sänk temperaturen\nhöger fram.”", tr_TR="\"Hey Audi, ön sağdaki sıcaklığı\nazalt.\"")
assist_settings_help_climate_item_lower_temperature_desc = TextObject(cs_CZ="Teplota ve vnitřním prostoru vpředu vpravo se sníží.", da_DK="Kabinetemperaturen foran i højre side reduceres.", de_DE="Die Innenraumtemperatur vorn rechts wird verringert.", el_GR="Θα μειωθεί η θερμοκρασία στον εσωτερικό χώρο εμπρός δεξιά.", en_GB="The interior temperature will be reduced at the front right.", es_ES="Bajando la temperatura en la plaza delantera derecha.", fi_FI="Sisälämpötilaa lasketaan edessä oikealla.", fr_FR="Abaissement de la température dans l'habitacle côté avant droit.", hu_HU="A belső tér hőmérséklete jobb oldalon elöl csökken.", it_IT="Viene abbassata la temperatura dell'abitacolo nella zona anteriore destra.", nl_NL="De binnentemperatuur rechts voor wordt verlaagd.", no_NO="Kupétemperaturen foran til høyre senkes.", pl_PL="Temperatura we wnętrzu z przodu z prawej strony zostaje zmniejszona.", pt_PT="A temperatura da zona dianteira direita do habitáculo será reduzida.", ru_RU="Температура в салоне спереди справа снижается.", sv_SE="Kupétemperaturen höger fram sänks.", tr_TR="Sağ öndeki iç mekan sıcaklığı azaltılıyor.")
assist_settings_help_climate_item_seat_heating = TextObject(cs_CZ="\"Zapni vyhřívání sedadel.\"", da_DK="\"Tænd sædevarmen.\"", de_DE="„Schalte die Sitzheizung ein.“", el_GR="\"Ενεργοποίησε τη θέρμανση καθισμάτων.\"", en_GB="\"Switch the seat heating on.\"", es_ES="\"Enciende la calefacción del asiento.\"", fi_FI="\"Kytke istuinlämmitys päälle.\"", fr_FR="«Active le chauffage de siège.»", hu_HU="„Kapcsold be az ülésfűtést.”", it_IT="\"Accendi il riscaldamento del sedile.\"", nl_NL="\"Schakel de stoelverwarming in.\"", no_NO="«Slå på setevarmen.»", pl_PL="„Włącz podgrzewanie siedzenia”.", pt_PT="\"Liga o aquecimento do banco.\"", ru_RU="«Включи обогрев сидений».", sv_SE="”Aktivera sätesvärmen.”", tr_TR="\"Koltuk ısıtmasını aç.\"")
assist_settings_help_climate_item_seat_heating_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, zapni vyhřívání\nsedadel.\"", da_DK="\"Hey Audi, tænd sædevarmen.\"", de_DE="„Hey Audi, schalte die\nSitzheizung ein.“", el_GR="\"Γεια σου Audi, ενεργοποίησε τη\nθέρμανση καθισμάτων.\"", en_GB="\"Hey Audi, switch the seat heating\non.\"", es_ES="\"Hey, Audi, enciende la calefacción\ndel asiento.\"", fi_FI="\"Hei Audi, kytke istuinlämmitys\npäälle.\"", fr_FR="«Hey Audi, active le chauffage de\nsiège.»", hu_HU="„Hey Audi, kapcsold be az\nülésfűtést.”", it_IT="\"Ehi Audi, accendi il riscaldamento\ndel sedile.\"", nl_NL="\"Hey Audi, schakel de\nstoelverwarming in.\"", no_NO="«Hey Audi, slå på setevarmen.»", pl_PL="„Hey Audi, włącz podgrzewanie\nsiedzenia”.", pt_PT="\"Olá Audi, liga o aquecimento do\nbanco.\"", ru_RU="«Привет Audi, включи обогрев\nсидений».", sv_SE="”Hej Audi, aktivera sätesvärmen.”", tr_TR="\"Hey Audi, koltuk ısıtmasını aç.\"")
assist_settings_help_climate_item_seat_heating_codriver = TextObject(cs_CZ="\"Nastav vyhřívání sedadla spolujezdce na maximum.\"", da_DK="\"Indstil sædevarmen hos forsædepassageren til maksimum.\"", de_DE="„Stelle die Sitzheizung beim Beifahrer auf Maximum.“", el_GR="\"Ρύθμισε τη θέρμανση καθίσματος στον συνοδηγό στο μέγιστο.\"", en_GB="\"Switch the seat heating for the passenger to maximum.\"", es_ES="\"Ajusta al máximo la calefacción del asiento del acompañante.\"", fi_FI="\"Säädä etumatkustajan istuinlämmitys maksimiteholle.\"", fr_FR="«Règle le chauffage du siège du passager avant au maximum.»", hu_HU="„Állítsd az utas ülésfűtését a maximálisra.”", it_IT="\"Imposta al massimo il riscaldamento del sedile del passeggero anteriore.\"", nl_NL="\"Stel de stoelverwarming bij de bijrijder in op de maximale stand.\"", no_NO="«Sett setevarmen for passasjeren foran på maks.»", pl_PL="„Ustaw podgrzewanie siedzenia pasażera na maksimum”.", pt_PT="\"Regula o aquecimento do banco do passageiro para o máximo.\"", ru_RU="«Установи обогрев сиденья переднего пассажира на максимум».", sv_SE="”Ställ sätesvärmen för passageraren på max.”", tr_TR="\"Ön yolcu için koltuk ısıtmasını maksimuma ayarla.\"")
assist_settings_help_climate_item_seat_heating_codriver_aiscreen = TextObject(cs_CZ="\"Nastav vyhřívání sedadla\nspolujezdce na maximum.\"", da_DK="\"Indstil sædevarmen hos forsæde-\npassageren til maksimum.\"", de_DE="„Hey Audi, stelle die Sitzheizung\nbeim Beifahrer auf Maximum.“", el_GR="\"Ρύθμισε τη θέρμανση καθίσματος\nστον συνοδηγό στο μέγιστο.\"", en_GB="\"Hey Audi, switch the seat heating\nfor the passenger to maximum.\"", es_ES="\"Ajusta al máximo la calefacción\ndel asiento del acompañante.\"", fi_FI="\"Hei Audi, säädä etumatkustajan\nistuinlämmitys maksimiteholle.\"", fr_FR="«Règle le chauffage du siège du\npassager avant au maximum.»", hu_HU="„Hey Audi, állítsd az utas\nülésfűtését a maximálisra.”", it_IT="\"Riscaldamento sedile del\npasseggero anteriore al massimo.\"", nl_NL="\"Stel de stoelverwarming bij de\nbijrijder in op de maximale stand.\"", no_NO="«Hey Audi, sett setevarmen for\npassasjeren foran på maks.»", pl_PL="„Ustaw podgrzewanie siedzenia\npasażera na maksimum”.", pt_PT="\"Regula o aquecimento do banco\ndo passageiro para o máximo.\"", ru_RU="«Установи обогрев сиденья\nпассажира на максимум».", sv_SE="”Hej Audi, ställ sätesvärmen för\npassageraren på max.”", tr_TR="\"Hey Audi, ön yolcu için koltuk\nısıtmasını maksimuma ayarla.\"")
assist_settings_help_climate_item_seat_heating_codriver_desc = TextObject(cs_CZ="Vyhřívání sedadla spolujezdce se nastaví na maximum.", da_DK="Forsædepassagerens sædevarme indstilles til maksimum.", de_DE="Die Sitzheizung des Beifahrers wird auf Maximum eingestellt.", el_GR="Η θέρμανση καθίσματος του συνοδηγού θα ρυθμιστεί στο μέγιστο.", en_GB="The passenger's seat heating will be switched to maximum.", es_ES="Ajustando al máximo la calefacción del asiento del acompañante.", fi_FI="Etumatkustajan istuinlämmitys säädetään maksimiteholle.", fr_FR="Réglage du chauffage du siège du passager avant au maximum.", hu_HU="Az utas ülésfűtése a maximálisra kerül beállításra.", it_IT="Il riscaldamento del sedile del passeggero anteriore viene impostato al massimo.", nl_NL="De stoelverwarming van de bijrijder wordt op de maximale stand ingesteld.", no_NO="Setevarmen for passasjeren foran settes på maks.", pl_PL="Podgrzewanie siedzenia pasażera zostaje ustawione na maksimum.", pt_PT="O aquecimento do banco do passageiro será regulado para o máximo.", ru_RU="Обогрев сиденья переднего пассажира устанавливается на максимум.", sv_SE="Sätesvärmen för passageraren ställs in på max.", tr_TR="Ön yolcunun koltuk ısıtması maksimuma ayarlanıyor.")
assist_settings_help_climate_item_seat_heating_desc = TextObject(cs_CZ="Vyhřívání sedadla mluvčího se aktivuje.", da_DK="Sædevarmen aktiveres for den talende.", de_DE="Die Sitzheizung des Sprechers wird aktiviert.", el_GR="Θα ενεργοποιηθεί η θέρμανση του καθίσματος του ομιλούντα.", en_GB="The seat heating will be activated for the person speaking.", es_ES="Calentando el asiento del usuario.", fi_FI="Puhujan istuinlämmitys aktivoidaan.", fr_FR="Activation du chauffage du siège du locuteur.", hu_HU="A beszélő ülésfűtése aktiválásra kerül.", it_IT="Viene attivato il riscaldamento del sedile di chi parla.", nl_NL="De stoelverwarming van de spreker wordt geactiveerd.", no_NO="Setevarmen aktiveres for den som snakker.", pl_PL="Zostaje aktywowane podgrzewanie siedzenia osoby mówiącej.", pt_PT="O aquecimento do banco do locutor será ativado.", ru_RU="Активируется обогрев сиденья говорящего.", sv_SE="Stolsvärmen aktiveras för talaren.", tr_TR="Konuşmacının koltuk ısıtması etkinleştiriliyor.")
