assist_settings_help_climate_item_smell_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, aktivuj recirkulaci.\"", da_DK="\"Hey Audi, aktiver recirkulationen.”", de_DE="„Hey Audi, aktiviere Umluft.“", el_GR="\"Γεια σου Audi, ενεργοποίησε την\nανακύκλωση αέρα.\"", en_GB="\"Hey Audi, activate air\nrecirculation.\"", es_ES="\"Hey, Audi, activa la recirculación\nde aire.\"", fi_FI="\"Hei Audi, aktivoi ilmankierto.\"", fr_FR="«Hey Audi, active le recyclage de\nl'air ambiant.»", hu_HU="„„Hey Audi, aktiváld\nlevegőkeringetést.“", it_IT="\"Ehi Audi, attiva il ricircolo.\"", nl_NL="\"Hey Audi, activeer circulatie.\"", no_NO="«Hey Audi, aktiver omluft.»", pl_PL="„Hey Audi, aktywuj obieg\npowietrza”.", pt_PT="\"Olá Audi, ativa recirculação.\"", ru_RU="«Привет Audi, включи\nрециркуляцию воздуха».", sv_SE="”Hej Audi, aktivera\ncirkulationsluft.”", tr_TR="\"Hey Audi, hava sirkülasyonunu\netkinleştir.\"")
assist_settings_help_climate_item_smell_desc = TextObject(cs_CZ="Poměry vzduchu se přizpůsobují.", da_DK="Luftforholdene tilpasses.", de_DE="Die Luftverhältnisse werden angepasst.", el_GR="Θα προσαρμοστούν οι ατμοσφαιρικές συνθήκες.", en_GB="The air conditions will be adjusted.", es_ES="Cambiando las condiciones del aire.", fi_FI="Ilmaolosuhteita säädetään.", fr_FR="Modification des proportions de l'air.", hu_HU="A levegőminőség módosításra kerül.", it_IT="Vengono modificate le condizioni dell'aria.", nl_NL="De luchtverhoudingen worden aangepast.", no_NO="Luftforholdene tilpasses.", pl_PL="Następuje dostosowanie warunków powietrza.", pt_PT="As condições do ar serão ajustadas.", ru_RU="Регулируется качество воздуха.", sv_SE="Luftegenskaperna anpassas.", tr_TR="Hava koşulları ayarlanıyor.")
assist_settings_help_climate_item_temperature_codriver = TextObject(cs_CZ="\"Nastav teplotu u spolujezdce na 22 stupňů.\"", da_DK="\"Indstil temperaturen hos forsædepassageren til 22 grader.\"", de_DE="„Stelle die Temperatur beim Beifahrer auf 22 Grad.“", el_GR="\"Ρύθμισε τη θερμοκρασία στον συνοδηγό στους 22 βαθμούς\"", en_GB="\"Set the temperature for the passenger to 22 degrees.\"", es_ES="\"Ajusta la temperatura del acompañante a 22 grados.\"", fi_FI="\"Säädä etumatkustajan puolen lämpötilaksi 22 astetta.\"", fr_FR="«Règle la température du passager avant sur 22 degrés.»", hu_HU="„Állítsd a hőmérsékletet az utasnál 22 fokra.”", it_IT="\"Imposta la temperatura per il passeggero anteriore a 22 gradi\"", nl_NL="\"Stel de temperatuur bij de bijrijder in op 22 graden\"", no_NO="«Sett temperaturen for passasjeren foran på 22 grader»", pl_PL="„Ustaw temperaturę po stronie pasażera na 22 stopnie”", pt_PT="\"Regula a temperatura do passageiro para 22 graus\"", ru_RU="«Установи температуру на стороне переднего пассажира на 22 градуса»", sv_SE="”Ställ in temperaturen för passageraren på 22 grader.”", tr_TR="\"Ön yolcu için sıcaklığı 22 dereceye ayarla.\"")
assist_settings_help_climate_item_temperature_codriver_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, nastav teplotu u\nspolujezdce na 22 stupňů.\"", da_DK="\"Indstil temperaturen hos\nforsædepassageren til 22 grader.\"", de_DE="„Hey Audi, stelle die Temperatur\nbeim Beifahrer auf 22 Grad.“", el_GR="\"Ρύθμισε τη θερμοκρασία στον\nσυνοδηγό στους 22 βαθμούς\"", en_GB="\"Hey Audi, set the temperature for\nthe passenger to 22 degrees.\"", es_ES="\"Hey, Audi, ajusta la temperatura\ndel acompañante a 22 grados.\"", fi_FI="\"Hei Audi, säädä etumatkustajan\npuolen lämpötilaksi 22 astetta.\"", fr_FR="«Hey Audi, règle la température\ndu passager avant sur 22 degrés.»", hu_HU="„Hey Audi, állítsd a hőmérsékletet\naz utasnál 22 fokra.”", it_IT="\"Imposta la temperatura per il\npasseggero anteriore a 22 gradi\"", nl_NL="\"Hey Audi, stel de temperatuur bij\nde bijrijder in op 22 graden\"", no_NO="«Hey Audi, sett temperaturen for\npassasjeren foran på 22 grader»", pl_PL="„Hey Audi, ustaw temperaturę po\nstronie pasażera na 22 stopnie”", pt_PT="\"Olá Audi, regula a temperatura\ndo passageiro para 22 graus\"", ru_RU="«Установи температуру для\nпассажира на 22 градуса».", sv_SE="”Hej Audi, ställ in temperaturen\nför passageraren på 22 grader.”", tr_TR="\"Hey Audi, ön yolcu için sıcaklığı\n22 dereceye ayarla.\"")
assist_settings_help_climate_item_temperature_codriver_desc = TextObject(cs_CZ="Teplota ve vnitřním prostoru na straně spolujezdce se odpovídajícím způsobem přizpůsobí.", da_DK="Kabinetemperaturen i passagersiden tilpasses i henhold til det.", de_DE="Die Innenraumtemperatur auf der Beifahrerseite wird entsprechend angepasst.", el_GR="Θα προσαρμοστ. αντιστοίχως η θερμοκρασία τ. εσωτ. χώρου στην πλευρά του συνοδηγού.", en_GB="The interior temperature will be adjusted accordingly on the passenger's side.", es_ES="Ajustando la temperatura del acompañante.", fi_FI="Sisälämpötilaa etumatkustajan puolella säädetään ohjeen mukaan.", fr_FR="Modification en conséquence de la température dans l'habitacle côté passager avant.", hu_HU="A belső tér hőmérséklete az utasoldalon megfelelően beállításra kerül.", it_IT="La temperatura dell'abitacolo lato passeggero anteriore viene modificata di conseguenza.", nl_NL="De binnentemperatuur aan de bijrijderskant wordt aangepast zoals gewenst.", no_NO="Kupétemperaturen på passasjersiden foran tilpasses tilsvarende.", pl_PL="Temperatura we wnętrzu po stronie pasażera zostaje odpowiednio dostosowana.", pt_PT="A temperatura do habitáculo do lado do passageiro será adequadamente ajustada.", ru_RU="Температура в салоне со стороны пер. пассажира регулируется соответствующим образом.", sv_SE="Kupéutrymmestemperaturen på passagerarsidan anpassas på motsvarande sätt.", tr_TR="Ön yolcu tarafındaki iç mekan sıcaklığı uygun şekilde uyarlanıyor.")
