assist_settings_help_conversationals_example = TextObject(cs_CZ="\"Řekni mi něco k Ducati.\"", da_DK="\"Fortæl mig noget om Ducati.\"", de_DE="„Erzähl mir etwas zu Ducati.“", el_GR="\"Πες μου κάτι για την Ducati.\"", en_GB="\"Tell me something about Ducati.\"", es_ES="\"Cuéntame algo de Ducati.\"", fi_FI="\"Kerro minulle jotain Ducatista.\"", fr_FR="«Parle-moi de Ducati.»", hu_HU="„Mesélj valamit a Ducatiról!”", it_IT="\"Raccontami qualcosa su Ducati.\"", nl_NL="\"Vertel me eens iets over Ducati.\"", no_NO="«Fortell meg noe om Ducati.»", pl_PL="„Opowiedz mi coś o Ducati”.", pt_PT="\"Conta-me alguma coisa sobre a Ducati.\"", ru_RU="«Расскажи мне что-нибудь о Ducati».", sv_SE="”Berätta något om Ducati för mig.”", tr_TR="\"Bana Ducati hakkında bir şeyler anlat.\"")
assist_settings_help_conversationals_example1 = TextObject(cs_CZ=" \"Kde je centrála Audi?\"", da_DK="\"Hvor ligger Audis hovedkontor?\"", de_DE="„Wo ist die Audi Zentrale?“", el_GR="\"Πού είναι τα κεντρικά της Audi;\"", en_GB="\"Where is the Audi headquarters?\"", es_ES="\"¿Dónde está la central de Audi?\"", fi_FI="\"Missä on Audi-liike?\"", fr_FR="«Où se trouve le siège d'Audi?»", hu_HU="„Hol van az Audi-központ?”", it_IT="\"Dov'è la sede centrale di Audi?\"", nl_NL="\"Waar is het Audi-hoofdkantoor?\"", no_NO="«Hvor har Audi hovedkontor?»", pl_PL="„Gdzie jest centrala Audi?”", pt_PT="\"Onde é a sede da Audi?\"", ru_RU="«Где находится штаб-квартира Audi?»", sv_SE="”Var ligger Audis kontor?”", tr_TR="\"Audi merkezi nerede?\"")
