assist_settings_help_item_speechexclusive_bass_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, odmlž skla.\"", da_DK="\"Hey Audi, afrim ruden.\"", de_DE="„Hey Audi, mach die Scheibe frei.“", el_GR="\"Γεια σου Audi, ξεθάμπωσε το\nπαρμπρίζ.\"", en_GB="\"Hey Audi, clear the windscreen.\"", es_ES="\"Hey, Audi, desempaña el\nparabrisas.\"", fi_FI="\"Hei Audi, sulata ikkunalasi.\"", fr_FR="«Hey Audi, dégivre la vitre.»", hu_HU="„Hey Audi, tisztítsd le az ablakot.”", it_IT="\"Ehi Audi, sbrina il parabrezza.\"", nl_NL="\"Hey Audi, maak het venster vrij.\"", no_NO="«Hey Audi, fjern dugg fra ruten.»", pl_PL="„Hey Audi, oczyść szybę”.", pt_PT="\"Olá Audi, limpa os vidros.\"", ru_RU="«Привет Audi, очисти стекло».", sv_SE="”Hej Audi, gör sikten fri.”", tr_TR="\"Hey Audi, camı temizle.\"")
assist_settings_help_item_speechexclusive_bass_desc = TextObject(cs_CZ="Vyhřívání čelního skla se aktivuje.", da_DK="Den elopvarmede forrude aktiveres.", de_DE="Die Frontscheibenheizung wird aktiviert.", el_GR="Θα ενεργοποιηθεί η θέρμανση του μπροστινού παρμπρίζ.", en_GB="The windscreen heating will be activated.", es_ES="Activando la calefacción del parabrisas.", fi_FI="Tuulilasinlämmitys aktivoidaan.", fr_FR="Activation du dégivrage du pare-brise.", hu_HU="A szélvédőfűtés aktiválásra kerül.", it_IT="Si attiva il riscaldamento del parabrezza.", nl_NL="De voorruitverwarming wordt geactiveerd.", no_NO="Frontruteoppvarmingen aktiveres.", pl_PL="Zostaje włączone podgrzewanie przedniej szyby.", pt_PT="O desembaciador do vidro para-brisas será ativado.", ru_RU="Включается обогрев ветрового стекла.", sv_SE="Vindruteuppvärmningen aktiveras.", tr_TR="Ön cam ısıtması etkinleştirilir.")
assist_settings_help_item_speechexclusive_battery_load = TextObject(cs_CZ="„Ukaž mi nastavení světel.“", da_DK="\"Vis mig lysindstillingerne.\"", de_DE="„Zeige mir die Lichteinstellungen.“", el_GR="\"Δείξε μου τις ρυθμίσεις φώτων.\"", en_GB="\"Show me the light settings.\"", es_ES="\"Muéstrame los ajustes de la iluminación.\"", fi_FI="\"Näytä valojen asetukset.\"", fr_FR="«Affiche-moi les réglages de l'éclairage.»", hu_HU="„Mutasd a világításbeállításokat.”", it_IT="\"Mostrami le impostazioni delle luci.\"", nl_NL="\"Laat me de verlichtingsinstellingen zien.\"", no_NO="«Vis meg lysinnstillingene.»", pl_PL="„Pokaż ustawienia świateł.”", pt_PT="\"Mostra-me os ajustes das luzes.\"", ru_RU="«Покажи мне настройки освещения».", sv_SE="\"Visa mig ljusinställningarna.\"", tr_TR="\"Bana ışık ayarlarını göster.\"")
assist_settings_help_item_speechexclusive_battery_load_aiscreen = TextObject(cs_CZ="„Ahoj Audi, ukaž mi nastavení\nsvětel.“", da_DK="\"Hey Audi, vis mig\nlysindstillingerne.\"", de_DE="„Hey Audi, zeige mir die\nLichteinstellungen.“", el_GR="\"Γεια σου Audi, δείξε μου τις\nρυθμίσεις φώτων.\"", en_GB="\"Hey Audi, show me the light\nsettings.\"", es_ES="\"Hey, Audi, muéstrame los ajustes\nde la iluminación.\"", fi_FI="\"Hei Audi, näytä valojen\nasetukset.\"", fr_FR="«Hey Audi, affiche-moi les\nréglages de l'éclairage.»", hu_HU="„Hey Audi, mutasd a\nvilágításbeállításokat.”", it_IT="\"Ehi Audi, mostrami le\nimpostazioni delle luci.\"", nl_NL="\"Hey Audi, laat me de\nverlichtingsinstellingen zien.\"", no_NO="«Hey Audi, vis meg\nlysinnstillingene.»", pl_PL="„Hey Audi, pokaż ustawienia\nświateł.”", pt_PT="\"Olá Audi, mostra-me os ajustes\ndas luzes.\"", ru_RU="«Привет Audi, покажи мне\nнастройки освещения».", sv_SE="\"Hej Audi, visa mig\nljusinställningarna.\"", tr_TR="\"Hey Audi, bana ışık ayarlarını\ngöster.\"")
assist_settings_help_item_speechexclusive_battery_load_desc = TextObject(cs_CZ="Zobrazí se nastavení světel.", da_DK="Lysindstillingerne bliver vist.", de_DE="Die Lichteinstellungen werden angezeigt.", el_GR="Εμφανίζονται οι ρυθμίσεις φώτων.", en_GB="The light settings will be shown.", es_ES="Mostrando los ajustes de la iluminación.", fi_FI="Valojen asetukset tulevat näkyviin.", fr_FR="Affichage des réglages de l'éclairage.", hu_HU="Megjelennek a világításbeállítások.", it_IT="Vengono visualizzate le impostazioni delle luci.", nl_NL="De verlichtingsinstellingen worden weergegeven.", no_NO="Lysinnstillingene vises.", pl_PL="Zostają wyświetlone ustawienia świateł.", pt_PT="Os ajustes das luzes serão apresentados.", ru_RU="Отображаются настройки освещения.", sv_SE="Ljusinställningarna visas.", tr_TR="Işık ayarları gösterilir.")
assist_settings_help_item_speechexclusive_battery_load_status = TextObject(cs_CZ="„Buď stručné.“", da_DK="\"Fat dig i korthed.\"", de_DE="„Fasse dich kurz.“", el_GR="\"Να είσαι σύντομος.\"", en_GB="\"Keep it short.\"", es_ES="\"Sé breve.\"", fi_FI="\"Puhu lyhyesti.\"", fr_FR="«Sois brève.»", hu_HU="„Röviden mondd el.“", it_IT="\"Sii più breve.\"", nl_NL="\"Houd het kort.\"", no_NO="«Fatt deg i korthet.»", pl_PL="„Streszczaj się.”", pt_PT="\"Sê breve.\"", ru_RU="«Говори короче».", sv_SE="”Var kortfattad.”", tr_TR="\"Kısa konuş.\"")
assist_settings_help_item_speechexclusive_battery_load_status_aiscreen = TextObject(cs_CZ="„Ahoj Audi, buď stručné.“", da_DK="\"Hey Audi, fat dig i korthed.\"", de_DE="„Hey Audi, fasse dich kurz.“", el_GR="\"«Γεια σου Audi, να είσαι\nσύντομος.\"", en_GB="\"Hey Audi, keep it short.\"", es_ES="\"Hey, Audi, sé breve.\"", fi_FI="\"Hei Audi, puhu lyhyesti.\"", fr_FR="«Hey Audi, sois brève.»", hu_HU="„Hey Audi, röviden mondd el.“", it_IT="\"Ehi Audi, sii più breve.\"", nl_NL="\"Hé Audi, houd het kort.\"", no_NO="«Hey Audi, fatt deg i korthet.»", pl_PL="„Hey Audi, streszczaj się.”", pt_PT="\"Olá Audi, abrevia.\"", ru_RU="«Привет Audi, говори короче».", sv_SE="”Hej Audi, var kortfattad.”", tr_TR="\"Hey Audi, kısa konuş.\"")
assist_settings_help_item_speechexclusive_battery_load_status_desc = TextObject(cs_CZ="Audi assistant podává krátké odpovědi.", da_DK="Audi assistant giver korte svar.", de_DE="Der Audi assistant gibt kurze Antworten.", el_GR="Η Audi assistant δίνει σύντομες απαντήσεις.", en_GB="The Audi assistant will give short answers.", es_ES="El Audi assistant dará respuestas cortas.", fi_FI="Audi assistant antaa lyhyitä vastauksia.", fr_FR="L'Audi assistant donne des réponses courtes.", hu_HU="Az Audi assistant rövid válaszokat ad.", it_IT="L'Audi assistant fornisce risposte brevi.", nl_NL="De Audi assistant geeft korte antwoorden.", no_NO="Audi assistant gir korte svar.", pl_PL="Audi assistant udziela krótkich odpowiedzi.", pt_PT="O Audi assistant dá respostas curtas.", ru_RU="Audi assistant дает короткие ответы.", sv_SE="Audi assistant ger korta svar.", tr_TR="Audi assistant kısa cevaplar verir.")
assist_settings_help_item_speechexclusive_battery_remain_range = TextObject(cs_CZ="\"Jak daleko ještě dojedu?\"", da_DK="\"Hvor meget længere kan jeg køre?\"", de_DE="„Wie weit komme ich noch?“", el_GR="\"Πόσο μακριά μπορώ να πάω ακόμη;\"", en_GB="\"How much further can I go?\"", es_ES="\"¿Hasta dónde voy a llegar?\"", fi_FI="\"Kuinka pitkälle vielä pääsen?\"", fr_FR="«Combien de kilomètres puis-je encore parcourir?»", hu_HU="„Meddig juthatok el?”", it_IT="\"Quanta strada posso ancora fare?\"", nl_NL="\"Hoe ver kan ik nog rijden?\"", no_NO="«Hvor langt kan jeg kjøre?»", pl_PL="„Jak daleko jeszcze zajadę?”", pt_PT="\"Até onde é que ainda posso ir?\"", ru_RU="«Сколько я могу еще проехать?»", sv_SE="”Hur långt kommer jag?”", tr_TR="\"Daha ne kadar gidebilirim?\"")
assist_settings_help_item_speechexclusive_battery_remain_range_aiscreen = TextObject(cs_CZ="„Ahoj Audi, jak daleko ještě\ndojedu?“", da_DK="\"Hey Audi, hvor meget længere\nkan jeg køre?\"", de_DE="„Hey Audi, wie weit komme\nich noch?“", el_GR="\"Γεια σου Audi, πόσο μακριά\nμπορώ να πάω ακόμη;\"", en_GB="\"Hey Audi, how much further\ncan I go?\"", es_ES="\"Hey, Audi, ¿hasta dónde voy a\nllegar?\"", fi_FI="\"Hei Audi, kuinka pitkälle vielä\npääsen?\"", fr_FR="«Hey Audi, combien de kilomètres\npuis-je encore parcourir?»", hu_HU="„Hey Audi, meddig juthatok el?”", it_IT="\"Ehi Audi, quanta strada posso\nancora fare?\"", nl_NL="\"Hey Audi, hoe ver kan ik nog\nrijden?\"", no_NO="«Hey Audi, hvor langt kan jeg\nkjøre?»", pl_PL="„Hey Audi, jak daleko jeszcze\nzajadę?”", pt_PT="\"Olá Audi, até onde é que ainda\nposso ir?\"", ru_RU="«Привет Audi, сколько я могу еще\nпроехать?»", sv_SE="”Hej Audi, hur långt kommer jag?”", tr_TR="\"Hey Audi, daha ne kadar\ngidebilirim?\"")
assist_settings_help_item_speechexclusive_battery_remain_range_desc = TextObject(cs_CZ="Poskytne informace o dojezdu.", da_DK="Giver information om den resterende rækkevidde.", de_DE="Gibt Auskunft über die Restreichweite.", el_GR="Ενημερώνει για την υπολειπόμενη αυτονομία.", en_GB="Gives information on the remaining range.", es_ES="Proporciona información sobre la autonomía restante.", fi_FI="Saat tietoa jäljellä olevasta toimintamatkasta.", fr_FR="Renseignement sur l'autonomie.", hu_HU="Információt ad a fennmaradó hatótávolságról.", it_IT="Vengono fornite informazioni sull'autonomia residua.", nl_NL="Geeft informatie over de actieradius.", no_NO="Viser gjenværende rekkevidde.", pl_PL="Informuje, jaki jest pozostały zasięg.", pt_PT="Mostra informação sobre a autonomia.", ru_RU="Предоставляет информацию о запасе хода.", sv_SE="Ger information om återstående räckvidd.", tr_TR="Kalan menzil hakkında bilgi verir.")
assist_settings_help_item_speechexclusive_call = TextObject(cs_CZ="\"Zavolej Jiřího.\"", da_DK="\"Ring op til Jens.\"", de_DE="„Ruf bei Max an.“", el_GR="\"Κάλεσε τον Κώστα.\"", en_GB="\"Call Max.\"", es_ES="\"Llama a María.\"", fi_FI="\"Soita kontaktille Matti.\"", fr_FR="«Appelle Pierre.»", hu_HU="„Hívd fel Maxot.“", it_IT="\"Chiama Max.\"", nl_NL="\"Bel Max.\"", no_NO="«Ring Jan.»", pl_PL="„Zadzwoń do Maksa”.", pt_PT="\"Liga ao Max.\"", ru_RU="«Позвони Максу».", sv_SE="”Ring till Erik.”", tr_TR="\"Ali'yi ara.\"")
assist_settings_help_item_speechexclusive_call_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, zavolej Jiřího.\"", da_DK="\"Hey Audi, ring op til Jens.\"", de_DE="„Hey Audi, ruf bei Max an.“", el_GR="\"Γεια σου Audi, κάλεσε τον Κώστα.\"", en_GB="\"Hey Audi, call Max.\"", es_ES="\"Hey, Audi, llama a María.\"", fi_FI="\"Hei Audi, soita kontaktille Matti.\"", fr_FR="«Hey Audi, appelle Pierre.»", hu_HU="„Hey Audi, hívd fel Maxot.“", it_IT="\"Ehi Audi, chiama Max.\"", nl_NL="\"Hey Audi, bel Max.\"", no_NO="«Hey Audi, ring Jan.»", pl_PL="„Hey Audi, zadzwoń do Maksa”.", pt_PT="\"Olá Audi, liga ao Max.\"", ru_RU="«Привет Audi, позвони Максу».", sv_SE="”Hej Audi, ring till Erik.”", tr_TR="\"Hey Audi, Ali'yi ara.\"")
assist_settings_help_item_speechexclusive_call_desc = TextObject(cs_CZ="Zobrazí se seznam možných telefonních kontaktů.", da_DK="En liste med mulige telefonkontakter vises.", de_DE="Eine Liste möglicher Telefonkontakte wird angezeigt.", el_GR="Εμφανίζεται μια λίστα πιθανών επαφών τηλεφώνου.", en_GB="A list of possible telephone contacts will be shown.", es_ES="Se muestra una lista de posibles contactos del teléfono.", fi_FI="Lista mahdollisista puhelinkontakteista tulee näkyviin.", fr_FR="Affichage d'une liste de contacts donnée du téléphone.", hu_HU="Megjelenik a lehetséges telefonkapcsolatok listája.", it_IT="Viene visualizzato un elenco dei possibili contatti del telefono.", nl_NL="Een lijst van mogelijke telefooncontacten wordt weergegeven.", no_NO="Det vises en liste over mulige telefonkontakter.", pl_PL="Zostaje wyświetlona lista dostępnych kontaktów telefonicznych.", pt_PT="Será apresentada uma lista de contactos telefónicos possíveis.", ru_RU="Отображается список возможных телефонных контактов.", sv_SE="En lista över möjliga telefonkontakter visas.", tr_TR="Olası telefon kişilerinin bir listesi görüntülenir.")
assist_settings_help_item_speechexclusive_charging_station = TextObject(cs_CZ="„Aktivuj jednoduše mluvit.“", da_DK="\"Aktiver begynd bare at tale.\"", de_DE="„Aktiviere einfach lossprechen.“", el_GR="\"Ενεργοποίησε τη συνομιλία τώρα.\"", en_GB="\"Activate simply start talking.\"", es_ES="\"Activa la función de empezar a hablar sin más.\"", fi_FI="\"Aktivoi toiminto Aktivoi järjestelmä alkamalla puhua.\"", fr_FR="«Active la fonction «Dialoguer simplement».»", hu_HU="„Kapcsold be az Egyszerűen csak megszólalok funkciót.“", it_IT="\"Attiva la funzione Parlare direttamente.\"", nl_NL="\"Activeer gewoon praten.\"", no_NO="«Aktiver bare begynn å snakke.»", pl_PL="„Włącz: po prostu powiedz.”", pt_PT="\"Ativa conversação simples.\"", ru_RU="«Активируй «Просто начать говорить»».", sv_SE="”Aktivera tala bara.”", tr_TR="\"Sadece konuşmaya başlamayı etkinleştir.\"")
assist_settings_help_item_speechexclusive_charging_station_aiscreen = TextObject(cs_CZ="„Ahoj Audi, aktivuj jednoduše\nmluvit.“", da_DK="\"Hey Audi, aktiver begynd bare at\ntale.\"", de_DE="„Hey Audi, aktiviere einfach\nlossprechen.“", el_GR="\"Γεια Audi, ενεργοποίησε την\nομιλία τώρα.\"", en_GB="\"Hey Audi, activate simply start\ntalking.\"", es_ES="\"Hey, Audi, activa la función de\nempezar a hablar sin más.\"", fi_FI="\"Hei Audi, aktivoi toiminto Aktivoi\njärjestelmä alkamalla puhua.\"", fr_FR="«Hey Audi, active la fonction\n«Dialoguer simplement».»", hu_HU="„Hey Audi, kapcsold be az\nEgyszerűen csak megszólalok-at.“", it_IT="\"Ehi Audi, attiva la funzione\nParlare direttamente.\"", nl_NL="\"Hé Audi, activeer gewoon\npraten.\"", no_NO="«Hey Audi, aktiver bare begynn å\nsnakke.»", pl_PL="„Hey Audi, włącz: po prostu\npowiedz.”", pt_PT="\"Olá Audi, ativa conversação\nsimples.\"", ru_RU="«Привет Audi, активируй «Просто\nначать говорить»».", sv_SE="”Hej Audi, aktivera tala bara.”", tr_TR="\"Hey Audi, sadece konuşmaya\nbaşlamayı etkinleştir.\"")
assist_settings_help_item_speechexclusive_charging_station_desc = TextObject(cs_CZ="Hlasový vstup je možný bez aktivačního slova.", da_DK="Det er muligt at afgive stemmekommandoer uden aktiveringsord.", de_DE="Die Spracheingabe ist ohne Aktivierungswort möglich.", el_GR="Η φωνητική καταχώριση είναι δυνατή χωρίς λέξη ενεργοποίησης.", en_GB="Speech input is possible without an activation phrase.", es_ES="Puede utilizar el manejo por voz sin palabra de activación.", fi_FI="Puheohjaus on mahdollista ilman aktivointisanoja.", fr_FR="La commande vocale est possible sans mot de réveil.", hu_HU="A beszédbevitel aktiválószó nélkül lehetséges.", it_IT="È possibile impartire i comandi vocali senza il comando di attivazione.", nl_NL="Spraakinvoer is mogelijk zonder activeringswoord.", no_NO="Du kan bruke talekommandoer uten aktiveringsord.", pl_PL="Wprowadzanie głosowe jest możliwe bez słowa aktywującego.", pt_PT="As introduções por voz são possíveis sem palavra de ativação.", ru_RU="Голосовое сообщение возможно без слова активации.", sv_SE="Röstinmatning utan aktiveringsfras möjlig.", tr_TR="Aktivasyon kelimesi olmadan sesli giriş mümkündür.")
assist_settings_help_item_speechexclusive_cold_back = TextObject(cs_CZ="\"Mám studené nohy.\"", da_DK="\"Jeg fryser om mine fødder.\"", de_DE="„Meine Füße sind kalt.“", el_GR="\"Τα πόδια μου κρυώνουν.\"", en_GB="\"My feet are cold.\"", es_ES="\"Tengo frío en los pies.\"", fi_FI="\"Jalkani ovat kylmät.\"", fr_FR="«J'ai froid aux pieds.»", hu_HU="„Fázik a lábam.”", it_IT="\"Ho i piedi freddi.\"", nl_NL="\"Mijn voeten zijn koud.\"", no_NO="«Jeg er kald på føttene.»", pl_PL="„Zimno mi w stopy”.", pt_PT="\"Os meus pés estão frios.\"", ru_RU="«У меня мерзнут ноги».", sv_SE="”Mina fötter är kalla.”", tr_TR="\"Ayaklarım üşüdü.\"")
assist_settings_help_item_speechexclusive_cold_back_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, mám studené nohy.\"", da_DK="\"Hey Audi, jeg fryser om mine\nfødder.\"", de_DE="„Hey Audi, meine Füße sind kalt.“", el_GR="\"Γεια σου Audi, τα πόδια μου\nκρυώνουν.\"", en_GB="\"Hey Audi, my feet are cold.\"", es_ES="\"Hey, Audi, tengo frío en los pies.\"", fi_FI="\"Hei Audi, jalkani ovat kylmät.\"", fr_FR="«Hey Audi, j'ai froid aux pieds.»", hu_HU="„Hey Audi, fázik a lábam.”", it_IT="\"Ehi Audi, ho i piedi freddi.\"", nl_NL="\"Hey Audi, mijn voeten zijn koud.\"", no_NO="«Hey Audi, jeg er kald på føttene.»", pl_PL="„Hey Audi, zimno mi w stopy”.", pt_PT="\"Olá Audi, os meus pés estão\nfrios.\"", ru_RU="«Привет Audi, у меня мерзнут\nноги».", sv_SE="”Hej Audi, mina fötter är kalla.”", tr_TR="\"Hey Audi, ayaklarım üşüdü.\"")
assist_settings_help_item_speechexclusive_cold_back_desc = TextObject(cs_CZ="Vyhřívání prostoru nohou mluvčího se aktivuje.", da_DK="Den talendes fodrumsvarme aktiveres.", de_DE="Die Fußraumheizung des Sprechers wird aktiviert.", el_GR="Θα ενεργοποιηθεί η θέρμανση χώρου ποδιών του ομιλούντα.", en_GB="The speaker's footwell heating will be activated.", es_ES="Activando la calefacción para los pies.", fi_FI="Puhujan jalkatilan lämmitys aktivoidaan.", fr_FR="Activation du chauffage au plancher du locuteur.", hu_HU="A beszélő lábtérfűtése aktiválásra kerül.", it_IT="Viene attivato il riscaldamento del vano piedi di chi parla.", nl_NL="De voetruimteverwarming van de spreker wordt geactiveerd.", no_NO="Oppvarming av fotrommet blir aktivert for den som snakker.", pl_PL="Zostaje włączone podgrzewanie strefy stóp osoby mówiącej.", pt_PT="O aquecimento da zona dos pés do locutor será ativado.", ru_RU="Включается обогрев пространства для ног на стороне говорящего.", sv_SE="Golvutrymmesvärmen aktiveras för talaren.", tr_TR="Konuşmacının ayak bölmesi ısıtması etkinleştiriliyor.")
assist_settings_help_item_speechexclusive_desc = TextObject(cs_CZ="„Je mi teplo.“", da_DK="\"Jeg har det varmt.\"", de_DE="„Mir ist warm.“", el_GR="„Ζεσταίνομαι.“", en_GB="\"I'm hot.\"", es_ES="\"Tengo calor.\"", fi_FI="\"Minulla on lämmin.\"", fr_FR="«J'ai chaud.»", hu_HU="„Melegem van.”", it_IT="\"Ho caldo.\"", nl_NL="\"Ik heb het warm.\"", no_NO="«Jeg er varm.»", pl_PL="„Jest mi ciepło”.", pt_PT="\"Tenho calor.\"", ru_RU="«Мне тепло.»", sv_SE="”Jag är varm.”", tr_TR="\"Sıcak hissediyorum.\"")
assist_settings_help_item_speechexclusive_music = TextObject(cs_CZ="\"Přehraj hudbu od Madonny na Spotify.\"", da_DK="\"Afspil musik af Madonna på Spotify.\"", de_DE="„Spiele Musik von Madonna auf Spotify.“", el_GR="\"Παίξε μουσική της Madonna στο Spotify.\"", en_GB="\"Play music by Madonna on Spotify.\"", es_ES="\"Pon música de Madonna en Spotify.\"", fi_FI="\"Soita Madonnan musiikkia Spotifysta.\"", fr_FR="«Diffuse de la musique de Madonna sur Spotify.»", hu_HU="„Játszd Madonna zenéit a Spotifyon.”", it_IT="\"Riproduci musica di Madonna su Spotify.\"", nl_NL="\"Speel muziek af van Madonna op Spotify.\"", no_NO="«Spill musikk av Madonna på Spotify.»", pl_PL="„Zagraj Madonnę na Spotify”.", pt_PT="\"Reproduz música da Madonna no Spotify.\"", ru_RU="«Включи музыку Мадонны на Spotify».", sv_SE="”Spela musik av Madonna på Spotify.”", tr_TR="\"Spotify'da Madonna'dan müzik çal.\"")
assist_settings_help_item_speechexclusive_music_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, přehraj hudbu od\nMadonny na Spotify.\"", da_DK="\"Hey Audi, afspil musik af\nMadonna på Spotify.\"", de_DE="„Hey Audi, spiele Musik von\nMadonna auf Spotify.“", el_GR="\"Γεια σου Audi, παίξε μουσική της\nMadonna στο Spotify.\"", en_GB="\"Hey Audi, play music by Madonna\non Spotify.\"", es_ES="\"Hey, Audi, pon música de\nMadonna en Spotify.\"", fi_FI="\"Hei Audi, soita Madonnan\nmusiikkia Spotifysta.\"", fr_FR="«Hey Audi, diffuse de la musique\nde Madonna sur Spotify.»", hu_HU="„Hey Audi, játszd Madonna zenéit\na Spotifyon.”", it_IT="\"Ehi Audi, riproduci musica di\nMadonna su Spotify.\"", nl_NL="\"Hey Audi, speel muziek af van\nMadonna op Spotify.\"", no_NO="«Hey Audi, spill musikk av\nMadonna på Spotify.»", pl_PL="„Hey Audi, zagraj Madonnę na\nSpotify”.", pt_PT="\"Olá Audi, reproduz música da\nMadonna no Spotify.\"", ru_RU="«Привет Audi, включи музыку\nМадонны на Spotify».", sv_SE="”Hej Audi, spela musik av\nMadonna på Spotify.”", tr_TR="\"Hey Audi, Spotify'da\nMadonna'dan müzik çal.\"")
assist_settings_help_item_speechexclusive_music_desc = TextObject(cs_CZ="Přehrává se hudba od Madonny na Spotify.", da_DK="Musik af Madonna afspilles på Spotify.", de_DE="Musik von Madonna wird auf Spotify abgespielt.", el_GR="Γίνεται αναπαραγωγή μουσικής της Madonna στο Spotify.", en_GB="Music by Madonna will be played on Spotify.", es_ES="Reproduciendo música de Madonna en Spotify.", fi_FI="Madonnan musiikkia soitetaan Spotifysta.", fr_FR="Diffusion de musique de Madonna sur Spotify.", hu_HU="Madonna zenéje szól a Spotifyon.", it_IT="Viene riprodotta musica di Madonna su Spotify.", nl_NL="Muziek van Madonna wordt op Spotify afgespeeld.", no_NO="Det spilles musikk av Madonna på Spotify.", pl_PL="Zostają odtworzone utwory Madonny w serwisie Spotify.", pt_PT="A música da Madonna será reproduzida no Spotify.", ru_RU="Музыка Мадонны играет на Spotify.", sv_SE="Musik av Madonna spelas upp på Spotify.", tr_TR="Spotify'da Madonna'dan müzik çalınır.")
assist_settings_help_item_speechexclusive_navigation = TextObject(cs_CZ="„Chci do Prahy, Vinohradská 27“", da_DK="\"Jeg vil køre til Østerbrogade 9 i København.\"", de_DE="„Ich möchte nach Berlin in die Bodestraße 3.“", el_GR="„Θέλω να πάω στην Αθήνα, στην οδό Κουμπάρη 1“", en_GB="\"I'd like to go to 50 Kingston Road, London\"", es_ES="\"Quiero ir a Madrid Paseo del Prado 3\"", fi_FI="\"Haluaisin kohteeseen Helsinki osoitteeseen Museokatu 3.\"", fr_FR="«J'aimerais aller à Paris, rue de la Paix»", hu_HU="„Budapestre szeretnék menni a Tétényi út 3. címre“", it_IT="\"Vorrei andare a Roma in via Cavour 3\"", nl_NL="\"Ik wil graag naar de Beethovenstraat 27 in Amsterdam\"", no_NO="«Jeg vil til Oslo, Storgaten 33»", pl_PL="„Chcę jechać do Warszawy na ulicę Marszałkowską 3”", pt_PT="\"Quero ir para a Rua Augusta 3 em Lisboa.\"", ru_RU="«Я хочу поехать на Бодестрассе 3 в Берлине.»", sv_SE="”Jag vill till Kungsgatan 5 i Göteborg”", tr_TR="\"İstanbul'da Bağdat Caddesi 3'e gitmek istiyorum”")
assist_settings_help_item_speechexclusive_navigation_aiscreen = TextObject(cs_CZ="„Ahoj Audi, chci do Berlína,\nBodestraße 3“", da_DK="\"Hey Audi, jeg vil køre til\nØsterbrogade 9 i København.\"", de_DE="„Hey Audi, ich möchte nach Berlin\nin die Bodestraße 3.“", el_GR="“Γεια σου Audi, θέλω να πάω στην\nΑθήνα, στην οδό Κουμπάρη 1.“", en_GB="\"Hey Audi, I'd like to go to 50\nKingston Road, London\"", es_ES="\"Hey, Audi, quiero ir a Madrid\nPaseo del Prado 3.\"", fi_FI="\"Haluaisin kohteeseen Helsinki\nosoitteeseen Museokatu 3.\"", fr_FR="«Hey Audi, j'aimerais aller à Paris,\nrue de la Paix.»", hu_HU="„Hey Audi, Budapestre szeretnék\nmenni a Tétényi út 3. címre.“", it_IT="\"Ehi Audi, vorrei andare a Roma in\nvia Cavour 3.\"", nl_NL="\"Hey Audi, ik wil naar Beethoven-\nstraat 27 in Amsterdam\"", no_NO="«Hey Audi, jeg vil til Oslo,\nStorgaten 33»", pl_PL="„Hey Audi, chcę jechać do\nWarszawy na Marszałkowską 3”", pt_PT="\"Olá Audi, quero ir para a Rua\nAugusta 3 em Lisboa.\"", ru_RU="«Привет Audi, я хочу поехать в\nМоскву на улицу Усачева 3».", sv_SE="”Hej Audi, jag vill till Kungsgatan 5\ni Göteborg”", tr_TR="\"Hey Audi, İstanbul'da Bağdat\nCaddesi 3'e gitmek istiyorum”")
assist_settings_help_item_speechexclusive_navigation_desc = TextObject(cs_CZ="Navigace k odpovídajícímu cíli se spouští.", da_DK="Navigationen til den pågældende destination startes.", de_DE="Die Navigation zum entsprechenden Ziel wird gestartet.", el_GR="Θα ξεκινήσει η πλοήγηση στον αντίστοιχο προορισμό.", en_GB="Navigation to the corresponding destination will be started.", es_ES="Iniciando la navegación al destino.", fi_FI="Navigointi kohteeseen aloitetaan.", fr_FR="Lancement de la navigation vers la destination correspondante.", hu_HU="Elindul a navigáció a megfelelő címre.", it_IT="Viene avviata la navigazione verso la destinazione indicata.", nl_NL="De navigatie naar het betreffende doel wordt gestart.", no_NO="Navigasjon til ønsket mål startes.", pl_PL="Zostaje uruchomiona nawigacja do odpowiedniego miejsca docelowego.", pt_PT="A navegação para o respetivo destino foi iniciada.", ru_RU="Запускается навигация к соответствующей цели.", sv_SE="Navigering till motsvarande resmål startas.", tr_TR="İlgili hedefe navigasyon başlatılır.")
assist_settings_help_item_speechexclusive_seatheating = TextObject(cs_CZ="\"Je mi zima.\"", da_DK="\"Jeg fryser.\"", de_DE="„Mir ist kalt.“", el_GR="\"Κρυώνω.\"", en_GB="\"I'm cold.\"", es_ES="\"Tengo frío.\"", fi_FI="\"Minulla on kylmä.\"", fr_FR="«J'ai froid.»", hu_HU="„Fázom.”", it_IT="\"Ho freddo.\"", nl_NL="\"Ik heb het koud.\"", no_NO="«Jeg fryser.»", pl_PL="„Jest mi zimno”.", pt_PT="\"Tenho frio.\"", ru_RU="«Мне холодно».", sv_SE="”Jag fryser.”", tr_TR="\"Ben üşüdüm.\"")
assist_settings_help_item_speechexclusive_seatheating_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, je mi zima.\"", da_DK="\"Hey Audi, jeg fryser.\"", de_DE="„Hey Audi, mir ist kalt.“", el_GR="\"Γεια σου Audi, κρυώνω.\"", en_GB="\"Hey Audi, I'm cold.\"", es_ES="\"Hey, Audi, tengo frío.\"", fi_FI="\"Hei Audi, minulla on kylmä.\"", fr_FR="«Hey Audi, j'ai froid.»", hu_HU="„Hey Audi, fázom.”", it_IT="\"Ehi Audi, ho freddo.\"", nl_NL="\"Hey Audi, ik heb het koud.\"", no_NO="«Hey Audi, jeg fryser.»", pl_PL="„Hey Audi, jest mi zimno”.", pt_PT="\"Olá Audi, tenho frio.\"", ru_RU="«Привет Audi, мне холодно».", sv_SE="”Hej Audi, jag fryser.”", tr_TR="\"Hey Audi, ben üşüdüm.\"")
assist_settings_help_item_speechexclusive_seatheating_desc = TextObject(cs_CZ="Funkce klimatizace mluvčího se odpovídajícím způsobem přizpůsobí.", da_DK="Den talendes klimafunktioner tilpasses i henhold til dette.", de_DE="Die Klimafunktionen des Sprechers werden entsprechend angepasst.", el_GR="Θα γίνει αντίστοιχη προσαρμογή των λειτουργιών κλιματισμού για τον ομιλούντα.", en_GB="The air conditioning functions will be adjusted for the person speaking.", es_ES="Adaptando la calefacción del usuario.", fi_FI="Puhujan ilmastointitoimintoja säädetään pyynnön mukaisesti.", fr_FR="Modification en conséquence des fonctions de la climatisation du locuteur.", hu_HU="A beszélő klímafunkciói ennek megfelelően kerülnek beállításra.", it_IT="Vengono modificate di conseguenza le funzioni di climatizzazione di chi parla.", nl_NL="De aircofuncties van de spreker worden aangepast zoals gewenst.", no_NO="Klimafunksjonene blir tilpasset ønsket til den som snakker.", pl_PL="Funkcje klimatyzacji rozmówcy zostają odpowiednio dostosowane.", pt_PT="As funções do ar condicionado do locutor sero adequadamente adaptadas.", ru_RU="Функции климата на стороне говорящего настраиваются соответствующим образом.", sv_SE="Klimatfunktionerna anpassas på motsvarande sätt för talaren.", tr_TR="Konuşmacının klima fonksiyonları uygun şekilde uyarlanıyor.")
assist_settings_help_item_speechexclusive_tab_caption = TextObject(cs_CZ="Příklady zvláštních hlasových vstupů", da_DK="Eksempler på særlige stemmekommandoer", de_DE="Beispiele für besondere Spracheingaben", el_GR="Παραδείγματα για ειδικές φωνητικές καταχωρίσεις", en_GB="Examples of special spoken commands", es_ES="Ejemplos de órdenes por voz especiales", fi_FI="Esimerkkejä erikoispuhekäskyistä", fr_FR="Exemples de commandes vocales spécifiques", hu_HU="Példák speciális beszédbevitelekre", it_IT="Esempi di comandi vocali speciali", nl_NL="Voorbeelden van bijzondere spraakinvoer", no_NO="Eksempler på spesifikke talekommandoer", pl_PL="Przykłady szczególnych wpisów głosowych", pt_PT="Exemplos de instruções de voz especiais", ru_RU="Примеры специальных голосовых сообщений", sv_SE="Exempel på särskilda röstkommandon", tr_TR="Özel sesli girişler için örnekler")
assist_settings_help_item_speechexclusive_temperature = TextObject(cs_CZ="\"Nastav teplotu u spolujezdce na 22 stupňů.\"", da_DK="\"Indstil temperaturen hos forsædepassageren til 22 grader.\"", de_DE="„Stelle die Temperatur beim Beifahrer auf 22 Grad.“", el_GR="\"Ρύθμισε τη θερμοκρασία στον συνοδηγό στους 22 βαθμούς\"", en_GB="\"Set the temperature for the passenger to 22 degrees.\"", es_ES="\"Ajusta la temperatura del acompañante a 22 grados.\"", fi_FI="\"Säädä etumatkustajan puolen lämpötilaksi 22 astetta.\"", fr_FR="«Règle la température du passager avant sur 22 degrés.»", hu_HU="„Állítsd a hőmérsékletet az utasnál 22 fokra.”", it_IT="\"Imposta la temperatura per il passeggero anteriore a 22 gradi\"", nl_NL="\"Stel de temperatuur bij de bijrijder in op 22 graden\"", no_NO="«Sett temperaturen for passasjeren foran på 22 grader»", pl_PL="„Ustaw temperaturę po stronie pasażera na 22 stopnie”", pt_PT="\"Regula a temperatura do passageiro para 22 graus\"", ru_RU="«Установи температуру на стороне переднего пассажира на 22 градуса»", sv_SE="”Ställ in temperaturen för passageraren på 22 grader.”", tr_TR="\"Ön yolcu için sıcaklığı 22 dereceye ayarla.\"")
assist_settings_help_item_speechexclusive_temperature_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, nastav teplotu u\nspolujezdce na 22 stupňů.\"", da_DK="\"Indstil temperaturen hos\nforsædepassageren til 22 grader.\"", de_DE="„Hey Audi, stelle die Temperatur\nbeim Beifahrer auf 22 Grad.“", el_GR="\"Ρύθμισε τη θερμοκρασία στον\nσυνοδηγό στους 22 βαθμούς\"", en_GB="\"Hey Audi, set the temperature for\nthe passenger to 22 degrees.\"", es_ES="\"Hey, Audi, ajusta la temperatura\ndel acompañante a 22 grados.\"", fi_FI="\"Hei Audi, säädä etumatkustajan\npuolen lämpötilaksi 22 astetta.\"", fr_FR="«Hey Audi, règle la température\ndu passager avant sur 22 degrés.»", hu_HU="„Hey Audi, állítsd a hőmérsékletet\naz utasnál 22 fokra.”", it_IT="\"Imposta la temperatura per il\npasseggero anteriore a 22 gradi\"", nl_NL="\"Hey Audi, stel de temperatuur bij\nde bijrijder in op 22 graden\"", no_NO="«Hey Audi, sett temperaturen for\npassasjeren foran på 22 grader»", pl_PL="„Hey Audi, ustaw temperaturę po\nstronie pasażera na 22 stopnie”", pt_PT="\"Olá Audi, regula a temperatura\ndo passageiro para 22 graus\"", ru_RU="«Установи температуру для\nпассажира на 22 градуса».", sv_SE="”Hej Audi, ställ in temperaturen\nför passageraren på 22 grader.”", tr_TR="\"Hey Audi, ön yolcu için sıcaklığı\n22 dereceye ayarla.\"")
assist_settings_help_item_speechexclusive_temperature_desc = TextObject(cs_CZ="Teplota ve vnitřním prostoru na straně spolujezdce se odpovídajícím způsobem přizpůsobí.", da_DK="Kabinetemperaturen i passagersiden tilpasses i henhold til det.", de_DE="Die Innenraumtemperatur auf der Beifahrerseite wird entsprechend angepasst.", el_GR="Θα προσαρμοστ. αντιστοίχως η θερμοκρασία τ. εσωτ. χώρου στην πλευρά του συνοδηγού.", en_GB="The interior temperature will be adjusted accordingly on the passenger's side.", es_ES="Ajustando la temperatura del acompañante.", fi_FI="Sisälämpötilaa etumatkustajan puolella säädetään ohjeen mukaan.", fr_FR="Modification en conséquence de la température dans l'habitacle côté passager avant.", hu_HU="A belső tér hőmérséklete az utasoldalon megfelelően beállításra kerül.", it_IT="La temperatura dell'abitacolo lato passeggero anteriore viene modificata di conseguenza.", nl_NL="De binnentemperatuur aan de bijrijderskant wordt aangepast zoals gewenst.", no_NO="Kupétemperaturen på passasjersiden foran tilpasses tilsvarende.", pl_PL="Temperatura we wnętrzu po stronie pasażera zostaje odpowiednio dostosowana.", pt_PT="A temperatura do habitáculo do lado do passageiro será adequadamente ajustada.", ru_RU="Температура в салоне со стороны пер. пассажира регулируется соответствующим образом.", sv_SE="Kupéutrymmestemperaturen på passagerarsidan anpassas på motsvarande sätt.", tr_TR="Ön yolcu tarafındaki iç mekan sıcaklığı uygun şekilde uyarlanıyor.")
assist_settings_help_item_speechexclusive_tired = TextObject(cs_CZ="\"Jsem unavený.\"", da_DK="\"Jeg er træt.\"", de_DE="„Ich bin müde.“", el_GR="\"Είμαι κουρασμένος.\"", en_GB="\"I'm tired.\"", es_ES="\"Estoy cansado.\"", fi_FI="\"Olen väsynyt.\"", fr_FR="«Je suis fatigué.»", hu_HU="„Fáradt vagyok.”", it_IT="\"Sono stanco.\"", nl_NL="\"Ik ben moe.\"", no_NO="«Jeg er trøtt.»", pl_PL="\"Jestem zmęczony.\"", pt_PT="\"Estou cansado.\"", ru_RU="\"Я устал.\"", sv_SE="\"Jag är trött.\"", tr_TR="\"Çok uykum var.\"")
assist_settings_help_item_speechexclusive_tired_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, jsem unavený.\"", da_DK="\"Hey Audi, jeg er træt.\"", de_DE="„Hey Audi, ich bin müde.“", el_GR="\"Γεια σου Audi, είμαι\nκουρασμένος.\"", en_GB="\"Hey Audi, I'm tired.\"", es_ES="\"Hey, Audi, estoy cansado.\"", fi_FI="\"Hei Audi, olen väsynyt.\"", fr_FR="«Hey Audi, je suis fatigué.»", hu_HU="„Hey Audi, fáradt vagyok.”", it_IT="\"Ehi Audi, sono stanco.\"", nl_NL="\"Hey Audi, ik ben moe.\"", no_NO="«Hey Audi, jeg er trøtt.»", pl_PL="\"Hey Audi, jestem zmęczony.\"", pt_PT="\"Olá Audi, estou cansado.\"", ru_RU="«Привет Audi, я устал».", sv_SE="\"Hej Audi, jag är trött.\"", tr_TR="\"Hey Audi, ben yorgunum.\"")
assist_settings_help_item_speechexclusive_tired_desc = TextObject(cs_CZ="Hledají se odpočívadla podél trasy nebo v okolí.", da_DK="Der søges efter rastepladser langs med ruten eller i nærheden.", de_DE="Es werden Rastplätze entlang der Route oder im Umkreis gesucht.", el_GR="Γίνεται αναζήτηση για χώρους ανάπαυσης κατά μήκος της διαδρομής ή στη γύρω περιοχή.", en_GB="A search for rest areas along the route or nearby will be performed.", es_ES="Buscando áreas de descanso cerca o a lo largo de la ruta.", fi_FI="Taukopaikkoja etsitään reitin varrelta ja lähistöltä.", fr_FR="Recherche d'aires de repos le long de l'itinéraire ou à proximité.", hu_HU="Pihenőhelyek keresése az útvonal mentén vagy annak közelében.", it_IT="Vengono cercate aree di servizio lungo l'itinerario o nelle vicinanze.", nl_NL="Er worden rustplaatsen langs de route of in de omgeving gezocht.", no_NO="Det søkes etter rasteplasser langs ruten eller i nærheten.", pl_PL="Zostają wyświetlone miejsca postoju na trasie lub w okolicy.", pt_PT="A procurar áreas de repouso ao longo do trajeto ou nas imediações.", ru_RU="Выполняется поиск мест для отдыха вдоль маршрута или поблизости.", sv_SE="Söker efter rastplatser längs rutten eller i närheten.", tr_TR="Rota boyunca veya çevredeki dinlenme alanları aranır.")
assist_settings_help_item_speechexclusive_title = TextObject(cs_CZ="\"Co právě poslouchám?\"", da_DK="\"Hvad hører jeg lige nu?\"", de_DE="„Was höre ich gerade?“", el_GR="\"Τι ακούω αυτή τη στιγμή;\"", en_GB="\"What am I listening to?\"", es_ES="\"¿Qué está sonando?\"", fi_FI="\"Mitä kuuntelen parhaillaan?\"", fr_FR="«Que suis-je en train d'écouter?»", hu_HU="„Mit hallok most?”", it_IT="\"Cosa sto ascoltando?\"", nl_NL="\"Wat hoor ik nu?\"", no_NO="«Hva hører jeg på nå?»", pl_PL="„Czego właśnie słucham?”", pt_PT="\"O que estou a ouvir agora?\"", ru_RU="«Что я сейчас слушаю?»", sv_SE="”Vad lyssnar jag på nu?”", tr_TR="\"Şu anda ne dinliyorum?\"")
assist_settings_help_item_speechexclusive_title_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, co právě poslouchám?\"", da_DK="\"Hey Audi, hvad hører jeg lige nu?\"", de_DE="„Hey Audi, was höre ich gerade?“", el_GR="\"Γεια σου Audi, τι ακούω αυτή τη\nστιγμή;\"", en_GB="\"Hey Audi, what am I listening to?\"", es_ES="\"Hey, Audi, ¿qué está sonando?\"", fi_FI="\"Hei Audi, mitä kuuntelen\nparhaillaan?\"", fr_FR="«Hey Audi, que suis-je en train\nd'écouter?»", hu_HU="„Hey Audi, mit hallok most?”", it_IT="\"Ehi Audi, cosa sto ascoltando?\"", nl_NL="\"Hey Audi, wat hoor ik nu?\"", no_NO="«Hey Audi, hva hører jeg på nå?»", pl_PL="„Hey Audi, czego właśnie\nsłucham?”", pt_PT="\"Olá Audi, o que estou a ouvir\nagora?\"", ru_RU="«Привет Audi, что я сейчас\nслушаю?»", sv_SE="”Hej Audi, vad lyssnar jag på nu?”", tr_TR="\"Hey Audi, şu anda ne\ndinliyorum?\"")
assist_settings_help_item_speechexclusive_title_desc = TextObject(cs_CZ="Sdělují se informace o aktuální reprodukci.", da_DK="Informationer om den aktuelle afspilning meddeles.", de_DE="Informationen über aktuelle Wiedergabe werden mitgeteilt.", el_GR="Γνωστοποιούνται πληροφορίες για την τρέχουσα αναπαραγωγή.", en_GB="Information on what is currently playing will be shared.", es_ES="Informando sobre la reproducción actual.", fi_FI="Saat tietoa parhaillaan toistettavasta sisällöstä.", fr_FR="Indication des informations sur la lecture en cours.", hu_HU="A rendszer információkat ad az aktuális lejátszással kapcsolatban.", it_IT="Vengono fornite informazioni sulla riproduzione attuale.", nl_NL="Informatie over wat nu wordt afgespeeld wordt gegeven.", no_NO="Du får informasjon om avspillingen.", pl_PL="Zostają podane informacje dotyczące bieżącego odtwarzania.", pt_PT="Serão comunicadas informações sobre a reprodução atual.", ru_RU="Сообщается информация о текущей композиции.", sv_SE="Ger användaren information om den aktuella uppspelningen.", tr_TR="Geçerli oynatmayla ilgili bilgiler iletilir.")
assist_settings_help_item_top_used = TextObject(cs_CZ="Nejvíce používané hlasové vstupy", da_DK="Oftest anvendte stemmekommandoer", de_DE="Meistgenutzte Spracheingaben", el_GR="Οι συχνότερα χρησιμοποιούμενες φωνητικές καταχωρίσεις", en_GB="Most frequently used spoken commands", es_ES="Órdenes por voz más utilizadas", fi_FI="Käytetyimmät puhekäskyt", fr_FR="Commandes vocales les plus utilisées", hu_HU="Leggyakrabban használt beszédbevitelek", it_IT="Comandi vocali più frequenti", nl_NL="Meest gebruikte spraakinvoer", no_NO="Mest brukte talekommandoer", pl_PL="Najczęściej używane wpisy głosowe", pt_PT="Instruções de voz mais utilizadas", ru_RU="Наиболее часто используемые голосовые сообщения", sv_SE="Mest använda röstkommandon", tr_TR="En çok kullanılan sesli girişler")
assist_settings_help_item_top_used_desc = TextObject(cs_CZ="Prohlédněte si nejvíce používané hlasové vstupy.", da_DK="Kig på de oftest anvendte stemmekommandoer.", de_DE="Sieh dir die meistgenutzten Spracheingaben an.", el_GR="Δείτε τις συχνότερα χρησιμοποιούμενες φωνητικές καταχωρίσεις.", en_GB="Take a look at the most frequently used spoken commands.", es_ES="Estas son las órdenes por voz más utilizadas.", fi_FI="Voit nähdä käytetyimmät puhekäskyt.", fr_FR="Voici les commandes vocales les plus utilisées.", hu_HU="Tekintsd meg a leggyakrabban használt beszédbeviteleket.", it_IT="Vengono visualizzati i comandi vocali utilizzati più di frequente.", nl_NL="Bekijk de meest gebruikte spraakinvoer.", no_NO="Du kan se de mest brukte talekommandoene.", pl_PL="Zobacz najczęściej używane wpisy głosowe.", pt_PT="Vê as instruções de voz mais utilizadas.", ru_RU="Ознакомьтесь с наиболее часто используемыми голосовыми сообщениями.", sv_SE="Visar de mest använda röstkommandona.", tr_TR="En çok kullanılan sesli girişlere göz at.")
assist_settings_help_media_item_bass = TextObject(cs_CZ="\"Ukaž mi všechny rozhlasové stanice.\"", da_DK="\"Vis mig alle radiostationer.\"", de_DE="„Zeige mir alle Radiosender.“", el_GR="\"Δείξε μου όλους τους σταθμούς ραδιοφώνου.\"", en_GB="\"Show me all radio stations.\"", es_ES="\"Muéstrame todas las emisoras de radio.\"", fi_FI="\"Näytä kaikki radioasemat.\"", fr_FR="«Affiche-moi toutes les stations radio.»", hu_HU="„Mutasd meg az összes rádióadót.”", it_IT="\"Mostrami tutte le stazioni radio.\"", nl_NL="\"Laat me alle radiozenders zien.\"", no_NO="«Vis meg alle radiostasjonene.»", pl_PL="„Pokaż mi wszystkie programy radiowe”.", pt_PT="\"Mostra-me todos os sensores rádio.\"", ru_RU="\"Покажите мне все радиостанции\".", sv_SE="”Visa mig alla radiokanaler.”", tr_TR="\"Bana tüm radyo istasyonlarını göster.\"")
