assist_settings_help_media_item_bass_desc = TextObject(cs_CZ="Seznam stanic se zobrazí na displeji", da_DK="Stationslisten vises i displayet.", de_DE="Die Senderliste wird im Display dargestellt", el_GR="Η λίστα σταθμών φαίνεται στην οθόνη", en_GB="The station list will be shown on the display", es_ES="Mostrando en pantalla la lista de emisoras", fi_FI="Asemalista näkyy näyttöruudulla", fr_FR="Affichage à l'écran de la liste des stations", hu_HU="Az adólista megjelenik a kijelzőn", it_IT="Sul display viene visualizzato l'elenco delle stazioni radio", nl_NL="De zenderlijst wordt in het display weergegeven", no_NO="Stasjonslisten vises på displayet", pl_PL="Lista programów zostanie wyświetlona na wyświetlaczu", pt_PT="A lista de emissoras será apresentada no ecrã", ru_RU="Список станций отображается на дисплее", sv_SE="Kanallistan visas på displayen", tr_TR="İstasyon listesi ekranda gösterilir")
assist_settings_help_media_item_bayern = TextObject(cs_CZ="„Přehraj Český rozhlas 2.“", da_DK="\"Afspil P4 København.\"", de_DE="„Spiele Antenne Bayern.“", el_GR="\"Παίξε Flash 96.\"", en_GB="\"Play BBC Radio 1.\"", es_ES="\"Pon Radio Nacional.\"", fi_FI="\"Soita radioasemaa Yle Puhe.\"", fr_FR="«Diffuse RTL2.»", hu_HU="„Játszd a Petőfit.”", it_IT="\"Riproduci Rai Radio 2.\"", nl_NL="\"Luister Radio Veronica.\"", no_NO="«Spill NRK P2.»", pl_PL="„W​łącz Radio Zet”.", pt_PT="\"Reproduz rádio Comercial.\"", ru_RU="«Включи Европа Плюс».", sv_SE="”Spela P4 Göteborg.”", tr_TR="\"Power Türk çal.\"")
