assist_settings_help_media_item_bayern_desc = TextObject(cs_CZ="Nastaví se stanice Český rozhlas 2.", da_DK="Radiostationen P4 København indstilles.", de_DE="Der Radiosender Antenne Bayern wird eingestellt.", el_GR="Θα επιλεγεί ο σταθμός ραδιοφώνου Flash 96.", en_GB="The radio station BBC Radio 1 will be set.", es_ES="Sintonizando la emisora Radio Nacional.", fi_FI="Radioasema Yle Puhe valitaan.", fr_FR="Sélection de la station de radio RTL2.", hu_HU="Beállításra kerül a Petőfi rádió.", it_IT="Viene impostata la stazione Rai Radio 2.", nl_NL="De radiozender Radio Veronica wordt aangezet.", no_NO="Radiokanalen NRK P2 stilles inn.", pl_PL="Włączam program radiowy Radio Zet.", pt_PT="A emissora rádio Comercial será sintonizada.", ru_RU="Настраивается радиостанция Европа Плюс.", sv_SE="Radiokanalen P4 Göteborg ställs in.", tr_TR="Power Türk radyo istasyonu ayarlanır.")
assist_settings_help_media_item_continue = TextObject(cs_CZ="\"Pokračuj v přehrávání.\"", da_DK="\"Fortsæt afspilning.\"", de_DE="„Wiedergabe fortsetzen.“", el_GR="\"Συνέχιση αναπαραγωγής.\"", en_GB="\"Continue playback.\"", es_ES="\"Reanudar reproducción.\"", fi_FI="\"Jatka toistoa.\"", fr_FR="«Poursuis la lecture.»", hu_HU="„Lejátszás folytatása”", it_IT="\"Riprendi la riproduzione.\"", nl_NL="\"Doorgaan met huidige weergave.\"", no_NO="«Fortsett avspillingen.»", pl_PL="„Kontynuuj odtwarzanie”.", pt_PT="\"Continuar reprodução.\"", ru_RU="«Продолжить воспроизведение».", sv_SE="”Fortsätt uppspelningen.”", tr_TR="\"Yayına devam et.\"")
assist_settings_help_media_item_continue_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, pokračuj v přehrávání.\"", da_DK="\"Hey Audi, fortsæt afspilning.\"", de_DE="„Hey Audi, Wiedergabe\nfortsetzen.“", el_GR="\"Γεια σου Audi, συνέχιση\nαναπαραγωγής.\"", en_GB="\"Hey Audi, continue playback.\"", es_ES="\"Hey, Audi, reanudar\nreproducción.\"", fi_FI="\"Hei Audi, jatka toistoa.\"", fr_FR="«Hey Audi, poursuis la lecture.»", hu_HU="„Hey Audi, lejátszás folytatása”", it_IT="\"Ehi Audi, riprendi la\nriproduzione.\"", nl_NL="\"Hey Audi, doorgaan met huidige\nweergave.\"", no_NO="«Hey Audi, fortsett avspillingen.»", pl_PL="„Hey Audi, kontynuuj\nodtwarzanie”.", pt_PT="\"Olá Audi, continuar reprodução.\"", ru_RU="«Привет Audi, продолжи\nвоспроизведение».", sv_SE="”Hej Audi, fortsätt\nuppspelningen.”", tr_TR="\"Hey Audi, yayına devam et.\"")
assist_settings_help_media_item_continue_desc = TextObject(cs_CZ="Reprodukce bude pokračovat, pokud byla pozastavena.", da_DK="Afspilningen fortsættes, hvis medieafspilningen tidligere er blevet pauset.", de_DE="Die Wiedergabe wird fortgesetzt, falls zuvor die Medienwiedergabe pausiert wurde.", el_GR="Η αναπαραγωγή θα συνεχιστεί, εάν προηγουμένως έχει παυθεί η αναπαραγωγή μέσων.", en_GB="Playback will be continued if it was previously paused.", es_ES="La reproducción se reanudará si antes se había pausado la reproducción de medios.", fi_FI="Mediatoistoa jatketaan, mikäli toisto on aiemmin pysäytetty.", fr_FR="Poursuite de la lecture si la lecture multimédia avait été mise en pause auparavant.", hu_HU="A lejátszás folytatódik, ha a médialejátszást előzőleg szüneteltették.", it_IT="La riproduzione di contenuti multimediali riprende, se era stata messa in pausa.", nl_NL="Het afspelen van de weergave wordt hervat, mocht de mediaweergave eerder gepauzeerd zijn.", no_NO="Avspillingen fortsetter etter at medieavspillingen har blitt satt på pause.", pl_PL="Odtwarzanie będzie kontynuowane, jeśli wcześniej wstrzymano odtwarzanie multimediów.", pt_PT="A reprodução prosseguirá, caso a reprodução mídia tenha sido anteriormente pausada.", ru_RU="Воспроизведение возобновляется, если воспроизв. мультимедиа было приостановлено.", sv_SE="Uppspelningen fortsätter om mediauppspelningen har pausats.", tr_TR="Medya oynatma önceden duraklatıldıysa, yayına devam edilir.")
assist_settings_help_media_item_fmradio = TextObject(cs_CZ="\"Chci poslouchat FM.\"", da_DK="\"Jeg vil høre FM.\"", de_DE="„Ich will FM hören.“", el_GR="\"Θέλω να ακούσω FM.\"", en_GB="\"I want to listen to FM.\"", es_ES="\"Quiero escuchar FM.\"", fi_FI="\"Haluan kuunnella FM-taajuutta.\"", fr_FR="«Je veux écouter FM.»", hu_HU="„FM-et szeretnék hallgatni.”", it_IT="\"Voglio ascoltare la radio FM.\"", nl_NL="\"Ik wil FM horen.\"", no_NO="«Jeg vil høre på FM.»", pl_PL="„Chcę słuchać FM”.", pt_PT="\"Quero ouvir FM.\"", ru_RU="«Хочу слушать FM».", sv_SE="”Jag vill lyssna på FM.”", tr_TR="\"FM dinlemek istiyorum.\"")
