assist_settings_help_media_item_fmradio_desc = TextObject(cs_CZ="Přehrává se zdroj FM rádio.", da_DK="Afspilningskilden FM-radio afspilles.", de_DE="Die Wiedergabequelle FM Radio wird abgespielt.", el_GR="Γίνεται αναπαραγωγή της πηγής αναπαραγωγής ραδιόφωνο FM.", en_GB="The FM radio playback source will be played.", es_ES="Sintonizando la radio FM.", fi_FI="Toistolähdettä FM-radio soitetaan.", fr_FR="Diffusion de la source de lecture Radio FM.", hu_HU="FM-rádió lejátszási forrás bekapcsolása.", it_IT="Viene riprodotta la fonte Radio FM.", nl_NL="De afspeelbron FM Radio wordt aangezet.", no_NO="Avspillingskilden FM-radio spilles.", pl_PL="Zostanie odtworzone źródło radio FM.", pt_PT="A fonte de reprodução rádio FM será reproduzida.", ru_RU="Воспроизводится источник воспроизведения FM-радио.", sv_SE="Källan FM-radio spelas upp.", tr_TR="FM Radyo yayın kaynağı çalınır.")
assist_settings_help_media_item_louder = TextObject(cs_CZ="„Nastav to hlasitěji.“", da_DK="\"Indstil højere.\"", de_DE="„Mach lauter.“", el_GR="„Αύξησε την ένταση ήχου.“", en_GB="\"Make it louder\"", es_ES="\"Más alto.\"", fi_FI="\"Ääntä kovemmalle.\"", fr_FR="«Mets plus fort.»", hu_HU="„Hangosítsd fel.“", it_IT="\"Alza il volume.\"", nl_NL="\"Zet hem harder.\"", no_NO="«Skru opp lyden.»", pl_PL="„Zrób głośniej”.", pt_PT="\"Aumenta o volume.\"", ru_RU="«Сделай громче.»", sv_SE="”Höj volymen.”", tr_TR="\"Sesi aç.\"")
