assist_settings_help_media_item_louder_desc = TextObject(cs_CZ="Hlasitost zdroje médií se zvýší.", da_DK="Mediekildens lydstyrke øges.", de_DE="Die Lautstärke der Medienquelle wird erhöht.", el_GR="Θα αυξηθεί η ένταση ήχου της πηγής μέσων.", en_GB="The volume of the media source will be increased.", es_ES="Subiendo el volumen de la fuente de medios.", fi_FI="Medialähteen äänenvoimakkuutta nostetaan.", fr_FR="Augmentation du volume de la source multimédia.", hu_HU="A médiaforrás hangereje nő.", it_IT="Viene alzato il volume della fonte Media.", nl_NL="De geluidssterkte van de mediabron wordt verhoogd.", no_NO="Volumet for mediekilden økes.", pl_PL="Głośność źródła multimediów zostaje zwiększona.", pt_PT="O volume da fonte mídia será aumentado.", ru_RU="Громкость медиаисточника увеличивается.", sv_SE="Mediekällans volym höjs.", tr_TR="Medya kaynağının ses seviyesi arttırılır.")
assist_settings_help_media_item_madonna = TextObject(cs_CZ="\"Přehraj hudbu od Madonny.\"", da_DK="\"Afspil musik af Madonna.\"", de_DE="„Spiele Musik von Madonna.“", el_GR="\"Παίξε μουσική της Madonna.\"", en_GB="\"Play music by Madonna.\"", es_ES="\"Pon música de Madonna.\"", fi_FI="\"Soita Madonnan musiikkia.\"", fr_FR="«Diffuse de la musique de Madonna.»", hu_HU="„Játszd Madonna zenéit.”", it_IT="\"Riproduci musica di Madonna.\"", nl_NL="\"Speel muziek af van Madonna.\"", no_NO="«Spill musikk av Madonna.»", pl_PL="„Zagraj Madonnę”.", pt_PT="\"Reproduz música da Madonna.\"", ru_RU="«Включи музыку Мадонны».", sv_SE="”Spela musik av Madonna.”", tr_TR="\"Madonna'dan müzik çal.\"")
