assist_settings_help_media_item_madonna_desc = TextObject(cs_CZ="U stávajících zdrojů médií se vyhledá a přehraje hudba Madonny.", da_DK="Der søges efter musik af Madonna på de tilgængelige mediekilder, og den afspilles.", de_DE="Auf den vorhanden Medienquellen wird nach Musik von Madonna gesucht und abgespielt.", el_GR="Στις υπάρχουσες πηγές μέσων γίνεται αναζήτηση και αναπαραγωγή μουσικής της Madonna.", en_GB="Music by Madonna will be searched for in the available media sources and played.", es_ES="Buscando música de Madonna para reproducirla en los medios disponibles.", fi_FI="Saatavilla olevista medialähteistä etsitään ja soitetaan Madonnan musiikkia.", fr_FR="Recherche et lecture de musique de Madonna sur les sources multimédia disponibles.", hu_HU="A rendszer Madonna zenéit keresi és játssza le az elérhető médiaforrásokon.", it_IT="Sulle fonti Media disponibili viene cercata e riprodotta musica di Madonna.", nl_NL="Op de beschikbare mediabronnen wordt naar muziek van Madonna gezocht en afgespeeld.", no_NO="Det søkes etter og spilles musikk av Madonna på de tilgjengelige mediekildene.", pl_PL="Następuje wyszukiwanie i odtwarzanie utworów Madonny z dostępnych źródeł multimediów.", pt_PT="A procurar e reproduzir música da Madonna nas fontes mídia existentes.", ru_RU="Выполняется поиск и воспроизведение музыки Мадонны на доступных медиаисточниках.", sv_SE="Söker efter musik av Madonna på den befintliga mediekällan och spelar upp den.", tr_TR="Mevcut medya kaynaklarında Madonna'dan müzik aranır ve çalınır.")
assist_settings_help_media_item_max_volume = TextObject(cs_CZ="\"Úplně vytoč hlasitost.\"", da_DK="\"Skru lyden helt op.\"", de_DE="„Dreh die Lautstärke voll auf.“", el_GR="\"Βάλε τέρμα την ένταση ήχου.\"", en_GB="\"Turn the volume all the way up.\"", es_ES="\"Sube el volumen a tope.\"", fi_FI="\"Käännä äänenvoimakkuus täysille.\"", fr_FR="«Monte le son.»", hu_HU="„Állítsd teljesre a hangerőt.”", it_IT="\"Alza il volume al massimo.\"", nl_NL="\"Zet het geluid op de maximale sterkte.\"", no_NO="«Skru lyden helt opp.»", pl_PL="„Daj głośność do pełna.”", pt_PT="\"Coloca o volume no máximo.\"", ru_RU="«Установи громкость на максимум».", sv_SE="”Skruva upp volymen till max.”", tr_TR="\"Ses seviyesini sonuna kadar aç!\"")
assist_settings_help_media_item_max_volume_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, úplně vytoč hlasitost.\"", da_DK="\"Hey Audi, skru lyden helt op.\"", de_DE="„Hey Audi, dreh die Lautstärke\nvoll auf.“", el_GR="\"Γεια σου Audi, βάλε τέρμα την\nένταση ήχου.\"", en_GB="\"Hey Audi, turn the volume all the\nway up.\"", es_ES="\"Hey, Audi, sube el volumen a\ntope.\"", fi_FI="\"Hei Audi, käännä\näänenvoimakkuus täysille.\"", fr_FR="«Hey Audi, monte le son.»", hu_HU="„Hey Audi, állítsd teljesre a\nhangerőt.”", it_IT="\"Ehi Audi, alza il volume al\nmassimo.\"", nl_NL="\"Hey Audi, zet het geluid op de\nmaximale sterkte.\"", no_NO="«Hey Audi, skru lyden helt opp.»", pl_PL="„Hey Audi, daj głośność do pełna.”", pt_PT="\"Olá Audi, coloca o volume no\nmáximo.\"", ru_RU="«Привет Audi, установи\nгромкость на максимум».", sv_SE="”Hej Audi, skruva upp volymen till\nmax.”", tr_TR="\"Hey Audi, ses seviyesini sonuna\nkadar aç!\"")
assist_settings_help_media_item_max_volume_desc = TextObject(cs_CZ="Hlasitost přehrávání médií se zvýší.", da_DK="Medieafspilningens lydstyrke øges.", de_DE="Die Lautstärke der Medienwiedergabe wird angehoben.", el_GR="Θα αυξηθεί η ένταση ήχου της αναπαραγωγής μέσων.", en_GB="The volume of media playback will be increased.", es_ES="Subiendo el volumen.", fi_FI="Mediatoiston äänenvoimakkuutta nostetaan.", fr_FR="Augmentation du volume de la lecture multimédia.", hu_HU="A médiaforrás hangereje nő.", it_IT="Viene alzato il volume della riproduzione di contenuti multimediali.", nl_NL="De geluidsterkte van de mediaweergave wordt verhoogd.", no_NO="Volumet for mediekilden økes.", pl_PL="Zostaje zwiększona głośność odtwarzania multimediów.", pt_PT="O volume da reprodução mídia será aumentada.", ru_RU="Громкость воспроизведения мультимедиа увеличивается.", sv_SE="Volymen på medieuppspelningen höjs.", tr_TR="Medya yayınının ses seviyesi yükseltilir.")
assist_settings_help_media_item_next = TextObject(cs_CZ="\"Další titul.\"", da_DK="\"Næste nummer.\"", de_DE="„Nächster Titel.“", el_GR="\"Επόμενος τίτλος.\"", en_GB="\"Next track.\"", es_ES="\"Título siguiente.\"", fi_FI="\"Seuraava kappale.\"", fr_FR="«Titre suivant.»", hu_HU="„Következő szám.”", it_IT="\"Brano successivo.\"", nl_NL="\"Volgende titel.\"", no_NO="«Neste spor.»", pl_PL="„Następny utwór”.", pt_PT="\"Título seguinte.\"", ru_RU="«Следующий трек».", sv_SE="\"Nästa titel.\"", tr_TR="\"Sonraki parça.\"")
assist_settings_help_media_item_next_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, další titul.\"", da_DK="\"Hey Audi, næste nummer.\"", de_DE="„Hey Audi, nächster Titel.“", el_GR="\"Γεια σου Audi, επόμενος τίτλος.\"", en_GB="\"Hey Audi, next track.\"", es_ES="\"Hey, Audi, título siguiente.\"", fi_FI="\"Hei Audi, seuraava kappale.\"", fr_FR="«Hey Audi, titre suivant.»", hu_HU="„Hey Audi, következő szám.”", it_IT="\"Ehi Audi, brano successivo.\"", nl_NL="\"Hey Audi, volgende titel.\"", no_NO="«Hey Audi, neste spor.»", pl_PL="„Hey Audi, następny utwór”.", pt_PT="\"Olá Audi, título seguinte.\"", ru_RU="«Привет Audi, следующий трек».", sv_SE="\"Hej Audi, nästa titel.\"", tr_TR="\"Hey Audi, sonraki parça.\"")
assist_settings_help_media_item_next_desc = TextObject(cs_CZ="Přehrává se další titul.", da_DK="Næste nummer afspilles.", de_DE="Der nächste Titel wird abgespielt.", el_GR="Θα γίνει αναπαραγωγή του επόμενου τίτλου.", en_GB="The next track will be played.", es_ES="Reproduciendo el título siguiente.", fi_FI="Seuraava kappale soitetaan.", fr_FR="Lecture du titre suivant.", hu_HU="A következő műsorszám lejátszásra kerül.", it_IT="Viene riprodotto il brano successivo.", nl_NL="De volgende titel wordt afgespeeld.", no_NO="Neste spor spilles av.", pl_PL="Zostanie odtworzony następny utwór.", pt_PT="A reproduzir o título seguinte.", ru_RU="Воспроизводится следующий трек.", sv_SE="Nästa titel spelas upp.", tr_TR="Sonraki parça çalınır.")
