assist_settings_help_media_item_repeat = TextObject(cs_CZ="\"Přehraj tento titul ještě jednou.\"", da_DK="\"Spil dette nummer igen.\"", de_DE="„Spiele diesen Titel nochmal.“", el_GR="\"Παίξε ξανά αυτόν τον τίτλο.\"", en_GB="\"Play this track again.\"", es_ES="\"Pon este título otra vez.\"", fi_FI="\"Soita tämä kappale uudelleen.\"", fr_FR="«Joue de nouveau ce titre.»", hu_HU="„Játszd újra ezt a számot.”", it_IT="\"Riproduci ancora questo brano.\"", nl_NL="\"Speel deze titel opnieuw af.\"", no_NO="«Spill dette sporet igjen.»", pl_PL="„Zagraj ten utwór jeszcze raz”.", pt_PT="\"Volta a reproduzir este título.\"", ru_RU="«Включи этот трек еще раз».", sv_SE="”Spela titeln igen.”", tr_TR="\"Bu parçayı bir daha çal.\"")
