assist_settings_help_media_item_repeat_desc = TextObject(cs_CZ="Naposledy reprodukovaný titul se znovu přehraje.", da_DK="Det senest afspillede nummer afspilles igen.", de_DE="Der zuletzt wiedergegebene Titel wird erneut abgespielt.", el_GR="Ο τελευταίος αναπαραχθείς τίτλος θα αναπαραχθεί ξανά.", en_GB="The last track will be played again.", es_ES="Reproduciendo de nuevo el último título.", fi_FI="Viimeksi toistettu kappale soitetaan uudelleen.", fr_FR="Rediffusion du dernier titre lu.", hu_HU="A legutóbb játszott műsorszám újra lejátszásra kerül.", it_IT="Viene nuovamente riprodotto l'ultimo brano ascoltato.", nl_NL="De laatst afgespeelde titel wordt opnieuw ten gehore gebracht.", no_NO="Det sist avspilte sporet spilles av på nytt.", pl_PL="Zostanie ponownie odtworzony ostatni utwór.", pt_PT="O último título reproduzido será novamente reproduzido.", ru_RU="Последний воспроизведенный трек воспроизводится снова.", sv_SE="Den senast spelade titeln spelas upp igen.", tr_TR="En son yayınlanan parça tekrar çalınır.")
assist_settings_help_media_item_shuffle = TextObject(cs_CZ="\"Aktivuj přehrávání v náhodném pořadí.\"", da_DK="\"Aktiver afspilning i tilfældig rækkefølge.\"", de_DE="„Aktiviere Zufallswiedergabe.“", el_GR="\"Ενεργοποίησε την τυχαία αναπαραγωγή.\"", en_GB="\"Activate random playback.\"", es_ES="\"Activa el aleatorio.\"", fi_FI="\"Aktivoi satunnaissoitto.\"", fr_FR="«Active la lecture aléatoire.»", hu_HU="„Kapcsold be a véletlenszerű lejátszást.”", it_IT="\"Attiva riproduzione casuale.\"", nl_NL="\"Activeer willekeurige titel afspelen.\"", no_NO="«Aktiver avspilling i tilfeldig rekkefølge.»", pl_PL="„Włącz odtwarzanie losowe”.", pt_PT="\"Ativa a reprodução aleatória.\"", ru_RU="«Включи воспроизведение в случайном порядке».", sv_SE="”Aktivera slumpmässig uppspelning.”", tr_TR="\"Rastgele çalmayı etkinleştir.\"")
