assist_settings_help_media_item_spotify_desc = TextObject(cs_CZ="Přehrává se hudba od Madonny na Spotify.", da_DK="Musik af Madonna afspilles på Spotify.", de_DE="Musik von Madonna wird auf Spotify abgespielt.", el_GR="Γίνεται αναπαραγωγή μουσικής της Madonna στο Spotify.", en_GB="Music by Madonna will be played on Spotify.", es_ES="Reproduciendo música de Madonna en Spotify.", fi_FI="Madonnan musiikkia soitetaan Spotifysta.", fr_FR="Diffusion de musique de Madonna sur Spotify.", hu_HU="Madonna zenéje szól a Spotifyon.", it_IT="Viene riprodotta musica di Madonna su Spotify.", nl_NL="Muziek van Madonna wordt op Spotify afgespeeld.", no_NO="Det spilles musikk av Madonna på Spotify.", pl_PL="Zostają odtworzone utwory Madonny w serwisie Spotify.", pt_PT="A música da Madonna será reproduzida no Spotify.", ru_RU="Музыка Мадонны играет на Spotify.", sv_SE="Musik av Madonna spelas upp på Spotify.", tr_TR="Spotify'da Madonna'dan müzik çalınır.")
assist_settings_help_media_item_title = TextObject(cs_CZ="\"Co právě poslouchám?\"", da_DK="\"Hvad hører jeg lige nu?\"", de_DE="„Was höre ich gerade?“", el_GR="\"Τι ακούω αυτή τη στιγμή;\"", en_GB="\"What am I listening to?\"", es_ES="\"¿Qué está sonando?\"", fi_FI="\"Mitä kuuntelen parhaillaan?\"", fr_FR="«Que suis-je en train d'écouter?»", hu_HU="„Mit hallok most?”", it_IT="\"Cosa sto ascoltando?\"", nl_NL="\"Wat hoor ik nu?\"", no_NO="«Hva hører jeg på nå?»", pl_PL="„Czego właśnie słucham?”", pt_PT="\"O que estou a ouvir agora?\"", ru_RU="«Что я сейчас слушаю?»", sv_SE="”Vad lyssnar jag på nu?”", tr_TR="\"Şu anda ne dinliyorum?\"")
assist_settings_help_media_item_title_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, co právě poslouchám?\"", da_DK="\"Hey Audi, hvad hører jeg lige nu?\"", de_DE="„Hey Audi, was höre ich gerade?“", el_GR="\"Γεια σου Audi, τι ακούω αυτή τη\nστιγμή;\"", en_GB="\"Hey Audi, what am I listening to?\"", es_ES="\"Hey, Audi, ¿qué está sonando?\"", fi_FI="\"Hei Audi, mitä kuuntelen\nparhaillaan?\"", fr_FR="«Hey Audi, que suis-je en train\nd'écouter?»", hu_HU="„Hey Audi, mit hallok most?”", it_IT="\"Ehi Audi, cosa sto ascoltando?\"", nl_NL="\"Hey Audi, wat hoor ik nu?\"", no_NO="«Hey Audi, hva hører jeg på nå?»", pl_PL="„Hey Audi, czego właśnie\nsłucham?”", pt_PT="\"Olá Audi, o que estou a ouvir\nagora?\"", ru_RU="«Привет Audi, что я сейчас\nслушаю?»", sv_SE="”Hej Audi, vad lyssnar jag på nu?”", tr_TR="\"Hey Audi, şu anda ne\ndinliyorum?\"")
assist_settings_help_media_item_title_desc = TextObject(cs_CZ="Sdělují se informace o aktuální reprodukci.", da_DK="Informationer om den aktuelle afspilning meddeles.", de_DE="Informationen über aktuelle Wiedergabe werden mitgeteilt.", el_GR="Γνωστοποιούνται πληροφορίες για την τρέχουσα αναπαραγωγή.", en_GB="Information on what is currently playing will be shared.", es_ES="Informando sobre la reproducción actual.", fi_FI="Saat tietoa parhaillaan toistettavasta sisällöstä.", fr_FR="Indication des informations sur la lecture en cours.", hu_HU="A rendszer információkat ad az aktuális lejátszással kapcsolatban.", it_IT="Vengono fornite informazioni sulla riproduzione attuale.", nl_NL="Informatie over wat nu wordt afgespeeld wordt gegeven.", no_NO="Du får informasjon om avspillingen.", pl_PL="Zostają podane informacje dotyczące bieżącego odtwarzania.", pt_PT="Serão comunicadas informações sobre a reprodução atual.", ru_RU="Сообщается информация о текущей композиции.", sv_SE="Ger användaren information om den aktuella uppspelningen.", tr_TR="Geçerli oynatmayla ilgili bilgiler iletilir.")
assist_settings_help_navigation_item_address = TextObject(cs_CZ="„Chci do Prahy, Vinohradská 27“", da_DK="\"Jeg vil køre til Østerbrogade 9 i København.\"", de_DE="„Ich möchte nach Berlin in die Bodestraße 3.“", el_GR="„Θέλω να πάω στην Αθήνα, στην οδό Κουμπάρη 1“", en_GB="\"I'd like to go to 50 Kingston Road, London\"", es_ES="\"Quiero ir a Madrid Paseo del Prado 3\"", fi_FI="\"Haluaisin kohteeseen Helsinki osoitteeseen Museokatu 3.\"", fr_FR="«J'aimerais aller à Paris, rue de la Paix»", hu_HU="„Budapestre szeretnék menni a Tétényi út 3. címre“", it_IT="\"Vorrei andare a Roma in via Cavour 3\"", nl_NL="\"Ik wil graag naar de Beethovenstraat 27 in Amsterdam\"", no_NO="«Jeg vil til Oslo, Storgaten 33»", pl_PL="„Chcę jechać do Warszawy na ulicę Marszałkowską 3”", pt_PT="\"Quero ir para a Rua Augusta 3 em Lisboa.\"", ru_RU="«Я хочу поехать на Бодестрассе 3 в Берлине.»", sv_SE="”Jag vill till Kungsgatan 5 i Göteborg”", tr_TR="\"İstanbul'da Bağdat Caddesi 3'e gitmek istiyorum”")
assist_settings_help_navigation_item_address_aiscreen = TextObject(cs_CZ="„Ahoj Audi, chci do Berlína,\nBodestraße 3“", da_DK="\"Hey Audi, jeg vil køre til\nØsterbrogade 9 i København.\"", de_DE="„Hey Audi, ich möchte nach Berlin\nin die Bodestraße 3.“", el_GR="“Γεια σου Audi, θέλω να πάω στην\nΑθήνα, στην οδό Κουμπάρη 1.“", en_GB="\"Hey Audi, I'd like to go to 50\nKingston Road, London\"", es_ES="\"Hey, Audi, quiero ir a Madrid\nPaseo del Prado 3.\"", fi_FI="\"Haluaisin kohteeseen Helsinki\nosoitteeseen Museokatu 3.\"", fr_FR="«Hey Audi, j'aimerais aller à Paris,\nrue de la Paix.»", hu_HU="„Hey Audi, Budapestre szeretnék\nmenni a Tétényi út 3. címre.“", it_IT="\"Ehi Audi, vorrei andare a Roma in\nvia Cavour 3.\"", nl_NL="\"Hey Audi, ik wil naar Beethoven-\nstraat 27 in Amsterdam\"", no_NO="«Hey Audi, jeg vil til Oslo,\nStorgaten 33»", pl_PL="„Hey Audi, chcę jechać do\nWarszawy na Marszałkowską 3”", pt_PT="\"Olá Audi, quero ir para a Rua\nAugusta 3 em Lisboa.\"", ru_RU="«Привет Audi, я хочу поехать в\nМоскву на улицу Усачева 3».", sv_SE="”Hej Audi, jag vill till Kungsgatan 5\ni Göteborg”", tr_TR="\"Hey Audi, İstanbul'da Bağdat\nCaddesi 3'e gitmek istiyorum”")
assist_settings_help_navigation_item_address_desc = TextObject(cs_CZ="Navigace k odpovídajícímu cíli se spouští.", da_DK="Navigationen til den pågældende destination startes.", de_DE="Die Navigation zum entsprechenden Ziel wird gestartet.", el_GR="Θα ξεκινήσει η πλοήγηση στον αντίστοιχο προορισμό.", en_GB="Navigation to the corresponding destination will be started.", es_ES="Iniciando la navegación al destino.", fi_FI="Navigointi kohteeseen aloitetaan.", fr_FR="Lancement de la navigation vers la destination correspondante.", hu_HU="Elindul a navigáció a megfelelő címre.", it_IT="Viene avviata la navigazione verso la destinazione indicata.", nl_NL="De navigatie naar het betreffende doel wordt gestart.", no_NO="Navigasjon til ønsket mål startes.", pl_PL="Zostaje uruchomiona nawigacja do odpowiedniego miejsca docelowego.", pt_PT="A navegação para o respetivo destino foi iniciada.", ru_RU="Запускается навигация к соответствующей цели.", sv_SE="Navigering till motsvarande resmål startas.", tr_TR="İlgili hedefe navigasyon başlatılır.")
assist_settings_help_navigation_item_charging_station = TextObject(cs_CZ="„Dovez mě do práce.“", da_DK="\"Kør mig hen på arbejdet.\"", de_DE="„Fahr mich zur Arbeit.“", el_GR="«Οδήγησέ με στη δουλειά».", en_GB="\"Drive me to work.\"", es_ES="\"Llévame al trabajo.\"", fi_FI="\"Aja minut töihin.\"", fr_FR="«Guide-moi vers le travail.»", hu_HU="„Vezess a munkahelyemre.”", it_IT="\"Portami al lavoro.\"", nl_NL="\"Rij me naar mijn werk.\"", no_NO="«Kjør meg til jobb.»", pl_PL="„Zawieź mnie do pracy.”", pt_PT="\"Conduz-me ao trabalho.\"", ru_RU="«Отвези меня на работу».", sv_SE="”Kör mig till arbetet.”", tr_TR="\"Beni işe götür.\"")
assist_settings_help_navigation_item_charging_station_aiscreen = TextObject(cs_CZ="„Ahoj Audi, dovez mě do práce.“", da_DK="\"Hey Audi, kør mig hen på\narbejdet.\"", de_DE="„Hey Audi, fahr mich zur Arbeit.“", el_GR="\"Γεια σου Audi, οδήγησέ με στη\nδουλειά.\"", en_GB="\"Hey Audi, drive me to work.\"", es_ES="\"Hey, Audi, llévame al trabajo.\"", fi_FI="\"Hei Audi, aja minut töihin.\"", fr_FR="«Hey Audi, guide-moi vers le\ntravail.»", hu_HU="„Hey Audi, vezess a\nmunkahelyemre.”", it_IT="\"Ehi Audi, portami al lavoro.\"", nl_NL="\"Hé Audi, rij me naar mijn werk.\"", no_NO="«Hey Audi, kjør meg til jobb.»", pl_PL="„Hey Audi, zawieź mnie do pracy.”", pt_PT="\"Olá Audi, conduz-me ao\ntrabalho.\"", ru_RU="«Привет Audi, отвези меня на\nработу».", sv_SE="”Hej Audi, kör mig till arbetet.”", tr_TR="\"Hey Audi, beni işe götür.\"")
assist_settings_help_navigation_item_charging_station_desc = TextObject(cs_CZ="Spustí navádění k cíli na firemní adresu, pokud je známa.", da_DK="Starter guidningen til arbejdsadressen, hvis den er kendt.", de_DE="Startet die Zielführung zur Geschäftsadresse, sofern diese bekannt ist.", el_GR="Ξεκινά την καθοδήγηση στον προορισμό προς τη διεύθυνση της επιχείρησης, εάν είναι γνωστή.", en_GB="Start route guidance to the business address, if known.", es_ES="Se inicia la navegación hasta la dirección de trabajo, siempre y cuando la haya indicado.", fi_FI="Opastus alkaa työosoitteeseen, jos se tunnetaan.", fr_FR="Lancement du guidage vers l'adresse professionnelle si cette dernière est connue.", hu_HU="Elindul a navigálás a munkahelyi címre, ha az ismert.", it_IT="Avvia la navigazione verso l'indirizzo del lavoro, se è noto.", nl_NL="Hiermee start je de routebegeleiding naar je werkadres, als dit bekend is.", no_NO="Hvis forretningsadressen er lagret, starter veivisning dit.", pl_PL="Uruchamia prowadzenie pod adres służbowy, jeśli tylko jest znany.", pt_PT="Inicia a condução ao destino para o endereço do trabalho, desde que este seja conhecido.", ru_RU="Начинается навигация к цели по служебному адресу, если таковой известен.", sv_SE="Startar vägledning till företagsadressen om en sådan finns sparad.", tr_TR="Biliniyorsa, iş adresine rota rehberini başlatır.")
assist_settings_help_navigation_item_contact = TextObject(cs_CZ="\"Doveď mě do restaurace.\"", da_DK="\"Naviger mig til en restaurant.\"", de_DE="„Navigiere mich zu einem Restaurant.“", el_GR="\"Πλοήγησέ με σε ένα εστιατόριο.\"", en_GB="\"Navigate me to a restaurant.\"", es_ES="\"Llévame a un restaurante.\"", fi_FI="\"Navigoi minut ravintolaan.\"", fr_FR="«Guide-moi vers un restaurant.»", hu_HU="„Navigálj egy étterembe.”", it_IT="\"Portami a un ristorante.\"", nl_NL="\"Navigeer naar een restaurant.\"", no_NO="«Naviger til en restaurant.»", pl_PL="„Zaprowadź mnie do restauracji”.", pt_PT="\"Conduz-me a um restaurante.\"", ru_RU="«Отвези меня в ресторан».", sv_SE="”Navigera mig till en restaurang.”", tr_TR="\"Beni bir restorana yönlendir.\"")
assist_settings_help_navigation_item_contact_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, doveď mě do\nrestaurace.\"", da_DK="\"Hey Audi, naviger mig til en\nrestaurant.\"", de_DE="„Hey Audi, navigiere mich zu\neinem Restaurant.“", el_GR="\"Γεια σου Audi, πλοήγησέ με σε ένα\nεστιατόριο.\"", en_GB="\"Hey Audi, navigate me to a\nrestaurant.\"", es_ES="\"Hey, Audi, llévame a un\nrestaurante.\"", fi_FI="\"Hei Audi, navigoi minut\nravintolaan.\"", fr_FR="«Hey Audi, guide-moi vers un\nrestaurant.»", hu_HU="„Hey Audi, navigálj egy\nétterembe.”", it_IT="\"Ehi Audi, portami a un\nristorante.\"", nl_NL="\"Hey Audi, navigeer naar een\nrestaurant.\"", no_NO="«Hey Audi, naviger til en\nrestaurant.»", pl_PL="„Hey Audi, zaprowadź mnie do\nrestauracji”.", pt_PT="\"Olá Audi, conduz-me a um\nrestaurante.\"", ru_RU="«Привет Audi, отвези меня в\nресторан».", sv_SE="”Hej Audi, navigera mig till en\nrestaurang.”", tr_TR="\"Hey Audi, beni bir restorana\nyönlendir.\"")
assist_settings_help_navigation_item_contact_desc = TextObject(cs_CZ="Zobrazí se výběr možných restaurací.", da_DK="Et udvalg af mulige restauranter vises.", de_DE="Eine Auswahl möglicher Restaurants wird angezeigt.", el_GR="Θα εμφανιστεί μια επιλογή πιθανών εστιατορίων.", en_GB="A selection of possible restaurants will be shown.", es_ES="Mostrando lista de posibles restaurantes.", fi_FI="Mahdollisten ravintoloiden valikoima tulee näkyviin.", fr_FR="Affichage d'une sélection de restaurants.", hu_HU="Megjelenik a lehetséges éttermek választéka.", it_IT="Viene visualizzata una selezione di possibili ristoranti.", nl_NL="Een selectie van mogelijke restaurants wordt weergegeven.", no_NO="Det vises et utvalg mulige restauranter.", pl_PL="Zostaje wyświetlony wybór możliwych restauracji.", pt_PT="É apresentada uma seleção de possíveis restaurantes.", ru_RU="Отображается список возможных ресторанов.", sv_SE="Ett urval av möjliga restauranger visas.", tr_TR="Olası restoranların bir seçimi görüntülenir.")
assist_settings_help_navigation_item_gas_station = TextObject(cs_CZ="\"Hledej čerpací stanici v Nádražní ulici.\"", da_DK="\"Søg efter en tankstation på Ringvejen.\"", de_DE="„Suche mir eine Tankstelle auf der Münchener Straße.“", el_GR="\"Αναζήτησε για μένα ένα πρατήριο καυσίμων στην οδό Πειραιώς.\"", en_GB="\"Find me a filling station on London Road.\"", es_ES="\"Búscame una gasolinera en la Gran Vía.\"", fi_FI="\"Etsi minulle tankkauspaikka tieltä Hämeentie.\"", fr_FR="«Recherche une station-service dans la rue principale.»", hu_HU="„Keress nekem egy benzinkutat a Fehérvári úton.”", it_IT="\"Cercami una stazione di rifornimento in via Roma.\"", nl_NL="\"Zoek naar een tankstation op de Vierhavensstraat.\"", no_NO="«Finn en bensinstasjon i Trondhjemsveien.»", pl_PL="„Poszukaj stacji paliw przy Wojska Polskiego”.", pt_PT="\"Procura uma bomba de combustível na Rua do Freixo.\"", ru_RU="«Найди мне заправку на улице Московской».", sv_SE="”Sök efter en tankstation på Storgatan.”", tr_TR="\"Bana Bağdat Caddesi üzerinde bir benzin istasyonu bul.\"")
assist_settings_help_navigation_item_gas_station_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, hledej čerpací stanici v\nNádražní ulici.\"", da_DK="\"Hey Audi, søg efter en\ntankstation på Ringvejen.\"", de_DE="„Suche mir eine Tankstelle auf der\nMünchener Straße.“", el_GR="\"Αναζήτησε για μένα ένα πρατήριο\nκαυσίμων στην οδό Πειραιώς.\"", en_GB="\"Hey Audi, find me a filling station\non London Road.\"", es_ES="\"Hey, Audi, búscame una\ngasolinera en la Gran Vía.\"", fi_FI="\"Hei Audi, etsi minulle\ntankkauspaikka tieltä Hämeentie.\"", fr_FR="«Recherche une station-service\ndans la rue principale.»", hu_HU="„Hey Audi, keress nekem egy\nbenzinkutat a Fehérvári úton.”", it_IT="\"Ehi Audi, cercami una stazione di\nrifornimento in via Roma.\"", nl_NL="\"Zoek naar een tankstation op de\nVierhavensstraat.\"", no_NO="«Hey Audi, finn en bensinstasjon i\nTrondhjemsveien.»", pl_PL="„Hey Audi, poszukaj stacji paliw\nprzy Wojska Polskiego”.", pt_PT="\"Olá Audi, procura uma bomba de\ncombustível na Rua do Freixo.\"", ru_RU="«Найди мне заправку на улице\nМосковской».", sv_SE="”Hej Audi, sök efter en tankstation\npå Storgatan.”", tr_TR="\"Hey Audi, bana Bağdat Caddesi\nüzerinde bir benzin istasyonu bul.\"")
assist_settings_help_navigation_item_gas_station_desc = TextObject(cs_CZ="Při více výsledcích se zobrazí výběr, jinak se spustí navádění k cíli.", da_DK="Hvis der er flere resultater, vises et udvalg, ellers startes guidningen.", de_DE="Bei mehreren Ergebnissen wird eine Auswahl gezeigt, ansonsten startet die Zielführung.", el_GR="Όταν υπάρχ.πολλά αποτελέσμ.εμφαν.μ.επιλογή, αλλιώς ξεκινά η καθοδήγηση στον προορισμό.", en_GB="A selection will be shown if there are multiple results, otherwise route guidance will start.", es_ES="Si hay varios resultados, se muestran las opciones; de lo contrario, se inicia el recorrido.", fi_FI="Jos tuloksia on useampia, näkyviin tulee listaus. Muuten opastus käynnistyy.", fr_FR="Affichage d'une sélection si plusieurs résultats sont dispos, autrement lancement du guidage.", hu_HU="Ha több találat is van, egy kiválasztás jelenik meg, ellenkező esetben elindul a navigálás.", it_IT="In caso di più risultati viene visualizzata una selezione, altrimenti viene avviata la navigazione.", nl_NL="Bij meerdere resultaten wordt een selectie weergegeven, anders start de routegeleiding.", no_NO="Hvis det er flere treff, vises utvalget, ellers starter veivisningen.", pl_PL="Przy wielu wynikach pojawia się wybór, w innym razie zostanie uruchomiona nawigacja.", pt_PT="Com vários resultados, é mostrada uma seleção; caso contrário, inicia a navegação ao destino.", ru_RU="Если результатов несколько, отображается список, иначе запускается навигация к цели.", sv_SE="Vid flera resultat visas ett urval, annars startas vägledningen.", tr_TR="Birden fazla sonuç varsa, bir seçim gösterilir, aksi takdirde rota rehberi başlar.")
assist_settings_help_navigation_item_home = TextObject(cs_CZ="\"Doveď mě domů\"", da_DK="\"Kør mig hjem.\"", de_DE="„Fahr mich nach Hause.“", el_GR="\"Πήγαινέ με σπίτι\"", en_GB="\"Drive me home.\"", es_ES="\"Llévame a casa.\"", fi_FI="\"Aja minut kotiin.\"", fr_FR="«Guide-moi vers la maison.»", hu_HU="„Vigyél haza.”", it_IT="\"Portami a casa\"", nl_NL="\"Rijd me naar huis\"", no_NO="«Kjør hjem.»", pl_PL="„Zawieź mnie do domu”", pt_PT="\"Conduz-me a casa.\"", ru_RU="«Отвези меня домой»", sv_SE="”Kör mig hem”", tr_TR="\"Beni eve götür.\"")
assist_settings_help_navigation_item_home_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, doveď mě domů\"", da_DK="\"Hey Audi, kør mig hjem.\"", de_DE="„Hey Audi, fahr mich nach Hause.“", el_GR="\"Γεια σου Audi, πήγαινέ με σπίτι.\"", en_GB="\"Hey Audi, drive me home.\"", es_ES="\"Hey, Audi, llévame a casa.\"", fi_FI="\"Hei Audi, aja minut kotiin.\"", fr_FR="«Hey Audi, guide-moi vers la\nmaison.»", hu_HU="„Hey Audi, vigyél haza.”", it_IT="\"Ehi Audi, portami a casa\"", nl_NL="\"Hey Audi, rijd me naar huis\"", no_NO="«Hey Audi, kjør hjem.»", pl_PL="„Hey Audi, zawieź mnie do domu”", pt_PT="\"Olá Audi, conduz-me a casa.\"", ru_RU="«Привет Audi, отвези меня\nдомой».", sv_SE="”Hej Audi, kör mig hem”", tr_TR="\"Hey Audi, beni eve götür.\"")
assist_settings_help_navigation_item_home_desc = TextObject(cs_CZ="Spouští se navádění na adresu domů, pokud je tato adresa známa.", da_DK="Starter guidningen til hjemadressen, hvis den er kendt.", de_DE="Startet die Zielführung zur Heimatadresse sofern diese bekannt ist.", el_GR="Ξεκινά την καθοδήγηση στον προορισμό προς τη διεύθ. προέλευσης, εάν αυτή είναι γνωστή.", en_GB="Route guidance will be started to the home address if it is known.", es_ES="Se inicia la navegación hasta su casa, siempre y cuando la haya indicado.", fi_FI="Opastus kotiin aloitetaan, mikäli kotisosoite on tiedossa.", fr_FR="Lancement du guidage vers le domicile si ce dernier est connu.", hu_HU="Elindul a navigálás az otthoni címre, ha az ismert.", it_IT="Avvia la navigazione verso l'indirizzo di base, se è noto.", nl_NL="Start het navigeren naar het huisadres indien dit bekend is.", no_NO="Hvis hjemmeadressen er lagret, starter veivisning dit.", pl_PL="Zostanie uruchomione prowadzenie pod adres domowy, jeśli tylko jest znany.", pt_PT="Iniciar a condução ao destino para o endereço de casa, desde que este seja conhecido.", ru_RU="Начинается навигация к цели по домашнему адресу, если таковой известен.", sv_SE="Startar vägledning till hemadressen om en sådan finns sparad.", tr_TR="Bu biliniyorsa, ev adresine rota rehberini başlatır.")
assist_settings_help_navigation_item_hotel = TextObject(cs_CZ="\"Hledej hotel v cíli.\"", da_DK="\"Søg efter et hotel ved destinationen.\"", de_DE="„Suche mir ein Hotel am Zielort.“", el_GR="\"Βρες μου ένα ξενοδοχείο στον τόπο προορισμού.\"", en_GB="\"Find me a hotel at the destination.\"", es_ES="\"Búscame un hotel en el destino.\"", fi_FI="\"Etsi minulle hotelli kohdepaikkakunnalta.\"", fr_FR="«Recherche un hôtel à proximité de la destination.»", hu_HU="„Keress nekem egy szállodát a célállomáson.”", it_IT="\"Cercami un hotel a destinazione.\"", nl_NL="\"Zoek een hotel voor mij op de doellocatie.\"", no_NO="«Finn et hotell på reisemålet.»", pl_PL="„Znajdź hotel u celu”.", pt_PT="\"Procura um hotel no local de destino.\"", ru_RU="«Найди мне гостиницу в пункте назначения».", sv_SE="”Sök efter ett hotell vid resmålet.”", tr_TR="\"Bana hedefte bir otel bul.\"")
assist_settings_help_navigation_item_hotel_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, hledej hotel v cíli.\"", da_DK="\"Hey Audi, søg efter et hotel ved\ndestinationen.\"", de_DE="„Hey Audi, suche mir ein Hotel\nam Zielort.“", el_GR="\"Βρες μου ένα ξενοδοχείο στον\nτόπο προορισμού.\"", en_GB="\"Hey Audi, find me a hotel at the\ndestination.\"", es_ES="\"Hey, Audi, búscame un hotel en el\ndestino.\"", fi_FI="\"Hei Audi, etsi minulle hotelli\nkohdepaikkakunnalta.\"", fr_FR="«Hey Audi, recherche un hôtel à\nproximité de la destination.»", hu_HU="„Hey Audi, keress nekem egy\nszállodát a célállomáson.”", it_IT="\"Ehi Audi, cercami un hotel a\ndestinazione.\"", nl_NL="\"Hey Audi, zoek een hotel voor mij\nop de doellocatie.\"", no_NO="«Hey Audi, finn et hotell på\nreisemålet.»", pl_PL="„Hey Audi, znajdź hotel u celu”.", pt_PT="\"Olá Audi, procura um hotel no\nlocal de destino.\"", ru_RU="«Привет Audi, найди мне\nгостиницу в пункте назначения».", sv_SE="”Hej Audi, sök efter ett hotell vid\nresmålet.”", tr_TR="\"Hey Audi, bana hedefte bir otel\nbul.\"")
assist_settings_help_navigation_item_hotel_desc = TextObject(cs_CZ="Hledání hotelu v cíli se spouští.", da_DK="Søgningen efter et hotel ved destinationen startes.", de_DE="Die Suche nach einem Hotel am Zielort wird gestartet.", el_GR="Θα ξεκινήσει η αναζήτηση για ένα ξενοδοχείο στον τόπο προορισμού.", en_GB="A search for a hotel at the destination will be initiated.", es_ES="Buscando un hotel en el destino.", fi_FI="Hotellin haku kohdepaikkakunnalta käynnistetään.", fr_FR="Lancement de la recherche d'un hôtel à proximité de la destination.", hu_HU="Megkezdődik a szálloda keresése a célállomáson.", it_IT="Viene avviata la ricerca di un hotel presso la destinazione.", nl_NL="Het zoeken naar een hotel op de doellocatie wordt gestart.", no_NO="Det startes søk etter hoteller på reisemålet.", pl_PL="Zostanie uruchomione wyszukiwanie hotelu w miejscu docelowym.", pt_PT="A iniciar a procura de um hotel no local de destino.", ru_RU="Начинается поиск гостиницы в пункте назначения.", sv_SE="Sökning efter ett hotell vid resmålet startas.", tr_TR="Hedefte otel araması başlatılır.")
assist_settings_help_navigation_item_italian = TextObject(cs_CZ="\"Najdi italskou restauraci.\"", da_DK="\"Søg efter en italiensk restaurant.\"", de_DE="„Suche mir ein italienisches Restaurant.“", el_GR="\"Βρες μου ένα ιταλικό εστιατόριο.\"", en_GB="\"Find me an Italian restaurant.\"", es_ES="\"Búscame un restaurante italiano.\"", fi_FI="\"Etsi minulle italialainen ravintola.\"", fr_FR="«Recherche un restaurant italien.»", hu_HU="„Keress nekem egy olasz éttermet.”", it_IT="\"Cercami un ristorante giapponese.\"", nl_NL="\"Zoek een Italiaans restaurant.\"", no_NO="«Finn en italiensk restaurant.»", pl_PL="„Znajdź włoską restaurację”.", pt_PT="\"Procura um restaurante italiano.\"", ru_RU="«Найди мне итальянский ресторан».", sv_SE="”Sök efter en italiensk restaurang.”", tr_TR="\"Bana bir İtalyan restoranı bul.\"")
assist_settings_help_navigation_item_italian_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, najdi italskou\nrestauraci.\"", da_DK="\"Hey Audi, søg efter en italiensk\nrestaurant.\"", de_DE="„Hey Audi, suche mir ein\nitalienisches Restaurant.“", el_GR="\"Γεια σου Audi, βρες μου ένα\nιταλικό εστιατόριο.\"", en_GB="\"Hey Audi, find me an Italian\nrestaurant.\"", es_ES="\"Hey, Audi, búscame un\nrestaurante italiano.\"", fi_FI="\"Hei Audi, etsi minulle italialainen\nravintola.\"", fr_FR="«Hey Audi, recherche un\nrestaurant italien.»", hu_HU="„Hey Audi, keress nekem egy olasz\néttermet.”", it_IT="\"Ehi Audi, cercami un ristorante\ngiapponese.\"", nl_NL="\"Hey Audi, zoek een Italiaans\nrestaurant.\"", no_NO="«Hey Audi, finn en italiensk\nrestaurant.»", pl_PL="„Hey Audi, znajdź włoską\nrestaurację”.", pt_PT="\"Olá Audi, procura um restaurante\nitaliano.\"", ru_RU="«Привет Audi, найди мне\nитальянский ресторан».", sv_SE="”Hej Audi, sök efter en italiensk\nrestaurang.”", tr_TR="\"Hey Audi, bana bir İtalyan\nrestoranı bul.\"")
assist_settings_help_navigation_item_italian_desc = TextObject(cs_CZ="Hledání italské restaurace se spouští.", da_DK="Søgningen efter en italiensk restaurant startes.", de_DE="Die Suche nach einem italienischen Restaurant wird gestartet.", el_GR="Θα ξεκινήσει η αναζήτηση για ένα ιταλικό εστιατόριο.", en_GB="A search for an Italian restaurant will be initiated.", es_ES="Buscando un hotel italiano.", fi_FI="Italialaisen ravintolan haku aloitetaan.", fr_FR="Lancement de la recherche d'un restaurant italien.", hu_HU="Elindul egy olasz étterem keresése.", it_IT="Viene avviata la ricerca di un ristorante giapponese.", nl_NL="Het zoeken naar een Italiaans restaurant wordt gestart.", no_NO="Det startes søk etter en italiensk restaurant.", pl_PL="Zostaje uruchomione wyszukiwanie włoskiej restauracji.", pt_PT="A iniciar a procura de um restaurante italiano.", ru_RU="Начинается поиск итальянского ресторана.", sv_SE="Startar sökning efter en italiensk restaurang.", tr_TR="Bir İtalyan restoranı araması başlatılır.")
assist_settings_help_navigation_item_last_dest = TextObject(cs_CZ="\"Ukaž mi moje poslední cíle.\"", da_DK="\"Vis mig mine seneste destinationer.\"", de_DE="„Zeige mir meine letzten Ziele.“", el_GR="\"Δείξε μου τους τελευταίους προορισμούς.\"", en_GB="\"Show me my last destinations.\"", es_ES="\"Muéstrame los últimos destinos.\"", fi_FI="\"Näytä edelliset kohteeni.\"", fr_FR="«Affiche-moi mes destinations récentes.»", hu_HU="„Mutasd meg a legutóbbi úti céljaimat.”", it_IT="\"Mostrami le mie ultime destinazioni.\"", nl_NL="\"Laat me mijn laatste reisdoelen zien.\"", no_NO="«Vis meg de siste målene mine.»", pl_PL="„Pokaż moje ostatnie cele”.", pt_PT="\"Mostra-me os meus últimos destinos.\"", ru_RU="«Покажи мне мои последние цели».", sv_SE="”Visa mig mina senaste resmål.”", tr_TR="\"Bana son hedeflerimi göster.\"")
assist_settings_help_navigation_item_last_dest_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, ukaž mi moje poslední\ncíle.\"", da_DK="\"Hey Audi, vis mig mine seneste\ndestinationer.\"", de_DE="„Hey Audi, zeige mir meine\nletzten Ziele.“", el_GR="\"Γεια σου Audi, δείξε μου τους\nτελευταίους μου προορισμούς.\"", en_GB="\"Hey Audi, show me my last\ndestinations.\"", es_ES="\"Hey, Audi, muéstrame los últimos\ndestinos.\"", fi_FI="\"Hei Audi, näytä edelliset\nkohteeni.\"", fr_FR="«Hey Audi, affiche-moi mes\ndestinations récentes.»", hu_HU="„Hey Audi, mutasd meg a\nlegutóbbi úti céljaimat.”", it_IT="\"Ehi Audi, mostrami le mie ultime\ndestinazioni.\"", nl_NL="\"Hey Audi, laat me mijn laatste\nreisdoelen zien.\"", no_NO="«Hey Audi, vis meg de siste\nmålene mine.»", pl_PL="„Hey Audi, pokaż moje ostatnie\ncele”.", pt_PT="\"Olá Audi, mostra-me os meus\núltimos destinos.\"", ru_RU="«Привет Audi, покажи мне мои\nпоследние цели».", sv_SE="”Hej Audi, visa mig mina senaste\nresmål.”", tr_TR="\"Hey Audi, bana son hedeflerimi\ngöster.\"")
assist_settings_help_navigation_item_last_dest_desc = TextObject(cs_CZ="Zobrazí se seznam posledních cílů.", da_DK="En liste med de seneste destinationer vises.", de_DE="Eine Liste der letzten Ziele wird angezeigt.", el_GR="Θα εμφανιστεί μια λίστα των τελευταίων προορισμών.", en_GB="A list of the last destinations will be shown.", es_ES="Mostrando la lista de los últimos destinos.", fi_FI="Edellisten kohteiden lista tulee näkyviin.", fr_FR="Affichage d'une liste des destinations récentes.", hu_HU="Megjelenik a legutóbbi úti célok listája.", it_IT="Viene visualizzato un elenco delle ultime destinazioni.", nl_NL="Er wordt een lijst van de laatste reisdoelen laten zien.", no_NO="Det vises en liste over de siste målene.", pl_PL="Zostaje wyświetlona lista ostatnich celów.", pt_PT="Será apresentada uma lista dos últimos destinos.", ru_RU="Отображается список последних целей.", sv_SE="Visar en lista med de senaste resmålen.", tr_TR="Son hedeflerin bir listesi görüntülenir.")
assist_settings_help_navigation_item_map = TextObject(cs_CZ="\"Ukaž mi mapu.\"", da_DK="\"Vis mig kortet.\"", de_DE="„Zeige mir die Karte.“", el_GR="\"Δείξε μου τον χάρτη.\"", en_GB="\"Show me the map.\"", es_ES="\"Muéstrame el mapa.\"", fi_FI="\"Näytä kartta.\"", fr_FR="«Affiche-moi la carte.»", hu_HU="„Mutasd a térképet.”", it_IT="\"Mostrami la cartina.\"", nl_NL="\"Laat me de kaart zien.\"", no_NO="«Vis meg kartet.»", pl_PL="„Wyświetl mapę”.", pt_PT="\"Mostra-me o mapa.\"", ru_RU="«Покажи мне карту».", sv_SE="”Visa mig kartan.”", tr_TR="\"Bana haritayı göster.\"")
assist_settings_help_navigation_item_map3d = TextObject(cs_CZ="\"Chci přidat vložený cíl.\"", da_DK="\"Jeg vil gerne tilføje en mellemdestination.\"", de_DE="„Ich möchte ein Zwischenziel hinzufügen.“", el_GR="\"Θέλω να προσθέσω έναν ενδιάμεσο προορισμό.\"", en_GB="\"I'd like to add a stopover.\"", es_ES="\"Quiero añadir una etapa.\"", fi_FI="\"Haluan lisätä välikohteen.\"", fr_FR="«J'aimerais ajouter une étape.»", hu_HU="„Hozzá szeretnék adni egy közbenső úti célt.”", it_IT="\"Vorrei aggiungere una tappa.\"", nl_NL="\"Ik wil een tussentijds reisdoel toevoegen.\"", no_NO="«Jeg vil legge til et mellommål.»", pl_PL="„Chcę dodać cel pośredni”.", pt_PT="\"Quero adicionar um destino intermédio.\"", ru_RU="\"Я хочу добавить промежуточную цель\".", sv_SE="”Jag vill lägga till ett etappmål.”", tr_TR="\"Bir ara hedef eklemek istiyorum.\"")
assist_settings_help_navigation_item_map3d_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, chci přidat vložený cíl.\"", da_DK="\"Hey Audi, jeg vil gerne tilføje en\nmellemdestination.\"", de_DE="„Hey Audi, ich möchte ein\nZwischenziel hinzufügen.“", el_GR="\"Γεια σου Audi, θέλω να προσθέσω\nέναν ενδιάμεσο προορισμό.\"", en_GB="\"Hey Audi, I'd like to add a\nstopover.\"", es_ES="\"Hey, Audi, quiero añadir una\netapa.\"", fi_FI="\"Hei Audi, haluan lisätä\nvälikohteen.\"", fr_FR="«Hey Audi, j'aimerais ajouter une\nétape.»", hu_HU="„Hey Audi, hozzá szeretnék adni\negy közbenső úti célt.”", it_IT="\"Ehi Audi, vorrei aggiungere una\ntappa.\"", nl_NL="\"Hey Audi, ik wil een tussentijds\nreisdoel toevoegen.\"", no_NO="«Hey Audi, jeg vil legge til et\nmellommål.»", pl_PL="„Hey Audi, chcę dodać cel\npośredni”.", pt_PT="\"Olá Audi, quero adicionar um\ndestino intermédio.\"", ru_RU="«Привет Audi, я хочу добавить\nпромежуточную цель».", sv_SE="”Hej Audi, jag vill lägga till ett\netappmål.”", tr_TR="\"Hey Audi, bir ara hedef eklemek\nistiyorum.\"")
assist_settings_help_navigation_item_map3d_desc = TextObject(cs_CZ="Umožňuje zadání vloženého cíle", da_DK="Gør det muligt at angive en mellemdestination", de_DE="Die Eingabe eines Zwischenziels wird ermöglicht.", el_GR="Επιτρέπει την καταχώριση ενός ενδιάμεσου προορισμού", en_GB="Allows you to enter a stopover", es_ES="Permite introducir una etapa", fi_FI="Mahdollistaa välikohteen syöttämisen", fr_FR="Possibilité d'entrer une étape", hu_HU="Lehetővé válik egy közbenső úti cél hozzáadása.", it_IT="Consente l'immissione di una tappa", nl_NL="Maakt het mogelijk om een tussentijds reisdoel in te voeren", no_NO="Lar deg legge inn et mellommål", pl_PL="Możliwość wprowadzenia celu pośredniego", pt_PT="Permite a introdução de um destino intermédio", ru_RU="Позволяет ввести промежуточную цель", sv_SE="Möjliggör inmatning av ett etappmål", tr_TR="Bir ara hedefin girilmesini sağlar")
assist_settings_help_navigation_item_map_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, ukaž mi mapu.\"", da_DK="\"Hey Audi, vis mig kortet.\"", de_DE="„Hey Audi, zeige mir die Karte.“", el_GR="\"Γεια σου Audi, δείξε μου τον\nχάρτη.\"", en_GB="\"Hey Audi, show me the map.\"", es_ES="\"Hey, Audi, muéstrame el mapa.\"", fi_FI="\"Hei Audi, näytä kartta.\"", fr_FR="«Hey Audi, affiche-moi la carte.»", hu_HU="„Hey Audi, mutasd a térképet.”", it_IT="\"Ehi Audi, mostrami la cartina.\"", nl_NL="\"Hey Audi, laat me de kaart zien.\"", no_NO="«Hey Audi, vis meg kartet.»", pl_PL="„Hey Audi, wyświetl mapę”.", pt_PT="\"Olá Audi, mostra-me o mapa.\"", ru_RU="«Привет Audi, покажи мне\nкарту».", sv_SE="”Hej Audi, visa mig kartan.”", tr_TR="\"Hey Audi, bana haritayı göster.\"")
assist_settings_help_navigation_item_map_desc = TextObject(cs_CZ="Vyvolá se mapa.", da_DK="Kortet kaldes frem.", de_DE="Die Karte wird aufgerufen.", el_GR="Θα γίνει κλήση του χάρτη.", en_GB="The map will be called up.", es_ES="Accediendo al mapa.", fi_FI="Kartta haetaan esiin.", fr_FR="Ouverture de la carte.", hu_HU="Megjelenik a térkép.", it_IT="Viene richiamata la cartina.", nl_NL="De kaart wordt opgehaald.", no_NO="Kartet åpnes.", pl_PL="Następuje wywołanie mapy.", pt_PT="O mapa será apresentado.", ru_RU="Открывается карта.", sv_SE="Kartan öppnas.", tr_TR="Harita çağrılır.")
assist_settings_help_navigation_item_munich = TextObject(cs_CZ="\"Doveď mě do Plzně.\"", da_DK="\"Kør mig til København.\"", de_DE="„Fahre mich nach München.“", el_GR="\"Πήγαινέ με στο Μόναχο.\"", en_GB="\"Drive me to London.\"", es_ES="\"Llévame a Madrid.\"", fi_FI="\"Aja minut paikkaan Turku.\"", fr_FR="«Guide-moi vers Paris.»", hu_HU="„Vigyél el Szegedre.”", it_IT="\"Portami a Roma.\"", nl_NL="\"Rijd naar Rotterdam.\"", no_NO="«Kjør til Oslo.»", pl_PL="„Zawieź mnie do Krakowa”.", pt_PT="\"Leva-me para o Porto.\"", ru_RU="«Отвези меня в Москву».", sv_SE="”Kör mig till Göteborg.”", tr_TR="\"Beni İzmir'e götür.\"")
assist_settings_help_navigation_item_munich_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, doveď mě do Plzně.\"", da_DK="\"Hey Audi, kør mig til København.\"", de_DE="„Hey Audi, fahre mich nach\nMünchen.“", el_GR="\"Γεια σου Audi, πήγαινέ με στο\nΜόναχο.\"", en_GB="\"Hey Audi, drive me to London.\"", es_ES="\"Hey, Audi, llévame a Madrid.\"", fi_FI="\"Hei Audi, aja minut paikkaan\nTurku.\"", fr_FR="«Hey Audi, guide-moi vers Paris.»", hu_HU="„Hey Audi, vigyél el Szegedre.”", it_IT="\"Ehi Audi, portami a Roma.\"", nl_NL="\"Hey Audi, rijd naar Rotterdam.\"", no_NO="«Hey Audi, kjør til Oslo.»", pl_PL="„Hey Audi, zawieź mnie do\nKrakowa”.", pt_PT="\"Olá Audi, leva-me para o Porto.\"", ru_RU="«Привет Audi, отвези меня в\nМоскву».", sv_SE="”Hej Audi, kör mig till Göteborg.”", tr_TR="\"Hey Audi, beni İzmir'e götür.\"")
assist_settings_help_navigation_item_munich_desc = TextObject(cs_CZ="Navigace do centra Plzně se spouští.", da_DK="Navigationen til Københavns centrum startes.", de_DE="Die Navigation in das Zentrum von München wird gestartet.", el_GR="Θα εκκινηθεί η πλοήγηση προς το κέντρο της Αθήνας.", en_GB="Navigation to the centre of London will be started.", es_ES="Iniciando la navegación al centro de Madrid.", fi_FI="Navigointi aloitetaan paikan Turku keskustaan.", fr_FR="Lancement de la navigation vers le centre de Paris.", hu_HU="Elindul a navigáció Szeged központjába.", it_IT="Viene avviata la navigazione verso il centro di Roma.", nl_NL="De navigatie naar het centrum van Rotterdam wordt gestart.", no_NO="Navigasjon til Oslo sentrum startes.", pl_PL="Zostaje włączona nawigacja do centrum Krakowa.", pt_PT="A iniciar a navegação para o centro do Porto.", ru_RU="Начинается навигация к центру Москвы.", sv_SE="Navigering till Göteborg centrum startas.", tr_TR="İzmir'in merkezine navigasyon başlatılır.")
assist_settings_help_navigation_item_parking_dest = TextObject(cs_CZ="\"Hledej parkoviště u Národního divadla.\"", da_DK="\"Søg efter en parkeringsplads ved Marselisborg Slot.\"", de_DE="„Suche einen Parkplatz am Brandenburger Tor.“", el_GR="\"Βρες μια θέση στάθμευσης στην Πλατεία Συντάγματος.\"", en_GB="\"Find a car park by Buckingham Palace.\"", es_ES="\"Busca un aparcamiento en Puerta de Atocha.\"", fi_FI="\"Etsi pysäköintipaikka paikasta Eduskuntatalo.\"", fr_FR="«Recherche une place de stationnement à proximité de l'Arc de Triomphe.»", hu_HU="„Keress egy parkolóhelyet az Astoriánál.”", it_IT="\"Cerca un parcheggio vicino al Colosseo.\"", nl_NL="\"Zoek een parkeerplaats bij het Anne Frank Huis.\"", no_NO="«Finn en parkeringsplass ved Operaen.»", pl_PL="„Znajdź parking pod Pałacem Kultury”.", pt_PT="\"Procura estacionamento na Torre de Belém.\"", ru_RU="«Найди стоянку на Кудринской площади».", sv_SE="”Sök efter en parkeringsplats vid Brunnsparken.”", tr_TR="\"Topkapı'da bir park yeri bul.\"")
assist_settings_help_navigation_item_parking_dest_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, hledej parkoviště u\nNárodního divadla.\"", da_DK="\"Søg efter en parkeringsplads ved\nMarselisborg Slot.\"", de_DE="„Hey Audi, suche einen Parkplatz\nam Brandenburger Tor.“", el_GR="\"Βρες μια θέση στάθμευσης στην\nΠλατεία Συντάγματος.\"", en_GB="\"Hey Audi, find a car park by\nBuckingham Palace.\"", es_ES="\"Hey, Audi, busca un aparcamiento\nen Puerta de Atocha.\"", fi_FI="\"Hei Audi, etsi pysäköintipaikka\npaikasta Eduskuntatalo.\"", fr_FR="«Hey Audi, recherche une place\nprès de l'Arc de Triomphe.»", hu_HU="„Hey Audi, keress egy\nparkolóhelyet az Astoriánál.”", it_IT="\"Ehi Audi, cerca un parcheggio\nvicino al Colosseo.\"", nl_NL="\"Hey Audi, zoek een parkeerplaats\nbij het Anne Frank Huis.\"", no_NO="«Hey Audi, finn en parkeringsplass\nved Operaen.»", pl_PL="„Hey Audi, znajdź parking pod\nPałacem Kultury”.", pt_PT="\"Procura estacionamento na Torre\nde Belém.\"", ru_RU="«Привет Audi, найди стоянку на\nКудринской площади».", sv_SE="”Sök efter en parkeringsplats vid\nBrunnsparken.”", tr_TR="\"Hey Audi, Topkapı'da bir park yeri\nbul.\"")
assist_settings_help_navigation_item_parking_dest_desc = TextObject(cs_CZ="Hledání možností parkování v blízkosti Národního divadla se spouští.", da_DK="Søgningen efter parkeringsmuligheder i nærheden af Marselisborg Slot startes.", de_DE="Die Suche nach Parkmöglichkeiten in der Nähe des Brandenburger Tors wird gestartet.", el_GR="Θα ξεκινήσει η αναζήτηση για δυνατότητες στάθμευσης κοντά στην Πλατεία Συντάγματος.", en_GB="A search for car parks near Buckingham Palace will be initiated.", es_ES="Buscando aparcamientos cerca de Puerta de Atocha.", fi_FI="Pysäköintipaikkojen haku aloitetaan läheltä paikkaa Eduskuntatalo.", fr_FR="Lancement de la recherche de parkings à proximité de l'Arc de Triomphe.", hu_HU="Megkezdődik a parkolási lehetőségek keresése az Astoriánál.", it_IT="Viene avviata la ricerca di opzioni di parcheggio nelle vicinanze del Colosseo.", nl_NL="Er wordt gezocht naar parkeerplaatsen in de buurt van het Anne Frank Huis.", no_NO="Det startes søk etter parkeringsmuligheter nær Operaen.", pl_PL="Zostanie uruchomione wyszukiwanie miejsc postojowych w pobliżu Pałacu Kultury.", pt_PT="A iniciar a procura de estacionamento nas imediações da Torre de Belém.", ru_RU="Начинается поиск стоянки вблизи Кудринской площади.", sv_SE="Startar sökning efter parkeringsmöjligheter i närheten av Brunnsparken.", tr_TR="Topkapı yakınındaki park yeri olanaklarının aranması başlatılır.")
assist_settings_help_navigation_item_parking_route = TextObject(cs_CZ="\"Hledej parkoviště podél trasy.\"", da_DK="\"Søg efter en parkeringsplads langs med ruten.\"", de_DE="„Suche mir einen Parkplatz entlang der Route.“", el_GR="\"Βρες μου μια θέση στάθμευσης κατά μήκος της διαδρομής.\"", en_GB="\"Find me a car park along the route.\"", es_ES="\"Búscame un aparcamiento a lo largo de la ruta.\"", fi_FI="\"Etsi pysäköintipaikka reitin varrelta.\"", fr_FR="«Recherche une place de stationnement le long de l'itinéraire.»", hu_HU="„Keress egy parkolóhelyet az útvonal mentén.”", it_IT="\"Cercami un parcheggio lungo l'itinerario.\"", nl_NL="\"Zoek een parkeerplaats langs de route.\"", no_NO="«Finn en parkeringsplass langs ruten.»", pl_PL="„Znajdź parking na trasie”.", pt_PT="\"Procurar um lugar de estacionamento ao longo do trajeto.\"", ru_RU="«Найди мне стоянку вдоль маршрута».", sv_SE="”Sök efter en parkeringsplats längs rutten.”", tr_TR="\"Rota boyunca benim için bir park yeri bul.\"")
assist_settings_help_navigation_item_parking_route_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, hledej parkoviště\npodél trasy.\"", da_DK="\"Hey Audi, søg efter en\nparkeringsplads langs med ruten.\"", de_DE="„Hey Audi, suche mir einen\nParkplatz entlang der Route.“", el_GR="\"Βρες μου μια θέση στάθμευσης\nκατά μήκος της διαδρομής.\"", en_GB="\"Hey Audi, find me a car park\nalong the route.\"", es_ES="\"Búscame un aparcamiento a lo\nlargo de la ruta.\"", fi_FI="\"Hei Audi, etsi pysäköintipaikka\nreitin varrelta.\"", fr_FR="«Hey Audi, cherche une place de\nstationn. le long de l'itinéraire.»", hu_HU="„Hey Audi, keress egy\nparkolóhelyet az útvonal mentén.”", it_IT="\"Ehi Audi, cercami un parcheggio\nlungo l'itinerario.\"", nl_NL="\"Hey Audi, zoek een parkeerplaats\nlangs de route.\"", no_NO="«Hey Audi, finn en parkeringsplass\nlangs ruten.»", pl_PL="„Hey Audi, znajdź parking na\ntrasie”.", pt_PT="\"Procurar um lugar de\nestacionamento ao longo trajeto.\"", ru_RU="«Привет Audi, найди мне стоянку\nвдоль маршрута».", sv_SE="”Hej Audi, sök efter en\nparkeringsplats längs rutten.”", tr_TR="\"Hey Audi, rota boyunca benim için\nbir park yeri bul.\"")
assist_settings_help_navigation_item_parking_route_desc = TextObject(cs_CZ="Hledání parkoviště podél trasy se spouští.", da_DK="Søgningen efter en parkeringsplads langs med ruten startes.", de_DE="Die Suche eines Parkplatzes entlang der Route wird gestartet.", el_GR="Θα ξεκινήσει η αναζήτηση για μια θέση στάθμευσης κατά μήκος της διαδρομής.", en_GB="A search for a car park along the route will be initiated.", es_ES="Buscando aparcamiento a lo largo de la ruta.", fi_FI="Pysäköintipaikan haku reitin varrelta aloitetaan.", fr_FR="Lancement de la recherche d'une place de stationnement le long de l'itinéraire.", hu_HU="Megkezdődik a parkolóhely keresése az útvonal mentén.", it_IT="Viene avviata la ricerca di un parcheggio lungo l'itinerario.", nl_NL="Het zoeken naar een parkeerplaats langs de route wordt gestart.", no_NO="Det startes søk etter en parkeringsplass langs ruten.", pl_PL="Zostanie uruchomione wyszukiwanie parkingu na trasie.", pt_PT="A iniciar a procura de um estacionamento ao longo do trajeto.", ru_RU="Начинается поиск стоянки вдоль маршрута.", sv_SE="Startar sökning efter en parkeringsplats längs rutten.", tr_TR="Rota boyunca bir park yeri aranması başlatılır.")
assist_settings_help_navigation_item_restaurant = TextObject(cs_CZ="\"Najdi restauraci v blízkosti.\"", da_DK="\"Søg efter en restaurant i nærheden.\"", de_DE="„Suche mir ein Restaurant in der Nähe.“", el_GR="\"Βρες μου ένα εστιατόριο στη γύρω περιοχή.\"", en_GB="\"Find me a restaurant nearby.\"", es_ES="\"Búscame un restaurante cerca.\"", fi_FI="\"Etsi minulle ravintola lähistöltä.\"", fr_FR="«Recherche un restaurant à proximité.»", hu_HU="„Keress nekem egy éttermet a közelben.”", it_IT="\"Cercami un ristorante nei dintorni.\"", nl_NL="\"Zoek een restaurant in de buurt.\"", no_NO="«Finn en restaurant i nærheten.»", pl_PL="„Znajdź restaurację w pobliżu”.", pt_PT="\"Procura um restaurante nas imediações.\"", ru_RU="«Найди мне ближайший ресторан».", sv_SE="”Sök efter en restaurang i närheten.”", tr_TR="\"Bana yakınlarda bir restoran bul.\"")
assist_settings_help_navigation_item_restaurant_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, najdi restauraci v\nblízkosti.\"", da_DK="\"Hey Audi, søg efter en restaurant\ni nærheden.\"", de_DE="„Hey Audi, suche mir ein\nRestaurant in der Nähe.“", el_GR="\"Γεια σου Audi, βρες μου ένα\nεστιατόριο στη γύρω περιοχή.\"", en_GB="\"Hey Audi, find me a restaurant\nnearby.\"", es_ES="\"Hey, Audi, búscame un\nrestaurante cerca.\"", fi_FI="\"Hei Audi, etsi minulle ravintola\nlähistöltä.\"", fr_FR="«Hey Audi, recherche un\nrestaurant à proximité.»", hu_HU="„Hey Audi, keress nekem egy\néttermet a közelben.”", it_IT="\"Ehi Audi, cercami un ristorante\nnei dintorni.\"", nl_NL="\"Hey Audi, zoek een restaurant in\nde buurt.\"", no_NO="«Hey Audi, finn en restaurant i\nnærheten.»", pl_PL="„Hey Audi, znajdź restaurację w\npobliżu”.", pt_PT="\"Olá Audi, procura um restaurante\nnas imediações.\"", ru_RU="«Привет Audi, найди мне\nближайший ресторан».", sv_SE="”Hej Audi, sök efter en restaurang\ni närheten.”", tr_TR="\"Hey Audi, bana yakınlarda bir\nrestoran bul.\"")
assist_settings_help_navigation_item_restaurant_desc = TextObject(cs_CZ="Hledání restaurace v okolí se spouští.", da_DK="Søgningen efter en restaurant i nærheden startes.", de_DE="Die Suche eines Restaurants im Umkreis wird gestartet.", el_GR="Θα ξεκινήσει η αναζήτηση για ένα εστιατόριο στη γύρω περιοχή.", en_GB="A search for restaurants nearby will be initiated.", es_ES="Buscando un restaurante cerca.", fi_FI="Ravintolan haku lähistöltä aloitetaan.", fr_FR="Lancement de la recherche d'un restaurant à proximité.", hu_HU="Elindul az étterem keresése a környéken.", it_IT="Viene avviata la ricerca di un ristorante nelle vicinanze.", nl_NL="Het zoeken naar een restaurant in de omgeving wordt gestart.", no_NO="Det startes søk etter en restaurant i nærheten.", pl_PL="Zostaje uruchomione wyszukiwanie restauracji w okolicy.", pt_PT="A iniciar a procura de um restaurante nas imediações.", ru_RU="Начинается поиск ближайшего ресторана.", sv_SE="Startar sökning efter en restaurang i närheten.", tr_TR="Çevredeki bir restoranın aranması başlatılır.")
assist_settings_help_navigation_item_speech = TextObject(cs_CZ="\"Doveď mě na letiště Praha.\"", da_DK="\"Kør mig til Københavns Lufthavn.\"", de_DE="„Fahre mich zum Flughafen München.“", el_GR="\"Πήγαινέ με στο Αεροδρόμιο Ελληνικού.\"", en_GB="\"Drive me to Heathrow Airport.\"", es_ES="\"Llévame al aeropuerto de Madrid.\"", fi_FI="\"Aja minut paikkaan Turun lentokenttä.\"", fr_FR="«Guide-moi vers l'aéroport de Lyon.»", hu_HU="„Vigyél el a budapesti repülőtérre.”", it_IT="\"Portami all'aeroporto di Bergamo.\"", nl_NL="\"Rijd me naar Maastricht Airport.\"", no_NO="«Kjør til Oslo lufthavn.»", pl_PL="„Zawieź mnie na lotnisko w Krakowie”.", pt_PT="\"Conduz-me ao aeroporto do Porto.\"", ru_RU="«Отвези меня в аэропорт Внуково».", sv_SE="”Kör mig till Arlanda flygplats.”", tr_TR="\"Beni İzmir havalimanına götür.\"")
assist_settings_help_navigation_item_speech_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, doveď mě na letiště\nPraha.\"", da_DK="\"Hey Audi, kør mig til Københavns\nLufthavn.\"", de_DE="„Hey Audi, fahre mich zum\nFlughafen München.“", el_GR="\"Γεια σου Audi, πήγαινέ με στο\nΑεροδρόμιο Ελληνικού.\"", en_GB="\"Hey Audi, drive me to Heathrow\nAirport.\"", es_ES="\"Hey, Audi, llévame al aeropuerto\nde Madrid.\"", fi_FI="\"Hei Audi, aja minut paikkaan\nTurun lentokenttä.\"", fr_FR="«Hey Audi, guide-moi vers\nl'aéroport de Lyon.»", hu_HU="„Hey Audi, vigyél el a budapesti\nrepülőtérre.”", it_IT="\"Ehi Audi, portami all'aeroporto di\nBergamo.\"", nl_NL="\"Hey Audi, rijd me naar Maastricht\nAirport.\"", no_NO="«Hey Audi, kjør til Oslo lufthavn.»", pl_PL="„Hey Audi, zawieź mnie na\nlotnisko w Krakowie”.", pt_PT="\"Olá Audi, conduz-me ao\naeroporto do Porto.\"", ru_RU="«Привет Audi, отвези меня в\nаэропорт Внуково».", sv_SE="”Hej Audi, kör mig till Arlanda\nflygplats.”", tr_TR="\"Hey Audi, beni İzmir havalimanına\ngötür.\"")
assist_settings_help_navigation_item_speech_desc = TextObject(cs_CZ="Navigace na letiště Praha se spouští.", da_DK="Navigationen til Københavns Lufthavn startes.", de_DE="Die Navigation zum Flughafen München wird gestartet.", el_GR="Θα εκκινηθεί η πλοήγηση προς το Αεροδρόμιο Ελληνικού.", en_GB="Navigation to Heathrow Airport will be started.", es_ES="Iniciando la navegación al aeropuerto de Madrid.", fi_FI="Navigointi aloitetaan paikkaan Turun lentokenttä.", fr_FR="Lancement de la navigation vers l'aéroport de Lyon.", hu_HU="Elindul a navigáció a budapesti repülőtérre.", it_IT="Viene avviata la navigazione verso l'aeroporto di Bergamo.", nl_NL="De navigatie naar Maastricht Airport wordt gestart.", no_NO="Navigasjon til Oslo lufthavn startes.", pl_PL="Zostaje włączona nawigacja na lotnisko w Krakowie.", pt_PT="A iniciar a navegação para o aeroporto do Porto.", ru_RU="Начинается навигация в аэропорт Внуково.", sv_SE="Startar navigering till Arlanda flygplats.", tr_TR="İzmir havalimanına navigasyon başlatılır.")
assist_settings_help_navigation_item_starbucks = TextObject(cs_CZ="\"Doveď mě ke Starbucks.\"", da_DK="\"Kør mig til Starbucks.\"", de_DE="„Fahre mich zu Starbucks.“", el_GR="\"Πήγαινέ με στο Starbucks.\"", en_GB="\"Drive me to Starbucks.\"", es_ES="\"Llévame a un Starbucks.\"", fi_FI="\"Aja minut kahvilaan Picnic.\"", fr_FR="«Guide-moi chez Starbucks.»", hu_HU="„Vigyél el egy Starbucksba.”", it_IT="\"Portami da McDonald's.\"", nl_NL="\"Rijd me naar Starbucks.\"", no_NO="«Kjør til Starbucks.»", pl_PL="„Zawieź mnie do Starbucks”.", pt_PT="\"Conduz-me ao Starbucks.\"", ru_RU="«Отвези меня в Starbucks».", sv_SE="”Kör mig till Starbucks.”", tr_TR="\"Beni Starbucks'a götür.\"")
assist_settings_help_navigation_item_starbucks_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, doveď mě ke\nStarbucks.\"", da_DK="\"Hey Audi, kør mig til Starbucks.\"", de_DE="„Hey Audi, fahre mich zu\nStarbucks.“", el_GR="\"Γεια σου Audi, πήγαινέ με στο\nStarbucks.\"", en_GB="\"Hey Audi, drive me to Starbucks.\"", es_ES="\"Hey, Audi, llévame a un\nStarbucks.\"", fi_FI="\"Hei Audi, aja minut kahvilaan\nPicnic.\"", fr_FR="«Hey Audi, guide-moi chez\nStarbucks.»", hu_HU="„Hey Audi, vigyél el egy\nStarbucksba.”", it_IT="\"Ehi Audi, portami da\nMcDonald's.\"", nl_NL="\"Hey Audi, rijd me naar\nStarbucks.\"", no_NO="«Hey Audi, kjør til Starbucks.»", pl_PL="„Hey Audi, zawieź mnie do\nStarbucks”.", pt_PT="\"Olá Audi, conduz-me ao\nStarbucks.\"", ru_RU="«Привет Audi, отвези меня в\nStarbucks».", sv_SE="”Hej Audi, kör mig till Starbucks.”", tr_TR="\"Hey Audi, beni Starbucks'a götür.\"")
assist_settings_help_navigation_item_starbucks_desc = TextObject(cs_CZ="Navigace ke Starbucks Café se spouští.", da_DK="Navigationen til en Starbucks-café startes.", de_DE="Die Navigation zu einem Starbucks Café wird gestartet.", el_GR="Θα εκκινηθεί η πλοήγηση προς ένα καφέ Starbucks.", en_GB="Navigation to a Starbucks café will be started.", es_ES="Iniciando la navegación a un establecimiento Starbucks.", fi_FI="Navigointi kahvilaan Picnic aloitetaan.", fr_FR="Lancement de la navigation vers un café Starbucks.", hu_HU="Elindul a navigáció egy Starbuckshoz.", it_IT="Viene avviata la navigazione verso un ristorante McDonald's.", nl_NL="De navigatie naar een Starbucks Café wordt gestart.", no_NO="Navigasjon til en Starbucks-kafé startes.", pl_PL="Zostaje włączona nawigacja do kawiarni Starbucks.", pt_PT="A iniciar a navegação para um café Starbucks.", ru_RU="Начинается навигация к кофейне Starbucks.", sv_SE="Startar navigering till ett Starbucks-café.", tr_TR="Bir Starbucks kafeye navigasyon başlatılır.")
assist_settings_help_navigation_item_time = TextObject(cs_CZ="\"Kdy přijedu?\"", da_DK="\"Hvornår ankommer jeg?\"", de_DE="„Wann komme ich an?“", el_GR="\"Πότε θα φθάσω;\"", en_GB="\"When will I arrive?\"", es_ES="\"¿A qué hora llego?\"", fi_FI="\"Milloin saavun perille?\"", fr_FR="«Quand est-ce que j'arrive?»", hu_HU="„Mikor érek oda?”", it_IT="\"Quando arrivo?\"", nl_NL="\"Wanneer kom ik aan?\"", no_NO="«Når er jeg fremme?»", pl_PL="„O której przyjadę?”", pt_PT="\"A que horas chego?\"", ru_RU="«Когда я приеду?»", sv_SE="”När kommer jag fram?”", tr_TR="\"Ne zaman varırım?\"")
assist_settings_help_navigation_item_time_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, kdy přijedu?\"", da_DK="\"Hey Audi, hvornår ankommer\njeg?\"", de_DE="„Hey Audi, wann komme ich an?“", el_GR="\"Γεια σου Audi, πότε θα φθάσω;\"", en_GB="\"Hey Audi, when will I arrive?\"", es_ES="\"Hey, Audi, ¿a qué hora llego?\"", fi_FI="\"Hei Audi, milloin saavun perille?\"", fr_FR="«Hey Audi, quand est-ce que\nj'arrive?»", hu_HU="„Hey Audi, mikor érek oda?”", it_IT="\"Ehi Audi, quando arrivo?\"", nl_NL="\"Hey Audi, wanneer kom ik aan?\"", no_NO="«Hey Audi, når er jeg fremme?»", pl_PL="„Hey Audi, o której przyjadę?”", pt_PT="\"Olá Audi, a que horas chego?\"", ru_RU="«Привет Audi, когда я приеду?»", sv_SE="”Hej Audi, när kommer jag fram?”", tr_TR="\"Hey Audi, ne zaman varırım?\"")
assist_settings_help_navigation_item_time_desc = TextObject(cs_CZ="Uvede se předpokládaný čas příjezdu.", da_DK="Den forventede ankomsttid angives.", de_DE="Die voraussichtliche Ankunftszeit wird angegeben.", el_GR="Θα αναφερθεί ο εκτιμώμενος χρόνος άφιξης.", en_GB="The estimated arrival time will be specified.", es_ES="Calculando la hora de llegada prevista.", fi_FI="Odotettavissa oleva saapumisaika ilmoitetaan.", fr_FR="Indication de l'heure d'arrivée prévue.", hu_HU="Megadásra kerül a várható érkezési idő.", it_IT="Viene indicato l'orario di arrivo previsto.", nl_NL="De verwachte aankomsttijd wordt aangegeven.", no_NO="Beregnet ankomsttid oppgis.", pl_PL="Zostaje podany przewidywany czas przyjazdu.", pt_PT="Será apresentada a hora prevista de chegada.", ru_RU="Сообщается предполагаемое время прибытия.", sv_SE="Indikerar den förväntade ankomsttiden.", tr_TR="Tahmini varış zamanı belirtilir.")
assist_settings_help_navigation_item_tired = TextObject(cs_CZ="\"Jsem unavený.\"", da_DK="\"Jeg er træt.\"", de_DE="„Ich bin müde.“", el_GR="\"Είμαι κουρασμένος.\"", en_GB="\"I'm tired.\"", es_ES="\"Estoy cansado.\"", fi_FI="\"Olen väsynyt.\"", fr_FR="«Je suis fatigué.»", hu_HU="„Fáradt vagyok.”", it_IT="\"Sono stanco.\"", nl_NL="\"Ik ben moe.\"", no_NO="«Jeg er trøtt.»", pl_PL="\"Jestem zmęczony.\"", pt_PT="\"Estou cansado.\"", ru_RU="\"Я устал.\"", sv_SE="\"Jag är trött.\"", tr_TR="\"Çok uykum var.\"")
assist_settings_help_navigation_item_tired_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, jsem unavený.\"", da_DK="\"Hey Audi, jeg er træt.\"", de_DE="„Hey Audi, ich bin müde.“", el_GR="\"Γεια σου Audi, είμαι\nκουρασμένος.\"", en_GB="\"Hey Audi, I'm tired.\"", es_ES="\"Hey, Audi, estoy cansado.\"", fi_FI="\"Hei Audi, olen väsynyt.\"", fr_FR="«Hey Audi, je suis fatigué.»", hu_HU="„Hey Audi, fáradt vagyok.”", it_IT="\"Ehi Audi, sono stanco.\"", nl_NL="\"Hey Audi, ik ben moe.\"", no_NO="«Hey Audi, jeg er trøtt.»", pl_PL="\"Hey Audi, jestem zmęczony.\"", pt_PT="\"Olá Audi, estou cansado.\"", ru_RU="«Привет Audi, я устал».", sv_SE="\"Hej Audi, jag är trött.\"", tr_TR="\"Hey Audi, ben yorgunum.\"")
assist_settings_help_navigation_item_tired_desc = TextObject(cs_CZ="Hledání odpočívadel podél trasy nebo v okolí se spouští.", da_DK="Søgningen efter rasteplads langs med ruten eller i nærheden startes.", de_DE="Die Suche nach Rastplätzen entlang der Route oder im Umkreis wird gestartet.", el_GR="Θα ξεκιν. η αναζήτ. γ. χώρους ανάπαυσης κατά μήκος τ. διαδρομής ή στη γύρω περιοχή.", en_GB="The search for rest areas along the route or in the vicinity will be initiated.", es_ES="Buscando áreas de descanso cerca o a lo largo de la ruta.", fi_FI="Taukopaikkojen haku reitin varrelta tai lähistöltä aloitetaan.", fr_FR="Lancement de la recherche d'aires de repos le long de l'itinéraire ou à proximité.", hu_HU="Megkezdődik a pihenőhelyek keresése az útvonal mentén vagy a környéken.", it_IT="Viene avviata la ricerca di aree di sosta lungo l'itinerario o nei dintorni.", nl_NL="Het zoeken naar wegrestaurants op de route of in de omgeving wordt gestart.", no_NO="Det startes søk etter rasteplasser langs ruten eller i nærheten.", pl_PL="Zostanie uruchomione wyszukiwanie miejsc odpoczynku na trasie lub w okolicy.", pt_PT="A iniciar a pesquisa de áreas de repouso ao longo do trajeto ou nas imediações.", ru_RU="Начинается поиск площадок для отдыха на маршруте или в окрестностях.", sv_SE="Sökningen efter rastplatser längs rutten eller i närheten har påbörjats.", tr_TR="Rota boyunca veya çevredeki dinlenme alanlarının aranması başlatılır.")
assist_settings_help_navigation_item_tor = TextObject(cs_CZ="\"Doveď mě k Pražskému hradu.\"", da_DK="\"Kør mig til Marselisborg Slot.\"", de_DE="„Fahre mich zum Brandenburger Tor.“", el_GR="\"Πήγαινέ με στην Ακρόπολη.\"", en_GB="\"Drive me to Buckingham Palace.\"", es_ES="\"Llévame a Puerta de Atocha.\"", fi_FI="\"Aja minut paikkaan Eduskuntatalo.\"", fr_FR="«Guide-moi vers l'Arc de Triomphe.»", hu_HU="„Vigyél el a Szegedi Dómhoz.”", it_IT="\"Portami al Colosseo.\"", nl_NL="\"Rijd naar het Anne Frank Huis.\"", no_NO="«Kjør til Operaen.»", pl_PL="„Zawieź mnie pod Pałac Kultury”.", pt_PT="\"Guia-me até à Torre de Belém.\"", ru_RU="«Отвези меня к Бранденбургским воротам».", sv_SE="”Kör mig till Brunnsparken.”", tr_TR="\"Beni Topkapı'ya götür.\"")
assist_settings_help_navigation_item_tor_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, doveď mě k Pražskému\nhradu.\"", da_DK="\"Hey Audi, kør mig til Marselisborg\nSlot.\"", de_DE="„Hey Audi, fahre mich zum\nBrandenburger Tor.“", el_GR="\"Γεια σου Audi, πήγαινέ με στην\nΑκρόπολη.\"", en_GB="\"Hey Audi, drive me to\nBuckingham Palace.\"", es_ES="\"Hey, Audi, llévame a Puerta de\nAtocha.\"", fi_FI="\"Hei Audi, aja minut paikkaan\nEduskuntatalo.\"", fr_FR="«Hey Audi, guide-moi vers l'Arc de\nTriomphe.»", hu_HU="„Hey Audi, vigyél el a Szegedi\nDómhoz.”", it_IT="\"Ehi Audi, portami al Colosseo.\"", nl_NL="\"Hey Audi, rijd naar het Anne\nFrank Huis.\"", no_NO="«Hey Audi, kjør til Operaen.»", pl_PL="„Hey Audi, zawieź mnie pod Pałac\nKultury”.", pt_PT="\"Olá Audi, guia-me até à Torre de\nBelém.\"", ru_RU="«Привет Audi, отвези меня на\nКудринскую площадь».", sv_SE="”Hej Audi, kör mig till\nBrunnsparken.”", tr_TR="\"Hey Audi, beni Topkapı'ya götür.\"")
assist_settings_help_navigation_item_tor_desc = TextObject(cs_CZ="Navigace k Pražskému hradu se spouští", da_DK="Navigation til Marselisborg Slot startes.", de_DE="Die Navigation zum Brandenburger Tor wird gestartet.", el_GR="Θα ξεκινήσει η πλοήγηση προς την Ακρόπολη", en_GB="Starting navigation to Buckingham Palace", es_ES="Iniciando la navegación a Puerta de Atocha", fi_FI="Navigointi aloitetaan paikkaan Eduskuntatalo", fr_FR="Lancement de la navigation vers l'Arc de Triomphe", hu_HU="Elindul a navigáció a Szegedi Dómhoz", it_IT="Viene avviata la navigazione verso il Colosseo", nl_NL="De navigatie naar het Anne Frank Huis wordt gestart", no_NO="Starter navigasjon til Operaen", pl_PL="Zostaje uruchomiona nawigacja do Pałacu Kultury", pt_PT="A iniciar a navegação até à Torre de Belém", ru_RU="Навигация к Бранденбургским воротам начата", sv_SE="Navigering till Brunnsparken startas", tr_TR="Topkapı'ya navigasyon başlatılır")
assist_settings_help_phone_item_call = TextObject(cs_CZ="\"Zavolej Jiřího.\"", da_DK="\"Ring op til Jens.\"", de_DE="„Ruf bei Max an.“", el_GR="\"Κάλεσε τον Κώστα.\"", en_GB="\"Call Max.\"", es_ES="\"Llama a María.\"", fi_FI="\"Soita kontaktille Matti.\"", fr_FR="«Appelle Pierre.»", hu_HU="„Hívd fel Maxot.“", it_IT="\"Chiama Max.\"", nl_NL="\"Bel Max.\"", no_NO="«Ring Jan.»", pl_PL="„Zadzwoń do Maksa”.", pt_PT="\"Liga ao Max.\"", ru_RU="«Позвони Максу».", sv_SE="”Ring till Erik.”", tr_TR="\"Ali'yi ara.\"")
assist_settings_help_phone_item_call_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, zavolej Jiřího.\"", da_DK="\"Hey Audi, ring op til Jens.\"", de_DE="„Hey Audi, ruf bei Max an.“", el_GR="\"Γεια σου Audi, κάλεσε τον Κώστα.\"", en_GB="\"Hey Audi, call Max.\"", es_ES="\"Hey, Audi, llama a María.\"", fi_FI="\"Hei Audi, soita kontaktille Matti.\"", fr_FR="«Hey Audi, appelle Pierre.»", hu_HU="„Hey Audi, hívd fel Maxot.“", it_IT="\"Ehi Audi, chiama Max.\"", nl_NL="\"Hey Audi, bel Max.\"", no_NO="«Hey Audi, ring Jan.»", pl_PL="„Hey Audi, zadzwoń do Maksa”.", pt_PT="\"Olá Audi, liga ao Max.\"", ru_RU="«Привет Audi, позвони Максу».", sv_SE="”Hej Audi, ring till Erik.”", tr_TR="\"Hey Audi, Ali'yi ara.\"")
assist_settings_help_phone_item_call_desc = TextObject(cs_CZ="Zobrazí se seznam možných telefonních kontaktů", da_DK="En liste med mulige telefonkontakter vises.", de_DE="Eine Liste möglicher Telefonkontakte wird angezeigt.", el_GR="Θα εμφανιστεί μια λίστα πιθανών επαφών τηλεφώνου", en_GB="A list of possible telephone contacts will be shown", es_ES="Se muestra una lista de posibles contactos del teléfono", fi_FI="Lista mahdollisista puhelinkontakteista tulee näkyviin", fr_FR="Affichage d'une liste de contacts donnée du téléphone", hu_HU="Megjelenik a lehetséges telefonkapcsolatok listája", it_IT="Viene visualizzato un elenco dei possibili contatti del telefono", nl_NL="Een lijst van mogelijke telefooncontacten wordt weergegeven", no_NO="Det vises en liste over mulige telefonkontakter", pl_PL="Zostaje wyświetlona lista możliwych kontaktów telefonicznych", pt_PT="A apresentar uma lista de possíveis contactos telefónicos", ru_RU="Отображается список возможных телефонных контактов", sv_SE="En lista över möjliga telefonkontakter visas", tr_TR="Olası telefon kişilerinin bir listesi görüntülenir")
assist_settings_help_phone_item_call_list = TextObject(cs_CZ="\"Ukaž mi můj seznam volání.\"", da_DK="\"Vis mig min opkaldsliste.\"", de_DE="„Zeige mir meine Anrufliste.“", el_GR="\"Δείξε μου τη λίστα κλήσεών μου.\"", en_GB="\"Show me my call list.\"", es_ES="\"Muéstrame mi lista de llamadas.\"", fi_FI="\"Näytä puhelulistani.\"", fr_FR="«Affiche-moi ma liste d'appels.»", hu_HU="„Mutasd meg a híváslistámat.”", it_IT="\"Mostrami la mia lista delle chiamate.\"", nl_NL="\"Laat me mijn oproepenlijst zien.\"", no_NO="«Vis meg anropslisten.»", pl_PL="„Pokaż mi listę moich połączeń”.", pt_PT="\"Mostra-me a minha lista de chamadas.\"", ru_RU="«Покажи мне мой список вызовов».", sv_SE="”Visa mig min samtalslista.”", tr_TR="\"Bana çağrı listemi göster.\"")
assist_settings_help_phone_item_call_list_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, ukaž mi můj seznam\nvolání.\"", da_DK="\"Hey Audi, vis mig min\nopkaldsliste.\"", de_DE="„Hey Audi, zeige mir meine\nAnrufliste.“", el_GR="\"Γεια σου Audi, δείξε μου τη λίστα\nκλήσεών μου.\"", en_GB="\"Hey Audi, show me my call list.\"", es_ES="\"Hey, Audi, muéstrame mi lista de\nllamadas.\"", fi_FI="\"Hei Audi, näytä puhelulistani.\"", fr_FR="«Hey Audi, affiche-moi ma liste\nd'appels.»", hu_HU="„Hey Audi, mutasd meg a\nhíváslistámat.”", it_IT="\"Ehi Audi, mostrami la mia lista\ndelle chiamate.\"", nl_NL="\"Hey Audi, laat me mijn\noproepenlijst zien.\"", no_NO="«Hey Audi, vis meg anropslisten.»", pl_PL="„Hey Audi, pokaż mi listę moich\npołączeń”.", pt_PT="\"Olá Audi, mostra-me a minha\nlista de chamadas.\"", ru_RU="«Привет Audi, покажи мне мой\nсписок вызовов».", sv_SE="”Hej Audi, visa mig min\nsamtalslista.”", tr_TR="\"Hey Audi, bana çağrı listemi\ngöster.\"")
assist_settings_help_phone_item_call_list_desc = TextObject(cs_CZ="Zobrazí se seznam volání připojeného zařízení", da_DK="Opkaldslisten på forbundet apparat vises.", de_DE="Die Anrufliste des verbundenen Geräts wird angezeigt.", el_GR="Θα εμφανιστεί η λίστα κλήσεων της συνδεδεμένης συσκευής", en_GB="The connected device's call list will be shown", es_ES="Se muestra la lista de llamadas del dispositivo conectado", fi_FI="Yhdistetyn laitteen puhelulista tulee näkyviin", fr_FR="Affichage de la liste d'appels du périphérique connecté", hu_HU="A csatlakoztatott készülék híváslistája megjelenik", it_IT="Viene visualizzata la lista delle chiamate del dispositivo collegato", nl_NL="De oproepenlijst van het verbonden apparaat wordt weergegeven", no_NO="Anropslisten på enheten som har forbindelse, vises", pl_PL="Zostaje wyświetlona lista połączeń podłączonego urządzenia", pt_PT="A lista de chamadas do aparelho ligado será apresentada", ru_RU="Отображается список вызовов подключенного устройства", sv_SE="Samtalslistan för den anslutna enheten visas", tr_TR="Bağlı cihazın çağrı listesi gösterilir")
assist_settings_help_phone_item_connect = TextObject(cs_CZ="\"Chci připojit svůj telefon.\"", da_DK="\"Jeg vil forbinde min telefon.\"", de_DE="„Ich will mein Telefon verbinden.“", el_GR="\"Θέλω να συνδέσω το τηλέφωνό μου.\"", en_GB="\"I'd like to connect my phone.\"", es_ES="\"Quiero conectar mi teléfono.\"", fi_FI="\"Haluan yhdistää puhelimeni.\"", fr_FR="«Je veux connecter mon téléphone.»", hu_HU="„Csatlakoztatni szeretném a telefonom.”", it_IT="\"Voglio collegare il mio telefono.\"", nl_NL="\"Ik wil mijn telefoon verbinden.\"", no_NO="«Jeg vil opprette forbindelse med telefonen.»", pl_PL="„Chcę podłączyć mój telefon”.", pt_PT="\"Quero ligar o meu telefone.\"", ru_RU="«Я хочу подключить свой телефон».", sv_SE="”Jag vill ansluta min telefon.”", tr_TR="\"Telefonumu bağlamak istiyorum.\"")
assist_settings_help_phone_item_connect_aiscreen = TextObject(cs_CZ="\"Ahoj Audi, chci připojit svůj\ntelefon.\"", da_DK="\"Hey Audi, jeg vil forbinde min\ntelefon.\"", de_DE="„Hey Audi, ich will mein Telefon\nverbinden.“", el_GR="\"Γεια σου Audi, θέλω να συνδέσω\nτο τηλέφωνό μου.\"", en_GB="\"Hey Audi, I'd like to connect my\nphone.\"", es_ES="\"Hey, Audi, quiero conectar mi\nteléfono.\"", fi_FI="\"Hei Audi, haluan yhdistää\npuhelimeni.\"", fr_FR="«Hey Audi, je veux connecter mon\ntéléphone.»", hu_HU="„Hey Audi, csatlakoztatni\nszeretném a telefonom.”", it_IT="\"Ehi Audi, voglio collegare il mio\ntelefono.\"", nl_NL="\"Hey Audi, ik wil mijn telefoon\nverbinden.\"", no_NO="«Hey Audi, jeg vil opprette\nforbindelse med telefonen.»", pl_PL="„Hey Audi, chcę podłączyć mój\ntelefon”.", pt_PT="\"Olá Audi, quero ligar o meu\ntelefone.\"", ru_RU="«Привет Audi, я хочу подключить\nсвой телефон».", sv_SE="”Hej Audi, jag vill ansluta min\ntelefon.”", tr_TR="\"Hey Audi, telefonumu bağlamak\nistiyorum.\"")
assist_settings_help_phone_item_connect_desc = TextObject(cs_CZ="Asistent vybavení se spouští", da_DK="Indstillingsassistent startes.", de_DE="Der Einrichtungsassistent wird gestartet.", el_GR="Θα εκκινηθεί το σύστημα υποβοήθησης διαμόρφωσης", en_GB="Starting setup wizard", es_ES="Iniciando el asistente de configuración", fi_FI="Ohjattu asennustoiminto (käyttöönottoavustin) käynnistyy", fr_FR="Lancement de l'assistant de configuration", hu_HU="A beállításasszisztens elindul", it_IT="Si avvia l'assistenza configurazione", nl_NL="De inrichtingsassistent wordt gestart", no_NO="Oppsettsassistenten starter", pl_PL="Zostaje uruchomiony asystent konfigurowania", pt_PT="A iniciar o assistente de configuração", ru_RU="Запускается ассистент настройки", sv_SE="Inställningsassistenten startas", tr_TR="Kurulum sihirbazı başlatılır")
