assist_settings_help_plug_and_play_horoscope = TextObject(cs_CZ="\"Narodil jsem se 22. ledna. V jakém jsem znamení?\"", da_DK="\"Jeg er født den 22. januar. Hvilket stjernetegn er jeg?\"", de_DE="„Ich bin am 22. Januar geboren. Welches Sternzeichen bin ich?“", el_GR="\"Γεννήθηκα στις 22 Ιανουαρίου. Τι ζώδιο είμαι;\"", en_GB="\"I was born on 22nd January. What is my star sign?\"", es_ES="\"Nací el 22 de enero. ¿Cuál es mi signo del zodiaco?\"", fi_FI="\"Olen syntynyt 22. tammikuuta. Mikä olen horoskoopiltani?\"", fr_FR="«Je suis né le 23 janvier. Quel est mon signe astrologique?»", hu_HU="\"Január 22-én születtem. Milyen csillagjegy vagyok?\"", it_IT="\"Sono nata il 22 gennaio. Di che segno sono?\"", nl_NL="\"Ik ben op 22 januari geboren. Welk sterrenbeeld ben ik?\"", no_NO="«Jeg er født den 22. januar. Hvilket stjernetegn er jeg?»", pl_PL="„Mam urodziny 22 stycznia. Jaki jest mój znak zodiaku?”", pt_PT="Nasci a 22 de janeiro. Qual é o meu signo do zodíaco?\"", ru_RU="«Я родился 22 января. Кто я по знаку зодиака?»", sv_SE="”Jag är född den 22 januari. Vilket stjärntecken är jag?”", tr_TR="\"22 Ocak'ta doğdum. Ben hangi burcum?\"")
