assist_settings_speech_update_available = TextObject(cs_CZ="Update hlasových dat nedostupný", da_DK="Opdatering til talte data tilgængelig", de_DE="Sprachdatenupdate verfügbar", el_GR="Αναβάθμιση δεδομένων ομιλίας διαθέσιμη", en_GB="Speech data update available", es_ES="Actualización de datos de voz disponible", fi_FI="Puhetietojen päivitys käytettävissä", fr_FR="Mise à jour des données linguistiques disponible", hu_HU="Beszédadatok frissítése elérhető", it_IT="Update dati vocali disponibile", nl_NL="Update spraakgegevens beschikbaar", no_NO="Oppdatering av stemmedata tilgjengelig", pl_PL="Dostępna aktualizacja danych językowych", pt_PT="Atualização dos dados de voz disponível", ru_RU="Доступно обновление голосовых данных", sv_SE="Språkdatauppdatering tillgänglig", tr_TR="Ses verileri güncellemesi mevcut")
assist_settings_speech_update_available_desc = TextObject(cs_CZ="Nyní lze stáhnout hlasová data.", da_DK="Talte data kan downloades nu.", de_DE="Sprachdaten können jetzt heruntergeladen werden.", el_GR="Η λήψη (download) των δεδομένων ομιλίας είναι τώρα εφικτή.", en_GB="Speech data can now be downloaded.", es_ES="Los datos de voz se pueden descargar ahora.", fi_FI="Puhetiedot voidaan nyt ladata.", fr_FR="Des données linguistiques peuvent maintenant être téléchargées.", hu_HU="A hangadatok mostantól letölthetők.", it_IT="Adesso è possibile scaricare i dati vocali.", nl_NL="Spraakgegevens kunnen nu worden gedownload.", no_NO="Du kan nå laste ned stemmedata.", pl_PL="Można pobrać dane językowe teraz.", pt_PT="Os dados de voz podem agora ser descarregados.", ru_RU="Голосовые данные теперь можно загрузить.", sv_SE="Du kan nu ladda ned språkdata.", tr_TR="Ses verileri şimdi indirilebilir.")
