assistant_routine_exec_unlock = TextObject(cs_CZ="Audi assistant provedl rutinu odemčení dveří: Dveře se odemknou.", da_DK="Audi assistant har udført rutinen oplåsning af døre: Døre låses op.", de_DE="Der Audi assistant hat die Routine Türen entriegeln ausgeführt: Türen werden\nentriegelt.", el_GR="Η Audi assistant εκτέλεσε τη ρουτίνα Ξεκλείδωμα πορτών: Οι πόρτες θα\nξεκλειδωθούν.", en_GB="The Audi assistant has performed the routine to unlock the doors: The doors\nwill be unlocked.", es_ES="El Audi assistant ha ejecutado la rutina que desbloquea las puertas: Las\npuertas se desbloquearán.", fi_FI="Audi assistant on suorittanut Ovilukkojen avaaminen -rutiinin: ovien lukot\navataan.", fr_FR="L'Audi assistant a exécuté la routine du déverrouillage des portes:\ndéverrouillage des portes.", hu_HU="Az Audi assistant végrehajtotta az ajtók nyitása rutint: megtörténik az ajtók\nnyitása.", it_IT="L'Audi assistant ha eseguito la routine di sbloccaggio delle porte: le porte\nverranno sbloccate.", nl_NL="De Audi assistant heeft de routine portieren ontgrendelen uitgevoerd:\nPortieren worden ontgrendeld.", no_NO="Audi assistant har utført rutinen opplåsing av dører: Låser opp dørene.", pl_PL="Audi assistant wykonał rutynę odblokowania drzwi: drzwi zostały\nodblokowane.", pt_PT="O Audi assistant executou a rotina destrancar portas. Função destrancar portas\nserá ativada.", ru_RU="Audi assistant выполнил стандартное действие отпереть двери: двери\nотпираются.", sv_SE="Audi assistant har utfört rutinen Låsa upp dörrar: Dörrarna låses  upp.", tr_TR="Audi assistant kapı kilitlerini açma rutinini uyguladı: Kapı kilitleri açılıyor.")
assistant_routine_int_ex_calm = TextObject(cs_CZ="Rutina Svět zážitků: Chcete, abych v budoucnu automaticky aktivoval režim\n„Relaxace“?", da_DK="Rutinen oplevelsesunivers: Vil du gerne have, at jeg fremover aktiverer\nindstillingen \"Afslappende\" automatisk?", de_DE="Routine Erlebniswelt: Möchtest du, dass ich zukünftig den Modus\n\"Entspannend\" automatisch aktiviere?", el_GR="Ρουτίνα Κόσμος εμπειριών: Θέλετε μελλοντικά να ενεργοποιώ αυτομάτως τη\n«Χαλαρωτική» λειτουργία;", en_GB="Experiences routine: Would you like me to activate \"Relaxing\" mode\nautomatically in future?", es_ES="Rutina de la aplicación Experiencias:\n¿Desea que, en adelante, active automáticamente el modo \"Relajante\"?", fi_FI="Kokemusmaailma-rutiini: Haluatko, että aktivoin \"Rentouttava\"-tilan jatkossa\nautomaattisesti?", fr_FR="Routine des univers d'expériences:\nsouhaitez-vous qu'à l'avenir j'active automatiquement le mode «Relaxant»?", hu_HU="Élményvilág rutin: szeretnéd, hogy a jövőben automatikusan aktiváljam a\n„Relaxáló” rutint?", it_IT="Routine Esperienze: desidera che d'ora in poi io attivi automaticamente la\nmodalità \"Rilassante\"?", nl_NL="Routine Belevingswereld: Wil je dat ik voortaan de modus\n\"Ontspanning\" automatisch activeer?", no_NO="Rutinen Opplevelser: Vil du at modusen Avslappende heretter skal aktiveres\nautomatisk?", pl_PL="Rutyna świata doznań: czy chcesz w przyszłości automatycznie aktywować tryb\n„Odprężenie”?", pt_PT="Rotina universo de experiências: Queres que daqui em diante eu ative\nautomaticamente o modo \"Relaxante\"?", ru_RU="Стандартное действие персонализации: хотите, чтобы я в будущем\nавтоматически активировала режим «Расслабляющий»?", sv_SE="Rutinen Upplevelser: Vill du att jag i framtiden\naktiverar läget ”Avslappnande” automatiskt?", tr_TR="Macera dünyası rutini: Gelecekte \"Rahatlama\" modunu otomatik olarak\netkinleştirmemi ister misin?")
