assistant_routine_int_ex_flow = TextObject(cs_CZ="Rutina svět „Zážitků“: Chcete, abych v budoucnu automaticky aktivoval režim\n„Vyvážení“?", da_DK="Rutinen oplevelsesunivers: Vil du gerne have, at jeg fremover aktiverer\nindstillingen \"Flydende\" automatisk?", de_DE="Routine Erlebniswelt: Möchtest du, dass ich zukünftig den Modus\n\"Ausgleichend\" automatisch aktiviere?", el_GR="Ρουτίνα Κόσμος εμπειριών: Θέλετε μελλοντικά να ενεργοποιώ αυτομάτως την\n«Εξισορροπητική» λειτουργία;", en_GB="Experiences routine: Would you like me to activate \"Harmonising\" mode\nautomatically in future?", es_ES="Rutina de la aplicación Experiencias: ¿Desea que, en adelante, active\nautomáticamente el modo \"Equilibrado\"?", fi_FI="Kokemusmaailma-rutiini: Haluatko, että aktivoin \"Tasapainottava\"-tilan\njatkossa automaattisesti?", fr_FR="Routine des univers d'expériences:\nsouhaitez-vous qu'à l'avenir j'active automatiquement le mode «Équilibrant»?", hu_HU="Élményvilág rutin: szeretnéd, hogy a jövőben automatikusan aktiváljam a\n„Kiegyensúlyozott” rutint?", it_IT="Routine Esperienze: desidera che d'ora in poi io attivi automaticamente la\nmodalità \"Equilibrio\"?", nl_NL="Routine Belevingswereld: Wil je dat ik voortaan de modus \"Balans\"\nautomatisch activeer?", no_NO="Rutinen Opplevelser: Vil du at modusen Balansert heretter skal aktiveres\nautomatisk?", pl_PL="Rutyna świata doznań: czy chcesz w przyszłości automatycznie aktywować tryb\n„Równowaga”?", pt_PT="Rotina universo de experiências: Desejas que o modo \"Equilibrante\" seja \nativado automaticamente nas próximas vezes?", ru_RU="Стандартное действие персонализации: хотите, чтобы я в будущем\nавтоматически активировала режим «Сбалансированный»?", sv_SE="Rutinen Upplevelser: Vill du att jag i framtiden aktiverar läget ”Neutral”\nautomatiskt?", tr_TR="Macera dünyası rutini: Gelecekte \"Dengeleyici\" modunu otomatik olarak\netkinleştirmemi ister misin?")
assistant_routine_ipa = TextObject(cs_CZ="Rutina Strategie parkování asistenta parkování: Chcete, abych v budoucnu při\npoužití asistenta parkování na tomto místě převzala naposledy použitou\nstrategii parkování?", da_DK="Rutinen parkeringsassistent parkeringsstrategi: Vil du gerne have, at jeg\nfremover ved anvendelse af parkeringsassistenten på dette sted overtager den\nsenest anvendte parkeringsstrategi her?", de_DE="Routine Parkassistent Parkstrategie: Möchtest du, dass ich zukünftig bei\nVerwendung des Parkassistenten an diesem Ort die hier zuletzt verwendete\nParkstrategie übernehme?", el_GR="Προτιμώμενη τυποποιημένη διαδικασία (συνήθεια) Στρατηγική στάθμευσης:\nΘέλετε μελλοντικά σε αυτή την τοποθεσία, σε περίπτωση χρήσης του\nσυστήματος υποβοήθησης στάθμευσης, να υιοθετώ τη στρατηγική στάθμευσης\nπου χρησιμοποιήθηκε εδώ τελευταία;", en_GB="Park assist parking strategy routine: Would you like me to use this location's\nmost recently used parking strategy when you use the park assist here in\nfuture?", es_ES="Rutina estrategia del aparcamiento asistido: ¿Desea que aplique la última\nestrategia de aparcamiento utilizada aquí siempre que use el asistente de\naparcamiento en este lugar?", fi_FI="Pysäköintiavustimen pysäköintistrategia -rutiini: Haluatko, että otan edellisen\ntäällä käytetyn pysäköintistrategian jatkossa käyttöön tässä paikassa\npysäköintiavustinta käytettäessä?", fr_FR="Routine de la technique de stationnement de l'assistant aux manœuvres de\nstationnement: souhaitez-vous lorsque vous utilisez l'assistant aux\nmanœuvres de stationnement à cet endroit que je reprenne la technique de\nstationnement que vous aviez utilisée ici la dernière fois?", hu_HU="Parkolássegítő parkolási stratégia rutin: Szeretnéd, hogy a jövőben a\nparkolássegítő használatakor ezen a helyen átvegyem az itt legutóbb használt\nparkolási stratégiát?", it_IT="Routine strategia di parcheggio assistenza al parcheggio: desidera che d'ora in\npoi, quando utilizza l'assistenza al parcheggio in questo luogo, io adotti\nl'ultima strategia di parcheggio utilizzata qui?", nl_NL="Routine Parkeerassistent parkeerstrategie: Wil je dat ik in de toekomst bij\ngebruik van de parkeerassistent op deze plaats steeds de hier voor het laatst\ngebruikte parkeerstrategie overneem?", no_NO="Rutinen parkeringsstrategi for parkeringsassistent: Vil du at den sist brukte\nparkeringsstrategien på dette stedet heretter skal velges når du bruker\nparkeringsassistenten her?", pl_PL="Rutyna strategii asystenta parkowania: czy chcesz, aby w przyszłości, przy\nkorzystaniu z asystenta parkowania w tej lokalizacji, zawsze zastosować\nostatnio użytą w tym miejscu strategię parkowania?", pt_PT="Rotina estratégia de estacionamento do assistente de estacionamento: Queres\nque futuramente, ao utilizar o assistente de estacionamento neste local seja\nassumida a última manobra de estacionamento utilizada?", ru_RU="Стандартное действие: стратегия парковки парковочного ассистента Хотите,\nчтобы при использовании системы автоматической парковки я применяла\nпоследнюю использованную здесь стратегию парковки в этом месте в\nбудущем?", sv_SE="Rutinen Parkeringsassistans Parkeringsstrategi: Vill du att jag i framtiden när\nparkeringsassistansen används på den här platsen laddar den\nparkeringsstrategi som senast användes här?", tr_TR="Park asistanı park etme stratejisi rutini: Gelecekte bu konumda park asistanını\nkullanırken burada en son kullanılan park etme stratejisini devralmamı ister\nmisin?")
