assistant_toast_download_data_failed = TextObject(cs_CZ="Stahování přerušeno. Hlasová data nelze stáhnout.", da_DK="Downloading afbrudt. Talte data kunne ikke downloades.", de_DE="Herunterladen abgebrochen. Die Sprachdaten\nkonnten nicht heruntergeladen werden.", el_GR="Η λήψη (download) διακόπηκε. Δεν ήταν εφικτή η λήψη\n(download) των δεδομένων ομιλίας.", en_GB="Download cancelled. The speech data could not be downloaded.", es_ES="Descarga cancelada. Los datos de voz no se han podido\ndescargar.", fi_FI="Lataaminen keskeytetty. Puhetietoja ei voitu ladata.", fr_FR="Téléchargement annulé. Les données linguistiques n'ont pas pu\nêtre téléchargées.", hu_HU="A letöltés megszakadt. A beszédadatokat nem sikerült letölteni.", it_IT="Download interrotto. Non è stato possibile scaricare i dati vocali.", nl_NL="Downloaden afgebroken. De taalgegevens kunnen niet worden\ngedownload.", no_NO="Nedlasting avbrutt. Kan ikke laste ned stemmedata.", pl_PL="Pobieranie anulowane. Nie można pobrać danych języka.", pt_PT="Download interrompido. Os dados de voz não podem ser\ndescarregados.", ru_RU="Загрузка прервана. Не удалось загрузить голосовые данные.", sv_SE="Nedladdning avbruten. Språkdatan kunde inte laddas ned.", tr_TR="İndirme iptal edildi. Ses verileri indirilemedi.")
assistant_toast_download_data_started = TextObject(cs_CZ="Bylo zahájeno stahování dat.", da_DK="Downloading af talte data blev startet.", de_DE="Herunterladen der Sprachdaten gestartet", el_GR="Ξεκίνησε η λήψη των δεδομένων ομιλίας.", en_GB="The speech data download has been started.", es_ES="La descarga de los datos de voz se ha iniciado.", fi_FI="Puhetietojen lataaminen on aloitettu.", fr_FR="Téléchargem. des données linguistiques lancé", hu_HU="A beszédadatok letöltése elindult.", it_IT="È stato avviato il download dei dati vocali.", nl_NL="Downloaden van de taalgegevens gestart", no_NO="Nedlasting av stemmedata er startet.", pl_PL="Pobieranie danych języka uruchomione", pt_PT="O download dos dados de voz foi iniciado.", ru_RU="Началась загрузка голосовых данных.", sv_SE="Nedladdningen av språkdata har påbörjats.", tr_TR="Ses verilerinin indirilmesi başlatıldı.")
assistant_toast_installation_data_failed = TextObject(cs_CZ="Instalace se nezdařila. Hlasová data nelze aktualizovat.", da_DK="Installation ikke gennemført korrekt. Talte data kunne ikke\nopdateres.", de_DE="Installation nicht erfolgreich. Die Sprachdaten konnten nicht\naktualisiert werden.", el_GR="Η εγκατάσταση δεν ήταν επιτυχής. Δεν ήταν εφικτή η ενημέρωση\nτων δεδομένων ομιλίας.", en_GB="Installation not successful. The speech data could not be\nupdated.", es_ES="Instalación incorrecta. Los datos de voz no se han\npodido actualizar.", fi_FI="Asennus epäonnistui. Puhetietoja ei voitu päivittää.", fr_FR="L'installation a échoué. Les données linguistiques n'ont pas pu\nêtre actualisées.", hu_HU="Sikertelen telepítés. A beszédadatokat nem sikerült frissíteni.", it_IT="Installazione non riuscita. Non è stato possibile aggiornare\ni dati vocali.", nl_NL="Installatie niet succesvol. De taalgegevens konden niet worden\ngeactualiseerd.", no_NO="Installeringen mislyktes. Kan ikke oppdatere stemmedata.", pl_PL="Instalowanie nie powiodło się. Nie można zaktualizować\ndanych języka.", pt_PT="Instalação falhou. Não é possível atualizar os dados de voz.", ru_RU="Установка не удалась. Голосовые данные не удалось обновить.", sv_SE="Installationen misslyckades. Språkdatan kunde inte uppdateras.", tr_TR="Yükleme başarısız. Ses verileri güncellenemedi.")
assistant_toast_installation_data_started = TextObject(cs_CZ="Byla zahájena instalace hlasových dat.", da_DK="Installation af talte data blev startet.", de_DE="Installation der Sprachdaten wurde gestartet", el_GR="Ξεκίνησε η εγκατάστ. των δεδομένων ομιλίας.", en_GB="The speech data installation has been started.", es_ES="Iniciada la instalación de los datos de voz", fi_FI="Puhetietojen asennus on aloitettu.", fr_FR="Installat. des données linguistiques démarrée", hu_HU="A beszédadatok frissítése elindult.", it_IT="È stata avviata l'installazione dei dati vocali.", nl_NL="Installatie van de taalgegevens is gestart", no_NO="Installering av stemmedata er startet.", pl_PL="Instalowanie danych języka uruchomione", pt_PT="A instalação dos dados de voz foi iniciada.", ru_RU="Началась установка голосовых данных.", sv_SE="Installationen av språkdata har påbörjats.", tr_TR="Ses verilerinin yüklenmesi başlatıldı.")
assistant_toast_language_needs_update_but_no_internet = TextObject(cs_CZ="Audi assistant je ve zvoleném jazyce deaktivován. Jazyková data\nmohou být k dispozici ke stažení.", da_DK="Audi assistant er deaktiveret på det indstillede sprog.\nDer er muligvis talte data klar til downloading.", de_DE="Der Audi assistant ist in dieser Sprache deaktiviert. Ggf.\nSprachdaten herunterladen.", el_GR="Audi assistant απενεργοποιημένη σε αυτήν τη γλώσσα. Ενδεχ.να\nυπάρχ.διαθέσιμα φωνητικά δεδομένα προς λήψη (download).", en_GB="The Audi assistant is deactivated in the selected language.\nSpeech data may be available to download.", es_ES="El Audi assistant está desactivado en el idioma ajustado.\nDescargar datos de voz listos.", fi_FI="Audi assistant on deaktivoitu asetetulla\nkielellä. Lataa tarvittaessa puhetiedot.", fr_FR="L'Audi assistant est désactivé dans la langue réglée. Des données\nlinguistiques sont probablement prêtes à être téléchargées.", hu_HU="Az Audi assistant a beállított nyelven ki van kapcsolva.\nLetölthető hangadatok állhatnak rendelkezésre.", it_IT="Audi assistant disattivato in questa lingua. Eventuali dati vocali\nscaricabili.", nl_NL="De Audi assistant is in deze taal gedeactiveerd. Zo nodig\ntaalgegevens downloaden.", no_NO="Audi assistant er deaktivert for dette språket. Last ev. ned\nstemmedata.", pl_PL="Audi assistant jest wyłączony w tym języku.\nMogą być dostępne dane języka do pobrania.", pt_PT="O Audi assistant está desativado no idioma selecionado.\nPodem existir dados de voz disponíveis para descarregar.", ru_RU="Audi assistant отключается на установленном языке. Для\nзагрузки могут быть доступны голосовые данные.", sv_SE="Audi assistant är avaktiverad på det inställda\nspråket. Ladda ev. ner språkdata.", tr_TR="Audi assistant bu dilde devre dışı bırakıldı. Gerekirse dil verilerini\nindiririn.")
