notification_ota_update_header = TextObject(cs_CZ="Aktualizace hlasových dat", da_DK="Opdatering af talte data", de_DE="Aktualisierung der Sprachdaten", el_GR="Ενημέρωση των δεδομένων ομιλίας", en_GB="Speech data update", es_ES="Actualizar datos de voz", fi_FI="Puhetietojen päivitys", fr_FR="Actualisation des données linguistiques", hu_HU="Beszédadatok frissítése", it_IT="Aggiornamento dei dati vocali", nl_NL="Actualisering van taalgegevens", no_NO="Oppdatering av stemmedata", pl_PL="Aktualizacja danych językowych", pt_PT="Atualização dos dados de voz", ru_RU="Обновление голосовых данных", sv_SE="Uppdatering av språkdata", tr_TR="Ses verilerinin güncellenmesi")
notification_ota_update_progress_download = TextObject(cs_CZ="Hlasová data se stahují", da_DK="Talte data downloades.", de_DE="Sprachdaten werden heruntergeladen", el_GR="Γίνεται λήψη (download) δεδομένων ομιλίας", en_GB="Downloading speech data", es_ES="Descargando datos de voz", fi_FI="Puhetietoja ladataan", fr_FR="Téléchargement des données linguistiques en cours...", hu_HU="Beszédadatok letöltése", it_IT="I dati vocali vengono scaricati", nl_NL="Taalgegevens worden gedownload", no_NO="Laster ned stemmedata", pl_PL="Trwa wczytywanie danych językowych", pt_PT="A descarregar dados de voz", ru_RU="Загружаются голосовые данные", sv_SE="Språkdata laddas ned", tr_TR="Ses verileri indiriliyor")
notification_ota_update_progress_installation = TextObject(cs_CZ="Hlasová data se instalují", da_DK="Talte data installeres.", de_DE="Sprachdaten werden installiert", el_GR="Θα εγκατασταθούν τα δεδομένα ομιλίας", en_GB="Installing speech data", es_ES="Instalando datos de voz", fi_FI="Puhetietoja asennetaan", fr_FR="Installation des données linguistiques en cours...", hu_HU="Beszédadatok telepítése", it_IT="I dati vocali vengono installati", nl_NL="Taalgegevens worden geïnstalleerd", no_NO="Installerer stemmedata", pl_PL="Trwa instalowanie danych językowych", pt_PT="A instalar dados de voz", ru_RU="Голосовые данные установлены", sv_SE="Språkdata installeras", tr_TR="Ses verileri yükleniyor")
notification_outdated_language_nonprimary_user_text = TextObject(bs_BA="Audi assistant nije raspoloživ na odabranom jeziku. Prijavite se kao glavni\nkorisnik i uspostavite podatkovnu vezu.", cs_CZ="Audi assistant není ve zvoleném jazyce dostupný. Mohou existovat jazyková\ndata ke stažení. Přihlaste se jako hlavní uživatel a vytvořte datové spojení.", da_DK="Audi assistant ikke til rådighed på valgt sprog. Log på som primær\nbruger/opret dataforbindelse for at downloade mulige talte data.", de_DE="Audi assistant in der gewählten Sprache nicht verfügbar. Als Hauptnutzer an-\nmelden/Datenverbindung herstellen um mögl. Sprachdaten herunterzuladen", el_GR="Η Audi assistant δεν είναι διαθ. στην επιλεγμ. γλώσσα. Συνδ. (log in) ως βασικ.\nχρήστ. και δημιουρ. μια σύνδ.δεδομέν.για να κατεβάσ. ενδεχ. δεδομ. ομιλίας.", en_GB="Audi assistant is not available in the selected language. Log in as the key user\nand establish a data connection to download any available speech data", es_ES="Audi assistant no disponible en idioma seleccionado. Inicie sesión como\nusuario principal y conéctese para descargar datos de voz disponibles.", fi_FI="Audi assistant ei käytettäv. valitulla kielellä. Kirjaudu sisään pääkäyttäjänä /\nmuodosta datayhteys mahdollisten puhetietojen lataamista varten.", fr_FR="Audi assistant indispo ds langue sélect. Se connecter comme utilisat. princip.\net établir connex. de donn. pr télécharger les éventuelles donn. linguistiques", hr_HR="Audi assistant nije raspoloživ na odabranom jeziku. Možda su raspoloživi\njezični podaci. Prijavite se kao glavni korisnik i uspostavite podatkovnu vezu.", hu_HU="Az Audi assistant nem érhető el a kiválaszt. nyelven. Jelentkezz be főfelhasz-\nnálóként, ill. hozz létre adatkapcs.ot az esetleges beszédadatok letöltéséhez", it_IT="Audi assistant non disponibile nella lingua selez. Fare il login come utente\nprincipale e stabilire un collegamento dati per scaricare eventuali dati vocali", nl_NL="De Audi assistant is niet beschikbaar in deze taal. Er staan taalgegevens voor\nje klaar. Meld je aan als hoofdgebruiker en breng een verbinding tot stand.", no_NO="Audi assistant er ikke tilgjengelig på valgt språk. Logg på som hovedbruker\nog opprett dataforbindelse for å laste ned tilgjengelige språkdata.", pl_PL="Audi assistant niedostępny w wybranym języku. Zaloguj się jako główny\nużytkownik/nawiąż połączenie danych, ab y pobrać możliwe dane językowe", pt_PT="Audi assistant indisp. no idioma selecionado. Iniciar sessão como util. princ. e\nestabelecer ligação de dados para descarregar eventuais dados de voz", ro_RO="Audi assistant indisp. în limba selectată. Autentificaţi-vă ca utilizator\nprincipal şi realizaţi o conex. de date pentru a descărca date lingvistice disp.", ru_RU="Audi assistant недост. на выбр. языке. Войдите в систему как осн.\nпольз./установ. соед. для передачи данных для возм. загр. голос. данных", sk_SK="Audi assistant nie je dostupný vo zvolenom jazyku. Jazykové údaje môžu byť k\ndisp. na stiahnutie. Prihláste sa ako hlavný použ. a vytvorte dát. pripoj.", sl_SI="Audi assistant v izbranem jeziku ni na voljo. Za prenos morebitnih govorjenih\npodatkov se prijavite kot glavni uporabnik/vzpostavite podatkovno povezavo.", sr_RS="Audi assistant nije dostupan na izabranom jeziku. Prijavite se kao glavni\nkorisnik i uspostavite vezu za prenos podataka.", sv_SE="Audi assistant är inte tillgänglig på det valda språket. Logga in som\nhuvudanvändare/upprätta dataanslutning för att ladda ned ev. röstdata", tr_TR="Audi assistant seçilen dilde mevcut değil. Olası dil verilerini indirmek için, ana\nkullanıcı olarak giriş yap/ veri bağlantısı oluştur", uk_UA="Audi assistant недост. вибраною мовою. Для завантаж. можл. мовних\nданих увійдіть як осн. користувач/встановіть з'єдн. для передачі даних")
notification_outdated_language_primary_user_text = TextObject(bs_BA="Audi assistant nije raspoloživ na odabranom jeziku. Možda postoje\nraspoloživi jezički podaci za preuzimanje. Neophodna podatkovna veza.", cs_CZ="Audi assistant není ve zvoleném jazyce dostupný. Mohou existovat jazyková\ndata ke stažení. K tomu potřebujete datové spojení.", da_DK="Audi assistant er ikke til rådighed på det valgte sprog. Der er muligvis talte\ndata klar til downloading. I den forbindelse er en dataforbindelse nødvendig.", de_DE="Audi assistant ist in der gewählten Sprache nicht verfügbar. Es stehen ggf.\nSprachdaten zum Herunterladen bereit. Eine Datenverbindung ist notwendig", el_GR="Η Audi assistant δεν είναι διαθέσ. στην επιλεγμ. γλώσσα. Ενδέχ. να υπάρχουν\nδιαθέσ. δεδομ. ομιλίας προς λήψη. Για αυτό απαιτ. σύνδεση δεδομένων.", en_GB="The Audi assistant is not available in the selected language. Speech data may\nbe available to download. A data connection is required to do this.", es_ES="Audi assistant no disponible en el idioma seleccionado. Puede que haya datos\nde voz listos para descargar. Necesita una conexión de datos.", fi_FI="Audi assistant ei ole käytettävissä valitulla kielellä. Puhetietoja saattaa olla\nvalmiina latausta varten. Sitä varten tarvitaan datayhteys.", fr_FR="Audi assistant indispo ds langue sélectionn. Des données linguistiques sont\nprobablement prêtes à être téléchargées. Connexion de données requise", hr_HR="Audi assistant nije raspoloživ na odabranom jeziku. Jezični su podaci možda\nraspoloživi za preuzimanje. Za to je potrebna veza za prijenos podataka.", hu_HU="Az Audi assistant nem érhető el a kiválasztott nyelven. Rendelkezésre\nállhatnak letölthető beszédadatok. Ehhez adatkapcsolat szükséges.", it_IT="L'Audi assistant non è disponibile nella lingua selezionata. È possibile che\nsiano disponibili dati vocali da scaricare. È necessario un collegamento dati.", nl_NL="De Audi assistant is niet beschikbaar in deze taal. Er staan taalgegevens klaar\nom te worden gedownload. Hiervoor is een dataverbinding vereist.", no_NO="Audi assistant er ikke tilgjengelig på valgt språk. Nye språkdata kan være\ntilgjengelige for nedlasting. Dette krever en dataforbindelse.", pl_PL="Audi assistant nie jest dostępny w wybranym języku. Mogą istnieć dane\njęzykowe gotowe do pobrania. Wymagane jest do tego połączenie danych.", pt_PT="O Audi assistant indisp. no idioma selecionado. É possível que existam dados\nde voz disponíveis para serem descarreg. É necessária ligação de dados", ro_RO="Audi assistant nu este disponibil în limba selectat. Este posibil să existe date\nlingvistice disponibile pentru descărcat. Conexiune de date necesară.", ru_RU="Audi assistant недост. на выбр. языке. Голос. данные могут быть доступны\nдля загрузки. Необх. подключ. для перед. данных", sk_SK="Audi assistant nie je dostupný vo zvolenom jazyku. Jazykové údaje môžu byť k\ndispozícii na stiahnutie. Na to je potrebné dátové pripojenie.", sl_SI="Audi assistant v izbranem jeziku ni na voljo. Govorjeni podatki so morda na\nvoljo za prenos. Za to potrebujete podatkovno povezavo.", sr_RS="Audi assistant nije dostupan na izabranom jeziku. Mogući su jezički podaci\nspremni za preuzimanje. Za to je neophodna veza za prenos podataka.", sv_SE="Audi assistant är inte tillgänglig på det valda språket. Det finns eventuellt\nröstdata redo att ladda ned. För detta krävs en dataanslutning.", tr_TR="Audi assistant seçilen dilde mevcut değildir. İndirilmek üzere dil verileri\nmevcut olabilir. Bunun için bir veri bağlantısı gereklidir.", uk_UA="Audi assistant недоступний вибраною мовою. Мовні дані доступні для\nзавантаження. Потрібне з'єднання для передачі даних")
notification_permission_revoked_option_settings = TextObject(bs_BA="Na postavke", cs_CZ="K nastavení", da_DK="Til indstillinger", de_DE="Zu den Einstellungen", el_GR="Μετάβαση στις ρυθμίσεις", en_GB="Go to settings", es_ES="A Ajustes", fi_FI="Asetuksiin", fr_FR="Accéder aux réglages", hr_HR="Na namještanja", hu_HU="A Beállításokhoz", it_IT="Vai alle impostazioni", nl_NL="Naar de instellingen", no_NO="Til innstillingene", pl_PL="Do ustawień", pt_PT="Para os ajustes", ro_RO="Spre setări", ru_RU="К настройкам", sk_SK="K nastaveniam", sl_SI="Na nastavitve", sr_RS="Ka podešavanjima", sv_SE="Till inställningarna", tr_TR="Ayarlara git", uk_UA="До настройок")
notification_permission_revoked_text = TextObject(cs_CZ="Audi assistantovi bylo odebráno oprávnění:\n%1\nAudi assistant byl deaktivován. Udělte prosím znovu oprávnění, abyste mohli opět\nAudi assistanta používat.", da_DK="Autorisation blev inddraget for Audi assistant:\n%1\nAudi assistant blev deaktiveret.\nTildel autorisationen på ny for at kunne anvende Audi assistant igen.", de_DE="Dem Audi assistant wurde die Berechtigung entzogen:\n%1\nDer Audi assistant wurde deaktiviert. Bitte erteile die Berechtigung erneut, um\nden Audi assistant wieder nutzen zu können.", el_GR="Το δικαίωμα αφαιρέθηκε από το:\n%1\nΗ Audi assistant απενεργοποιήθηκε. Χορηγήστε εκ νέου το δικαίωμα, ώστε να\nμπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="Authorisation for the Audi assistant has been revoked:\n%1\nThe Audi assistant has been deactivated. Please assign the authorisation again to\nuse the Audi assistant.", es_ES="Se ha retirado el permiso para el Audi assistant:\n%1\nEl Audi assistant se ha desactivado. Debe conceder el permiso de nuevo para\nvolver a utilizar el Audi assistant.", fi_FI="Audi assistantilta on peruutettu oikeus:\n%1\nAudi assistant on deaktivoitu.\nMyönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'autorisation suivante a été retirée à l'Audi assistant:\n%1\nL'Audi assistant a été désactivé. Veuillez de nouveau accorder votre autorisation\npour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az engedély az Audi assistant-től visszavonva:\n%1\nAz Audi assistant kikapcsolásra került. Kérünk, add meg újra az engedélyt, hogy\naz Audi assistant ismét használható lehessen.", it_IT="È stata revocata l'autorizzazione dell'Audi assistant:\n%1\nL'Audi assistant è stata disattivata. Concedere nuovamente l'autorizzazione per\npoter utilizzare ancora l'Audi assistant.", nl_NL="Je Audi assistant is van zijn autorisatie ontdaan:\n%1\nDe Audi assistant is gedeactiveerd. Geef de autorisatie opnieuw om de Audi\nassistant weer te kunnen gebruiken.", no_NO="En tilgangsrettighet for Audi assistant er trukket tilbake:\n%1\nAudi assistant er deaktivert.\nGi tilgangsrettigheten på nytt for å fortsette å bruke Audi assistant.", pl_PL="Audi assistant ma odebrane uprawnienie:\n%1\nAudi assistant został dezaktywowany. Aby ponownie korzystać z Audi assistant,\nprzydziel uprawnienie ponownie.", pt_PT="Foi retirada a permissão ao Audi assistant:\n%1\nO Audi assistant foi desativado. Por favor, concede novamente a permissão para\nse poder voltar a utilizar o Audi assistant.", ru_RU="Авторизация Audi assistant была отозвана:\n%1\nAudi assistant был дезактивирован. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har fråntagits behörigheten:\n%1\nAudi assistant har avaktiverats. Tilldela behörigheten på nytt för att kunna\nanvända Audi assistant igen.", tr_TR="Audi assistant'ın yetkisi iptal edildi:\n%1\nAudi assistant devre dışı bırakıldı. Audi assistant'ı tekrar kullanabilmek için,\nlütfen yeniden yetki ver.")
notification_revoked_permission_bluetooth_connect_da_pred_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro návrhy\ndoporučeného volání. Udělte prosím znovu oprávnění, abyste mohli opět Audi\nassistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet forslag fra opkaldsanbefalingen. Tildel autorisationen på ny for at\nkunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für\nVorschläge der Anrufempfehlung notwendig ist. Bitte erteile die Berechtigung\nerneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια προτάσεις της σύστασης κλήσεων. Χορηγήστε εκ νέου το δικαίωμα, ώστε να\nμπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required, for\nexample, for call recommendation suggestions. Please assign the authorisation\nagain to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara sugerir recomendaciones de llamada. Debe conceder el permiso de nuevo\npara volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puhelusuositusten\nehdottamiseen. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour la\nsuggestion d'appel. Veuillez de nouveau accorder votre autorisation pour pouvoir\nà nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközt a hívásajánlás-javaslatokhoz. Kérünk, add meg újra az engedélyt, hogy az\nAudi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per le proposte del suggerimento di chiamata. Concedere nuovamente\nl'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder andere voor\nsuggesties inzake oproepaanbevelingen is vereist. Verleen opnieuw de autorisatie\nom de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet forslag til anropsanbefalinger\nkrever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke\nAudi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do proponowania sugerowanych połączeń. Aby ponownie korzystać z Audi\nassistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessário permissão para as sugestões da\nrecomendação de chamada, entre outros. Por favor, volta a conceder a permissão\npara poderes voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был деактивирован, поскольку авторизация требуется, в\nчастности, для рекомендаций по вызовам. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten bland annat krävs för\nförslag på samtalsrekommendationer. Tilldela behörigheten igen för att kunna\nfortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, arama önerisinin\nönerileri için yetkilendirme gereklidir. Audi assistant'ı tekrar kullanabilmek için,\nlütfen yeniden yetki ver.")
notification_revoked_permission_bluetooth_connect_embedded_recog_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nrozpoznávání kontaktů ve Vašem telefonním seznamu. Udělte prosím znovu\noprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet registrering af kontakter fra din telefonbog. Tildel autorisationen på\nny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nErkennung von Kontakten aus deinem Telefonbuch notwendig ist. Bitte erteile die\nBerechtigung erneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια την αναγνώριση επαφών από τον τηλεφωνικό κατάλογό σας. Χορηγήστε εκ νέου\nτο δικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required, for\nexample, to detect contacts from your directory. Please assign the authorisation\nagain to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara detectar contactos de su agenda. Debe conceder el permiso de nuevo para\nvolver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puhelinluettelon\nkontaktien tunnistamiseen. Myönnä oikeus uudelleen käyttääksesi jälleen Audi\nassistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour la\nreconnaissance de contacts issus de votre annuaire. Veuillez de nouveau accorder\nvotre autorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközt a telefonkönyvben található névjegyek felismeréséhez. Kérünk, add meg újra\naz engedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per il riconoscimento dei contatti della rubrica. Concedere nuovamente\nl'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder andere voor het\nherkennen van contacten uit je telefoonboek is vereist. Verleen opnieuw de\nautorisatie om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet gjenkjenning av kontakter i\ntelefonboken krever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å\nfortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do rozpoznawania kontaktów z Twojej książki telefonicznej. Aby ponownie\nkorzystać z Audi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para o\nreconhecimento de contactos da tua lista telefónica, entre outros. Por favor, volta\na conceder permissão para poderes voltar a utilizar o Audi assitant.", ru_RU="Audi assistant был деактивирован, поскольку авторизация требуется, в\nчастности, для распознавания контактов из телефонной книги. Чтобы снова\nиметь возможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten bland annat krävs för att\nidentifiera kontakter ur din telefonbok. Tilldela behörigheten igen för att kunna\nfortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, telefon\ndefterindeki kişilerin tanınması için yetkilendirme gereklidir. Audi assistant'ı\ntekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_calendar_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro navigaci\na volbu nového termínu. Udělte prosím znovu oprávnění, abyste mohli opět Audi\nassistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet navigation og deltagelse i et møde. Tildel autorisationen på ny for\nat kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nNavigation und das Einwählen in einen Termin notwendig ist. Bitte erteile die\nBerechtigung erneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια την πλοήγηση και την επιλογή ενός ραντεβού. Χορηγήστε εκ νέου το δικαίωμα,\nώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as the navigation system and dialling into an appointment. Please\nassign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara navegar y acceder a una cita. Debe conceder el permiso de nuevo para volver\na utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. navigointiin sekä\nvarattuun tapahtumaan. Myönnä oikeus uudelleen käyttääksesi jälleen Audi\nassistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour la\nnavigation et la connexion à un rendez-vous. Veuillez de nouveau accorder votre\nautorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a navigációhoz és egy találkozóra történő bejelentkezéshez. Kérünk, add\nmeg újra az engedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per la navigazione e l'accesso a un appuntamento tramite il telefono.\nConcedere nuovamente l'autorizzazione per poter utilizzare ancora l'Audi\nassistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder andere voor de\nnavigatie en het inbellen in een vergadering is vereist. Verleen opnieuw de\nautorisatie om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet navigasjon og oppkobling til en\navtale krever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å\nbruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do nawigacji oraz dokonywania wyboru terminu. Aby ponownie korzystać\nz Audi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para a navegação e a\nseleção de uma data, entre outros. Por favor, volta a conceder permissão para\npoderes voltar a utilizar o Audi assitant.", ru_RU="Audi assistant был деактивирован, поскольку авторизация требуется, в\nчастности, для навигации и записи на встречу. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten bland annat krävs för\nnavigering och för att ansluta till en avtalad tid. Tilldela behörigheten igen för att\nkunna fortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, navigasyon ve bir\nrandevuyu aramak için yetkilendirme gereklidir. Audi assistant'ı tekrar\nkullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_call_log_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nopakování volání a pro návrhy doporučeného volání. Udělte prosím znovu\noprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet genkald og forslag fra opkaldsanbefalingen. Tildel autorisationen\npå ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nWahlwiederholung sowie für Vorschläge der Anrufempfehlung notwendig ist.\nBitte erteile die Berechtigung erneut, um den Audi assistant wieder nutzen\nzu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια την επανάληψη κλήσης, καθώς και προτάσεις της σύστασης κλήσεων.\nΧορηγήστε εκ νέου το δικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την\nAudi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required, for\nexample, to redial numbers or for call recommendation suggestions. Please\nassign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara repetir una llamada o sugerir recomendaciones de llamada. Debe conceder\nel permiso de nuevo para volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. numeron\nuudelleenvalintaan sekä puhelusuositusten ehdottamiseen. Myönnä oikeus\nuudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour la\nrecomposition et la suggestion d'appel. Veuillez de nouveau accorder votre\nautorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a hívásismétléshez és a hívásajánlat-javaslatokhoz. Kérünk, add meg újra\naz engedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per la ripetizione dell'ultimo numero selezionato e per le proposte del\nsuggerimento di chiamata. Concedere nuovamente l'autorizzazione per poter\nutilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder andere voor de\nkeuzeherhaling en voor suggesties inzake oproepaanbevelingen is vereist. Verleen\nde autorisatie opnieuw om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet nummerrepetisjon og forslag til\nanropsanbefalinger krever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å\nfortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do powtarzania połączeń oraz proponowania zalecanych połączeń. Aby\nponownie korzystać z Audi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para a remarcação e\npara sugestões de recomendação de chamada, entre outros. Por favor, volta a\nconceder permissão para poderes voltar a utilizar o Audi assitant.", ru_RU="Audi assistant был деактивирован, поскольку авторизация требуется, в\nчастности, для повторного набора номера и для рекомендаций по вызову.\nЧтобы снова иметь возможность пользоваться Audi assistant, повторно\nпредоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten bland annat krävs för\nåteruppringning samt för förslag på samtalsrekommendationer. Tilldela\nbehörigheten igen för att kunna fortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, tekrar arama ve\nayrıca arama önerisinin önerileri için yetkilendirme gereklidir. Audi assistant'ı\ntekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_call_log_da_pred_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro návrhy\ndoporučeného volání. Udělte prosím znovu oprávnění, abyste mohli opět Audi\nassistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet forslag fra opkaldsanbefalingen. Tildel autorisationen på ny for at\nkunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für\nVorschläge der Anrufempfehlung notwendig ist. Bitte erteile die Berechtigung\nerneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια προτάσεις της σύστασης κλήσεων. Χορηγήστε εκ νέου το δικαίωμα, ώστε να\nμπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required, for\nexample, for call recommendation suggestions. Please assign the authorisation\nagain to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara sugerir recomendaciones de llamada. Debe conceder el permiso de nuevo\npara volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puhelusuositusten\nehdottamiseen. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour la\nsuggestion d'appel. Veuillez de nouveau accorder votre autorisation pour pouvoir\nà nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközt a hívásajánlás-javaslatokhoz. Kérünk, add meg újra az engedélyt, hogy az\nAudi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per le proposte del suggerimento di chiamata. Concedere nuovamente\nl'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder andere voor\nsuggesties inzake oproepaanbevelingen is vereist. Verleen opnieuw de autorisatie\nom de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet forslag til anropsanbefalinger\nkrever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke\nAudi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do proponowania sugerowanych połączeń. Aby ponownie korzystać z Audi\nassistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessário permissão para as sugestões da\nrecomendação de chamada, entre outros. Por favor, volta a conceder a permissão\npara poderes voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был деактивирован, поскольку авторизация требуется, в\nчастности, для рекомендаций по вызовам. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten bland annat krävs för\nförslag på samtalsrekommendationer. Tilldela behörigheten igen för att kunna\nfortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, arama önerisinin\nönerileri için yetkilendirme gereklidir. Audi assistant'ı tekrar kullanabilmek için,\nlütfen yeniden yetki ver.")
notification_revoked_permission_car_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nzjišťování stavu nabití, dojezdu nebo řízení asistenčních systémů hlasově. Udělte\nprosím znovu oprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet fremkaldelse af ladestand, rækkevidde eller styring af\nassistentsystemer via stemmebetjening. Tildel autorisationen på ny for at kunne\nanvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nAbfrage des Ladestands, der Reichweite oder der Steuerung der\nAssistenzsysteme per Sprache notwendig ist. Bitte erteile die Berechtigung\nerneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια την κλήση της κατάστασης φόρτισης, της αυτονομίας ή του φωνητικού ελέγχου\nτων συστημάτων υποβοήθησης. Χορηγήστε εκ νέου το δικαίωμα, ώστε να\nμπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required, for\nexample, to query the charge level or range or to control assist systems by voice.\nPlease assign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara consultar el nivel de carga y la autonomía o para controlar los sitemas de\nasistencia Debe conceder el permiso de nuevo para volver a utilizar el Audi\nassistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. varaustilan tai\ntoimintamatkan kyselyyn ja avustinjärjestelmien ohjaukseen puheen avulla.\nMyönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'interrogation du niveau de charge, de l'autonomie ou de la commande des\nsystèmes d'assistance par commande vocale. Veuillez de nouveau accorder votre\nautorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a töltési szint és a hatótávolság lekérdezéséhez, valamint az\nasszisztensrendszerek beszéddel történő irányításához. Kérünk, add meg újra az\nengedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per richiamare il livello di carica e l'autonomia o per gestire i sistemi di\nassistenza tramite comando vocale. Concedere nuovamente l'autorizzazione per\npoter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder andere voor het\nopvragen van de laadstand, de reikwijdte of de besturing van de hulpsystemen\nper taal is vereist. Verleen de autorisatie opnieuw om de Audi assistant weer te\nkunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet forespørsler om ladenivå,\nrekkevidde og styring av assistentsystemer med stemmen krever\ntilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke Audi\nassistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do odczytu poziomu naładowania, zasięgu oraz głosowego sterowania\nsystemami wspomagającymi kierowcę. Aby ponownie korzystać z Audi assistant,\nprzydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para consulta do\nnível de carga, da autonomia ou da gestão dos sistemas de assistência através da\nvoz, entre outros. Por favor, volta a conceder permissão para poderes voltar a\nutilizar o Audi assistant.", ru_RU="Audi assistant был деактивирован, поскольку авторизация требуется, в\nчастности, для запроса уровня заряда, запаса хода или для управления\nассистирующими системами с помощью голоса. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten bland annat krävs för att\navläsa laddnivå och räckvidd samt för röststyrning av assistanssystemet. Tilldela\nbehörigheten igen för att kunna fortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, şarj seviyesini,\nmenzili sorgulamak veya asistan sistemlerini konuşarak kontrol etmek için\nyetkilendirme gereklidir. Audi assistant'ı tekrar kullanabilmek için, lütfen yeniden\nyetki ver.")
notification_revoked_permission_car_da_core_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože přístup k informacím o vozidle jako\nrychlost je nutný mimo jiné k nabídce návrhů přiměřených situaci. Udělte prosím\nznovu oprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet et situationsafhængigt passende udbud af forslag. Tildel\nautorisationen på ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da der Zugriff auf Fahrzeuginformationen\nwie die Geschwindigkeit unter anderem für das situativ angemessene Angebot\nvon Vorschlägen notwendig ist. Bitte erteile die Berechtigung erneut, um den\nAudi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι απαιτείται η πρόσβαση σε πληροφορίες\nτου οχήματος, όπως η ταχύτητα κίνησης, μεταξύ άλλων για την υποβολή\nκατάλληλων προτάσεων, ανάλογα με την εκάστοτε κατάσταση. Χορηγήστε εκ νέου\nτο δικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because access to vehicle information\nsuch as the speed is required for the system to offer appropriate suggestions for\nthe situation. Please assign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el acceso a información del\nvehículo como, por ejemplo, la velocidad. Debe conceder el permiso de nuevo\npara volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä auton tietoihin (kuten nopeuteen) tarvitaan\npääsy tilanteeseen sopivien ehdotusten tarjoamiseksi. Myönnä oikeus uudelleen\nkäyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'accès aux informations du véhicule (telles\nque la vitesse) est requis, par exemple pour la proposition de suggestions\nadaptées au contexte. Veuillez de nouveau accorder votre autorisation pour\npouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van a jármű-információkhoz,\npl. a sebességhez való hozzáférésre többek között az adott szituációnak\nmegfelelő javaslatokhoz. Kérünk, add meg újra az engedélyt, hogy az Audi\nassistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'accesso alle informazioni della\nvettura, come la velocità, è necessario, tra l'altro, per fornire proposte adeguate\nalla situazione. Concedere nuovamente l'autorizzazione per poter utilizzare\nancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de toegang tot voertuiginformatie\nzoals de snelheid, onder andere voor het per situatie afgestemde aanbod van\nsuggesties, is vereist. Verleen de autorisatie opnieuw om de Audi assistant weer\nte kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi tilgang til bilinformasjon, f.eks. hastighet, blant\nannet er nødvendig for å gi passende forslag i ulike situasjoner. Gi\ntilgangsrettigheter på nytt for å fortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ dostęp do informacji o pojeździe,\ntakich jak prędkość, jest wymagany, między innymi, do proponowania sugestii\nodpowiednio do sytuacji. Aby ponownie korzystać z Audi assistant, przydziel\nuprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para aceder às\ninformações do veículo como a velocidade, entre outros, para a proposta de\nrecomendações em função da situação. Por favor, volta a conceder permissão\npara poderes voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был деактивирован, поскольку доступ к информации об\nавтомобиле, такой как скорость, необходим, в частности, для того, чтобы\nдавать рекомендации, соответствующие ситуации. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom åtkomst till fordonsinformation som\nt.ex. hastighet bland annat krävs för att ge situationsberoende förslag. Tilldela\nbehörigheten igen för att kunna fortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, duruma uygun\nönerilerin teklifi için hız gibi araç bilgilerine erişim gereklidir. Audi assistant'ı\ntekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_contacts_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro volání a\nnavigaci hlasem, pro návrhy doporučeného volání i pro diktování zpráv. Udělte\nprosím znovu oprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet opkald og navigation via stemmebetjening, forslag fra\nopkaldsanbefalingen samt diktering af beskeder. Tildel autorisationen på ny for\nat kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nAnrufe und die Navigation per Sprache, Vorschläge der Anrufempfehlung sowie\ndas Diktieren von Nachrichten notwendig ist. Bitte erteile die Berechtigung\nerneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια τις τηλεφωνικές κλήσεις και την πλοήγηση μέσω φωνητικού χειρισμού,\nπροτάσεις της σύστασης κλήσεων, καθώς και την υπαγόρευση μηνυμάτων.\nΧορηγήστε εκ νέου το δικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την\nAudi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required, for\nexample, for calls and voice navigation, call recommendation suggestions and\ndictating messages. Please assign the authorisation again to use the Audi\nassistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara las llamadas y la navegación por voz, para sugerir recomendaciones de\nllamada y para dictar mensajes. Debe conceder el permiso de nuevo para volver a\nutilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puheluiden soittamiseen\nja navigointiin puheen avulla, puhelusuositusten ehdottamiseen sekä viestien\nsanelemiseen. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nles appels et la navigation par commande vocale, pour la suggestion d'appel ainsi\nque pour la diction de messages. Veuillez de nouveau accorder votre autorisation\npour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a hanggal történő híváshoz és navigációhoz, a hívásajánlás-javaslatokhoz,\nvalamint az üzenetek diktálásához. Kérünk, add meg újra az engedélyt, hogy az\nAudi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per le chiamate e la navigazione tramite comando vocale, per le proposte\ndel suggerimento di chiamata e per dettare messaggi. Concedere nuovamente\nl'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder andere voor\noproepen en de navigatie per taal, suggesties inzake oproepaanbevelingen en het\ndicteren van berichten is vereist. Verleen de autorisatie opnieuw om de Audi\nassistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet anrop og navigasjon med\nstemmestyring, forslag til anropsanbefalinger og diktering av meldinger krever\ntilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke Audi\nassistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do głosowej obsługi połączeń i nawigacji, proponowania sugerowanych\npołączeń oraz dyktowania wiadomości. Aby ponownie korzystać z Audi assistant,\nprzydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para chamadas e\nnavegação através do comando por voz, sugestões da recomendação de\nchamadas e ditar mensagens, entre outros. Por favor, volta a conceder permissão\npara poderes voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был деактивирован, поскольку авторизация требуется, в\nчастности, для вызовов и навигации с помощью голоса, рекомендаций по\nвызовам и диктовки сообщений. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten bland annat krävs för\nröststyrning av samtal och navigering, förslag på samtalsrekommendationer\nsamt diktering av meddelanden. Tilldela behörigheten igen för att kunna\nfortsätta använda Audi assistant.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, aramalar ve\nkonuşarak navigasyon, arama önerisinin önerileri ve ayrıca ve mesajları dikte\netmek için yetkilendirme gereklidir. Audi assistant'ı tekrar kullanabilmek için,\nlütfen yeniden yetki ver.")
notification_revoked_permission_contacts_da_pred_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro volání\nkontaktů a návrhy doporučených volání. Udělte prosím znovu oprávnění, abyste\nmohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet opkald til kontakter og forslag fra opkaldsanbefalingen. Tildel\nautorisationen på ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für\nAnrufe bei Kontakten und Vorschläge der Anrufempfehlung notwendig ist. Bitte\nerteile die Berechtigung erneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια κλήσεις σε επαφές και προτάσεις της σύστασης κλήσης. Χορηγήστε εκ νέου το\nδικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as calls to contacts and call recommendation suggestions. Please\nassign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara llamar a contactos y para sugerir recomendaciones de llamada. Debe\nconceder el permiso de nuevo para volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. kontakteille\nsoittamiseen ja puhelusuositusten ehdottamiseen. Myönnä oikeus uudelleen\nkäyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nles appels de contacts et pour la suggestion d'appel. Veuillez de nouveau\naccorder votre autorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a kapcsolatok hívásához és a hívásajánlat-javaslatokhoz. Kérünk, add meg\nújra az engedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per le chiamate ai contatti e per i suggerimenti di chiamata. Concedere\nnuovamente l'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere\noproepen naar contacten en suggesties van oproepaanbevelingen is vereist. Geef\nopnieuw de autorisatie om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet anrop til kontakter og forslag til\nanropsanbefalinger krever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å\nfortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, dla połączeń i propozycji zalecanych połączeń. Aby ponownie korzystać z\nAudi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para chamadas nos\ncontactos e recomendações da recomendação de chamada.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для вызовов контактов и рекомендаций по вызовам. Чтобы снова\nиметь возможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för att bland annat\nringa upp kontakter och förslag på samtalsrekommendationer. Tilldela\nbehörigheten på nytt för att kunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, kişilere yapılan\nçağrılar ve arama önerisinin önerileri için yetkilendirme gereklidir. Audi assistant'ı\ntekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_contacts_embedded_recog_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro volání\nkontaktů hlasově. Udělte prosím znovu oprávnění, abyste mohli opět Audi\nassistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet opkald til kontakter via stemmebetjening. Tildel autorisationen på\nny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für\nAnrufe bei Kontakten per Sprache notwendig ist. Bitte erteile die Berechtigung\nerneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια κλήσεις σε επαφές μέσω φωνητικού χειρισμού. Χορηγήστε εκ νέου το δικαίωμα,\nώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as calls to contacts by voice control. Please assign the\nauthorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara llamar por voz a contactos. Debe conceder el permiso de nuevo para volver a\nutilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. kontakteille\nsoittamiseen puheen avulla. Myönnä oikeus uudelleen käyttääksesi jälleen Audi\nassistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nles appels de contacts par commande vocale. Veuillez de nouveau accorder votre\nautorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a kapcsolatok hanggal történő hívásához. Kérünk, add meg újra az\nengedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per le chiamate ai contatti tramite comando vocale. Concedere\nnuovamente l'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere\noproepen naar contacten per taal is vereist. Geef opnieuw de autorisatie om de\nAudi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet anrop til kontakter med\nstemmestyringen krever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å\nfortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, dla połączeń przy kontaktach głosowych. Aby ponownie korzystać z Audi\nassistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para chamadas nos\ncontactos através da voz. Por favor, volta a conceder a permissão para se poder\nvoltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для голосовых вызовов контактов. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för att bland annat\nringa upp kontakter med röststyrning. Tilldela behörigheten på nytt för att kunna\nanvända Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, kişilere\nkonuşarak yapılan çağrılar için yetkilendirme gereklidir. Audi assistant'ı tekrar\nkullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_location_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nzadávání cílů hlasově i pro učení a provádění rutin. Udělte prosím znovu\noprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet destinationsangivelse via stemmebetjening samt indlæring og\nudførelse af rutiner. Tildel autorisationen på ny for at kunne anvende Audi\nassistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nZieleingabe per Sprache sowie das Erlernen und Ausführen von Routinen\nnotwendig ist. Bitte erteile die Berechtigung erneut, um den Audi assistant\nwieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια την καταχώριση προορισμών μέσω φωνητικού χειρισμού, καθώς και την\nεκμάθηση και εκτέλεση προτιμώμενων τυποποιημένων διαδικασιών (συνηθειών).\nΧορηγήστε εκ νέου το δικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την\nAudi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required to\nenter destinations by voice control and for programming and performing\nroutines. Please assign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara introducir por voz el destino o aprender y ejecutar rutinas. Debe conceder el\npermiso de nuevo para volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. kohteen syöttämiseen\npuheen avulla sekä rutiinien oppimiseen ja suorittamiseen. Myönnä oikeus\nuudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'entrée de la destination par commande vocale ainsi que pour l'apprentissage et\nl'exécution de routines. Veuillez de nouveau accorder votre autorisation pour\npouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött az úti cél hanggal történő megadásához, valamint a rutinok\nmegtanulásához és végrehajtásához. Kérünk, add meg újra az engedélyt, hogy az\nAudi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per l'immissione vocale di destinazioni e per l'apprendimento e\nl'esecuzione di routine. Concedere nuovamente l'autorizzazione per poter\nutilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere de\nbestemmingsinvoer per taal en het aanleren en uitvoeren van routines is vereist.\nGeef opnieuw de autorisatie om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet målangivelse med stemmestyring\nog innlæring og utføring av rutiner krever tilgangsrettigheter. Gi\ntilgangsrettigheter på nytt for å fortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do wprowadzania celu głosowo oraz uczenia się i wykonywania rutyn. Aby\nponownie korzystać z Audi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para introdução do\ndestino através do comando por voz e também para aprendizagem e execução de\nrotinas. Por favor, concede novamente permissão para se poder voltar a utilizar o\nAudi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для голосового ввода целей навигации, а также для\nпрограммирования и выполнения стандартных действий. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för att bland annat\nmata in resmål med röststyrning eller att lära in och utföra rutiner. Tilldela\nbehörigheten på nytt för att kunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, konuşarak hedef\ngirme ve ayrıca rutinlerin öğrenilmesi ve uygulanması için yetkilendirme\ngereklidir. Audi assistant'ı tekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_location_da_core_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro učení a\nprovádění rutin. Udělte prosím znovu oprávnění, abyste mohli opět Audi\nassistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet indlæring og udførelse af rutiner. Tildel autorisationen på ny for at\nkunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für das\nErlernen und Ausführen von Routinen notwendig ist. Bitte erteile die\nBerechtigung erneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια την εκμάθηση και εκτέλεση προτιμώμενων τυποποιημένων διαδικασιών\n(συνηθειών). Χορηγήστε εκ νέου το δικαίωμα, ώστε να μπορέσετε να\nχρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nprogramming and performing routines. Please assign the authorisation again to\nuse the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara aprender y ejecutar rutinas. Debe conceder el permiso de nuevo para volver a\nutilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. rutiinien oppimiseen ja\nsuorittamiseen. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'apprentissage et l'exécution de routines. Veuillez de nouveau accorder votre\nautorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a rutinok megtanulásához és végrehajtásához. Kérünk, add meg újra az\nengedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per l'apprendimento e l'esecuzione di routine. Concedere nuovamente\nl'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere het\naanleren en uitvoeren van routines is vereist. Geef opnieuw de autorisatie om de\nAudi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet innlæring og utføring av rutiner\nkrever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke\nAudi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do uczenia się i wykonywania rutyn. Aby ponownie korzystać z Audi\nassistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para para\naprendizagem e execução de rotinas. Por favor, concede novamente permissão\npara se poder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для программирования и выполнения стандартных действий.\nЧтобы снова иметь возможность пользоваться Audi assistant, повторно\nпредоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för att bland annat\nlära in och utföra rutiner. Tilldela behörigheten på nytt för att kunna använda\nAudi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, rutinlerin\nöğrenilmesi ve uygulanması için yetkilendirme gereklidir. Audi assistant'ı tekrar\nkullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_location_da_pred_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nzlepšování přesnosti návrhů i pro učení a provádění rutin. Udělte prosím znovu\noprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet forbedring af nøjagtigheden af forslag samt indlæring og udførelse\naf rutiner. Tildel autorisationen på ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nVerbesserung der Genauigkeit von Vorschlägen sowie das Erlernen und Ausführen\nvon Routinen notwendig ist. Bitte erteile die Berechtigung erneut, um den Audi\nassistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια τη βελτίωση της ακρίβειας των προτάσεων, καθώς και την εκμάθηση και\nεκτέλεση προτιμώμενων τυποποιημένων διαδικασιών (συνηθειών). Χορηγήστε εκ\nνέου το δικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required to\nimprove the precision of suggestions and to program and perform routines.\nPlease assign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara mejorar la precisión de las sugerencias o aprender y ejecutar rutinas. Debe\nconceder el permiso de nuevo para volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. ehdotusten tarkkuuden\nparantamiseen sekä rutiinien oppimiseen ja suorittamiseen. Myönnä oikeus\nuudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\naméliorer la précision des suggestions ainsi que pour l'apprentissage et\nl'exécution de routines. Veuillez de nouveau accorder votre autorisation pour\npouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a javaslatok pontosságának javításához, valamint a rutinok\nmegtanulásához és végrehajtásához. Kérünk, add meg újra az engedélyt, hogy az\nAudi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per il miglioramento e la precisione delle proposte e per l'apprendimento\ne l'esecuzione di routine. Concedere nuovamente l'autorizzazione per poter\nutilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere het\nverbeteren van de precisie van suggesties en het aanleren en uitvoeren van\nroutines is vereist. Geef opnieuw de autorisatie om de Audi assistant weer te\nkunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet funksjonen som gir mer nøyaktige\nforslag, og innlæring og utføring av rutiner krever tilgangsrettigheter. Gi\ntilgangsrettigheter på nytt for å fortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do zwiększenia precyzji sugestii oraz uczenia się i wykonywania rutyn. Aby\nponownie korzystać z Audi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para melhoria do\nrigor das recomendações e também para aprendizagem e execução de rotinas.\nPor favor, concede novamente permissão para se poder voltar a utilizar o Audi\nassistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для повышения точности предложений и для программирования и\nвыполнения стандартных действий. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för att bland annat\nge mer relevanta förslag eller att lära in och utföra rutiner. Tilldela behörigheten\npå nytt för att kunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, önerilerin\ndoğruluğunun iyileştirilmesi ve ayrıca rutinlerin öğrenilmesi ve uygulanması için\nyetkilendirme gereklidir. Audi assistant'ı tekrar kullanabilmek için, lütfen yeniden\nyetki ver.")
notification_revoked_permission_location_embedded_recog_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nzadávání cílů hlasově. Udělte prosím znovu oprávnění, abyste mohli opět Audi\nassistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet destinationsangivelse via stemmebetjening. Tildel autorisationen\npå ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nZieleingabe per Sprache notwendig ist. Bitte erteile die Berechtigung erneut, um\nden Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια την καταχώριση προορισμών μέσω φωνητικού χειρισμού. Χορηγήστε εκ νέου το\nδικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required to\nenter destinations by voice control. Please assign the authorisation again to use\nthe Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara introducir por voz el destino. Debe conceder el permiso de nuevo para volver\na utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. kohteen syöttämiseen\npuheen avulla. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'entrée de la destination par commande vocale. Veuillez de nouveau accorder\nvotre autorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött az úti cél hanggal történő megadásához. Kérünk, add meg újra az\nengedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per l'immissione vocale di destinazioni. Concedere nuovamente\nl'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere de\nbestemmingsinvoer per taal is vereist. Geef opnieuw de autorisatie om de Audi\nassistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet målangivelse med\nstemmestyringen krever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å\nfortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do wprowadzania celu głosowo. Aby ponownie korzystać z Audi assistant,\nprzydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para introdução do\ndestino através do comando por voz. Por favor, concede novamente permissão\npara se poder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для голосового ввода целей навигации. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för att bland annat\nmata in resmål med röststyrning. Tilldela behörigheten på nytt för att kunna\nanvända Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, konuşarak hedef\ngirme için yetkilendirme gereklidir. Audi assistant'ı tekrar kullanabilmek için,\nlütfen yeniden yetki ver.")
notification_revoked_permission_microphone_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nhlasovou interakci, návrhy i pro provádění rutin. Udělte prosím znovu oprávnění,\nabyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet taleinteraktion, forslag samt udførelse af rutiner. Tildel\nautorisationen på ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nSprachinteraktion, Vorschläge sowie das Ausführen von Routinen notwendig ist.\nBitte erteile die Berechtigung erneut, um den Audi assistant wieder nutzen\nzu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια τη φωνητική αλληλεπίδραση, για προτάσεις, καθώς και την εκτέλεση\nπροτιμώμενων τυποποιημένων διαδικασιών (συνηθειών). Χορηγήστε εκ νέου το\nδικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as spoken interaction, suggestions and performing routines.\nPlease assign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara interactuar por voz, para las sugerencias o para ejecutar rutinas. Debe\nconceder el permiso de nuevo para volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puhevuorovaikutukseen,\nehdotuksiin sekä rutiinien suorittamiseen. Myönnä oikeus uudelleen käyttääksesi\njälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'interaction vocale, les suggestions et l'exécution de routines. Veuillez de\nnouveau accorder votre autorisation pour pouvoir à nouveau utiliser l'Audi\nassistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a beszéd-interakcióhoz, valamint a rutinok megtanulásához és\nvégrehajtásához. Kérünk, add meg újra az engedélyt, hogy az Audi assistant\nismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per l'interazione vocale, le proposte e l'esecuzione di routine. Concedere\nnuovamente l'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere de\nspraakinteractie, suggesties en het uitvoeren van routines is vereist. Geef\nopnieuw de autorisatie om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet stemmestyrt kommunikasjon med\nbilen, forslag og utføring av rutiner krever tilgangsrettigheter. Gi\ntilgangsrettigheter på nytt for å fortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do interakcji głosowej, sugestii oraz wykonywania rutyn. Aby ponownie\nkorzystać z Audi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para interações de\nvoz, recomendações e também execução de rotinas. Por favor, concede\nnovamente permissão para se poder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для голосового взаимодействия, рекомендаций, а также\nвыполнения стандартных действий. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för bland annat\nröstinteraktion, förslag eller att lära in och utföra rutiner. Tilldela behörigheten\npå nytt för att kunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, sesli etkileşim,\nöneriler ve rutinlerin uygulanması için yetkilendirme gereklidir. Audi assistant'ı\ntekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_microphone_embedded_recog_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nhlasovou interakci, návrhy i pro provádění rutin. Aktivace externího hlasového\nasistenta aktivačním slovem již rovněž není možné. Udělte prosím znovu\noprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet taleinteraktion, forslag samt udførelse af rutiner. Aktivering af en\nekstern taleassistent via aktiveringsord er heller ikke længere muligt. Tildel\nautorisationen på ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nSprachinteraktion, Vorschläge sowie das Ausführen von Routinen notwendig ist.\nDie Aktivierung eines externen Sprachassistenten per Aktivierungswort ist\nebenfalls nicht mehr möglich. Bitte erteile die Berechtigung erneut, um den Audi\nassistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια τη φωνητική αλληλεπίδραση, για προτάσεις, καθώς και την εκτέλεση\nπροτιμώμενων τυποποιημένων διαδικασιών (συνηθειών). Η ενεργοποίηση ενός\nεξωτερικού φωνητικού βοηθού μέσω μιας φράσης ενεργοποίησης, επίσης δεν είναι\nπλέον εφικτή. Χορηγήστε εκ νέου το δικαίωμα, ώστε να μπορέσετε να\nχρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as spoken interaction, suggestions and performing routines. It is\nalso no longer possible to activate an external speech assistant using an\nactivation word. Please assign the authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara interactuar por voz, para las sugerencias o para ejecutar rutinas. Tampoco se\npuede activar ya un asistente de voz externo con una palabra de activación. Debe\nconceder el permiso de nuevo para volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puhevuorovaikutukseen,\nehdotuksiin sekä rutiinien suorittamiseen. Ulkoista puheavustinta ei voi\nmyöskään enää aktivoida aktivointisanoilla. Myönnä oikeus uudelleen\nkäyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'interaction vocale, les suggestions et l'exécution de routines. Vous ne pouvez\négalement plus activer un assistant vocal externe à l'aide d'un mot de réveil.\nVeuillez de nouveau accorder votre autorisation pour pouvoir à nouveau utiliser\nl'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a beszéd-interakcióhoz, a javaslatokhoz, valamint a rutinok\nvégrehajtásához. Kérünk, add meg újra az engedélyt, hogy az Audi assistant\nismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per l'interazione vocale, le proposte e l'esecuzione di routine. Anche\nl'attivazione di un assistente vocale esterno tramite comando di attivazione non è\npiù possibile. Concedere nuovamente l'autorizzazione per poter utilizzare ancora\nl'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere de\nspraakinteractie, suggesties en het uitvoeren van routines is vereist. Het activeren\nvan een externe spraakassistent per activeringswoord is eveneens niet meer\nmogelijk. Geef opnieuw de autorisatie om de Audi assistant weer te kunnen\ngebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet stemmestyrt kommunikasjon med\nbilen, forslag og utføring av rutiner krever tilgangsrettigheter. Det er heller ikke\nlenger mulig å aktivere en ekstern taleassistent ved hjelp av et aktiveringsord. Gi\ntilgangsrettigheter på nytt for å fortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do interakcji głosowej, sugestii oraz wykonywania rutyn. Aktywacja\nzewnętrznego asystenta głosowego słowem aktywującym również nie jest\nmożliwa. Aby ponownie korzystać z Audi assistant, przydziel uprawnienie\nponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para interações de\nvoz, recomendações e também execução de rotinas. A ativação de um assistente\nde voz externo através de palavra de ativação já não é possível. Por favor, concede\nnovamente permissão para se poder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для голосового взаимодействия, рекомендаций, а также\nвыполнения стандартных действий. Активация внешнего голосового\nпомощника с помощью слова активации также больше невозможна.Чтобы\nснова иметь возможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för bland annat\nröstinteraktion, förslag eller att utföra rutiner. Aktivering av en extern\nröstassistent med aktiveringsord är heller inte längre möjlig. Tilldela\nbehörigheten på nytt för att kunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, sesli etkileşim,\nöneriler ve rutinlerin uygulanması için yetkilendirme gereklidir. Harici bir dil\nasistanının bir aktivasyon kelimesi ile aktive edilmesi de artık mümkün değildir.\nAudi assistant'ı tekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_microphone_online_recog_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro\nzlepšování zadávání cílů i pro hledání médií. Udělte prosím znovu oprávnění,\nabyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet forbedring af destinationsangivelse samt mediesøgning. Tildel\nautorisationen på ny for at kunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nVerbesserung der Zieleingabe sowie die Mediensuche notwendig ist. Bitte erteile\ndie Berechtigung erneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια τη βελτίωση της καταχώρισης προορισμών, καθώς και την αναζήτηση μέσων.\nΧορηγήστε εκ νέου το δικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την\nAudi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required, for\nexample, to improve destination entry and for the media search. Please assign\nthe authorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara mejorar la introducción de destinos y para buscar medios. Debe conceder el\npermiso de nuevo para volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan kohdesyötön parantamiseen\nsekä mediahakuun. Myönnä oikeus uudelleen käyttääksesi jälleen Audi\nassistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'amélioration de l'entrée de la destination et pour la recherche multimédia.\nVeuillez de nouveau accorder votre autorisation pour pouvoir à nouveau utiliser\nl'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött az úti cél megadás javításához, valamint a médiakereséshez. Kérünk, add\nmeg újra az engedélyt, hogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per il miglioramento dell'immissione di destinazioni e per la ricerca di\ncontenuti multimediali. Concedere nuovamente l'autorizzazione per poter\nutilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere het\nverbeteren van de bestemmingsinvoer en het zoeken naar media is vereist. Geef\nopnieuw de autorisatie om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet forbedring av målangivelse og\nmediesøk krever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette\nå bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do lepszego wprowadzania celu oraz wyszukiwania multimediów. Aby\nponownie korzystać z Audi assistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para melhoria da\nintrodução do destino e também procura de dispositivos. Por favor, concede\nnovamente permissão para se poder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для улучшения ввода целей навигации и поиска мультимедиа.\nЧтобы снова иметь возможность пользоваться Audi assistant, повторно\nпредоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för bland annat\nförbättrad resmålsinmatning eller mediesökning. Tilldela behörigheten på nytt\nför att kunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, hedef girişinin\niyileştirilmesi ve ayrıca medya araması için yetkilendirme gereklidir. Audi\nassistant'ı tekrar kullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_phone_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro volání\nhlasově, doporučení v seznamu volání, návrhy rutin i pro provádění rutin. Udělte\nprosím znovu oprávnění, abyste mohli opět Audi assistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet opkald via stemmebetjening, anbefalinger på opkaldsliste, forslag\ntil rutiner samt udførelse af rutiner. Tildel autorisationen på ny for at kunne\nanvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für\nAnrufe per Sprache, Empfehlungen in der Anrufliste, Vorschläge für Routinen\nsowie das Ausführen von Routinen notwendig ist. Bitte erteile die Berechtigung\nerneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια κλήσεις μέσω φωνητικού χειρισμού, συστάσεις στη λίστα κλήσεων, προτάσεις\nγια προτιμώμενες τυποποιημένες διαδικασίες (συνήθειες), καθώς και την εκτέλεση\nπροτιμώμενων τυποποιημένων διαδικασιών (συνηθειών). Χορηγήστε εκ νέου το\nδικαίωμα, ώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as making calls by voice control, recommendations in the call list\nand suggesting and performing routines. Please assign the authorisation again to\nuse the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara llamar por voz, para las recomendaciones en la lista de llamadas o para\nsugerir y ejecutar rutinas. Debe conceder el permiso de nuevo para volver a\nutilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puheluiden soittamiseen\npuheen avulla, puhelulistan suosituksiin sekä rutiinien ehdottamiseen ja\nsuorittamiseen. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nles appels par commande vocale, les recommandations dans la liste d'appels, les\nsuggestions de routines et l'exécution de routines. Veuillez de nouveau accorder\nvotre autorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a hanggal történő híváshoz, a híváslista-javaslatokhoz, valamint a rutinok\nmegtanulásához és végrehajtásához. Kérünk, add meg újra az engedélyt, hogy az\nAudi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per le chiamate tramite comando vocale, per i suggerimenti nella lista\nchiamate, per le proposte di routine e per l'esecuzione di routine. Concedere\nnuovamente l'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere\noproepen per taal, aanbevelingen in de oproepenlijst, suggesties voor routines en\nhet uitvoeren van routines is vereist. Geef opnieuw de autorisatie om de Audi\nassistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet anrop med stemmestyringen,\nanbefalinger i anropslisten, forslag til rutiner og utføring av rutiner krever\ntilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke Audi\nassistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do nawiązywania połączeń głosowo, rekomendacji na liście połączeń.\nsugestii rutyn oraz wykonywania rutyn. Aby ponownie korzystać z Audi assistant,\nprzydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para chamadas\natravés do comando por voz, recomendações na lista de chamadas,\nrecomendações para rotinas e também para execução de rotinas. Por favor,\nconcede novamente permissão para se poder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для голосовых вызовов, рекомендаций в списке вызовов,\nрекомендаций по выполнению стандартных действий. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs bland annat för att\nringa samtal via röststyrning, rekommendationer i samtalslistan, förslag på\nrutiner eller att utföra rutiner. Tilldela behörigheten på nytt för att kunna\nanvända Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, konuşarak\nyapılan çağrılar, çağrı listesindeki öneriler ve ayrıca rutinler için öneriler ve\nrutinlerin uygulanması için yetkilendirme gereklidir. Audi assistant'ı tekrar\nkullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_phone_da_core_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro zajištění\nsprávného stavu systému, stejně jako pro situačně přiměřenou nabídku návrhů a\nrutin. Udělte prosím znovu oprávnění, abyste mohli opět Audi assistanta\npoužívat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet sikring af en korrekt systemtilstand samt et situationsafhængigt\npassende udbud af forslag til rutiner. Tildel autorisationen på ny for at kunne\nanvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für die\nSicherstellung eines korrekten Systemzustands sowie das situativ angemessene\nAngebot von Vorschlägen für Routinen notwendig ist. Bitte erteile die\nBerechtigung erneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια τη διασφάλιση τηε σωστής κατάστασης του συστήματος, καθώς και για την\nυποβολή προτάσεων για προτιμώμενες τυποποιημένες διαδικασίες (συνήθειες) που\nνα αντιστοιχούν στην εκάστοτε κατάσταση. Χορηγήστε εκ νέου το δικαίωμα, ώστε\nνα μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as ensuring that the system status is correct and to be able to\noffer situatively suitable suggestions for routines. Please assign the authorisation\nagain to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara garantizar el correcto estado del sistema o para sugerir rutinas adecuadas\nen cada contexto. Debe conceder el permiso de nuevo para volver a utilizar el Audi\nassistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. järjestelmän oikean tilan\nvarmistamiseen sekä tilanteeseen sopiviin rutiiniehdotuksiin. Myönnä oikeus\nuudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\ngarantir le bon état du système et pour la proposition de suggestions de routines\nadaptée au contexte. Veuillez de nouveau accorder votre autorisation pour\npouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a rendszer megfelelő állapotának biztosításához és az adott helyzetnek\nmegfelelő rutinjavaslatokhoz. Kérünk, add meg újra az engedélyt, hogy az Audi\nassistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per garantire un corretto stato del sistema e per offrire proposte di routine\nadeguate alla situazione. Concedere nuovamente l'autorizzazione per poter\nutilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere het\nwaarborgen van een correcte systeemtoestand en het situatief gepaste aanbod\nvan suggesties voor routines is vereist. Geef opnieuw de autorisatie om de Audi\nassistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi tilgangsrettigheter er nødvendige blant annet\nfor å sørge for korrekt systemstatus og å gi passende forslag til rutiner i ulike\nsituasjoner. Gi tilgangsrettigheter på nytt for å fortsette å bruke Audi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do zapewnienia prawidłowego stanu systemu oraz odpowiedniego dla\nsytuacji proponowania sugerowanych rutyn. Aby ponownie korzystać z Audi\nassistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para assegurar um\ncorreto estado do sistema bem como a proposta de recomendações situacionais\nadequadas para as rotinas. Por favor, concede novamente permissão para se\npoder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для обеспечения корректного состояния системы и рекомендаций\nсоответствующих ситуации стандартных действий. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för bland annat att\nsäkerställa korrekt systemtillstånd eller för att kontextbaserat ge förslag på\nrutiner. Tilldela behörigheten på nytt för att kunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, doğru bir sistem\ndurumunun sağlanması ve ayrıca rutinler için duruma uygun önerilerin teklifi için\nyetkilendirme gereklidir. Audi assistant'ı tekrar kullanabilmek için, lütfen yeniden\nyetki ver.")
notification_revoked_permission_phone_da_pred_service_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože oprávnění je nutné mimo jiné pro návrhy v\nseznamu volání telefonu. Udělte prosím znovu oprávnění, abyste mohli opět Audi\nassistanta používat.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet forslag på telefonens opkaldsliste. Tildel autorisationen på ny for at\nkunne anvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für\nVorschläge in der Anrufliste des Telefons notwendig ist. Bitte erteile die\nBerechtigung erneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι το δικαίωμα απαιτείται, μεταξύ άλλων,\nγια προτάσεις στη λίστα κλήσεων του τηλεφώνου. Χορηγήστε εκ νέου το δικαίωμα,\nώστε να μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required for\nfunctions such as suggestions in the telephone's call list. Please assign the\nauthorisation again to use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara las propuestas en la lista de llamadas. Debe conceder el permiso de nuevo\npara volver a utilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan mm. puhelimen puhelulistan\nehdotuksiin. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nles suggestions dans la liste d'appels du téléphone. Veuillez de nouveau accorder\nvotre autorisation pour pouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött a telefon-híváslista javaslatokhoz. Kérünk, add meg újra az engedélyt,\nhogy az Audi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per le proposte nella lista delle chiamate del telefono. Concedere\nnuovamente l'autorizzazione per poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd, omdat de autorisatie voor onder andere\nsuggesties in de oproeplijst van de telefoon is vereist. Geef opnieuw de\nautorisatie om de Audi assistant weer te kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet forslag i anropslisten for telefonen\nkrever tilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke\nAudi assistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do sugestii na liście połączeń telefonu. Aby ponownie korzystać z Audi\nassistant, przydziel uprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para as\nrecomendações na lista de chamadas do telefone. Por favor, concede novamente\npermissão para se poder voltar a utilizar o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку авторизация требуется, в\nчастности, для рекомендаций в списке вызовов телефона. Чтобы снова иметь\nвозможность пользоваться Audi assistant, повторно предоставьте\nавторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs bland annat för\nrekommendationer i telefonens samtalslista. Tilldela behörigheten på nytt för att\nkunna använda Audi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, telefonun çağrı\nlistesindeki öneriler için yetkilendirme gereklidir. Audi assistant'ı tekrar\nkullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_post_notifications_assistant_text = TextObject(cs_CZ="Audi assistant byl deaktivován, protože autorizace je nutná mimo jiné pro\nzobrazování notifikací. Udělte prosím znovu oprávnění, abyste mohli znovu\npoužívat asistenta Audi.", da_DK="Audi assistant blev deaktiveret, da det er nødvendigt med en autorisation til\nblandt andet visning af meddelelser. Tildel autorisationen på ny for at kunne\nanvende Audi assistant igen.", de_DE="Der Audi assistant wurde deaktiviert, da die Berechtigung unter anderem für das\nAnzeigen von Benachrichtigungen notwendig ist. Bitte erteile die Berechtigung\nerneut, um den Audi assistant wieder nutzen zu können.", el_GR="Η Audi assistant απενεργοποιήθηκε, διότι η εξουσιοδότηση απαιτείται, μεταξύ\nάλλων, για την εμφάνιση ειδοποιήσεων. Χορηγήστε εκ νέου την εξουσιοδότηση, για\nνα μπορέσετε να χρησιμοποιήσετε πάλι την Audi assistant.", en_GB="The Audi assistant has been deactivated because authorisation is required to\ndisplay notifications, as well as other options. Please provide authorisation again\nto use the Audi assistant.", es_ES="El Audi assistant se ha desactivado porque se necesita el permiso, por ejemplo,\npara mostrar notificaciones. Debe conceder el permiso de nuevo para volver a\nutilizar el Audi assistant.", fi_FI="Audi assistant on deaktivoitu, sillä oikeus tarvitaan muun muassa ilmoitusten\nnäyttämiseen. Myönnä oikeus uudelleen käyttääksesi jälleen Audi assistantia.", fr_FR="L'Audi assistant a été désactivé car l'autorisation est requise, par exemple pour\nl'affichage des notifications. Veuillez de nouveau accorder votre autorisation pour\npouvoir à nouveau utiliser l'Audi assistant.", hu_HU="Az Audi assistant kikapcsolásra került, mert szükség van az engedélyre többek\nközött az értesítések kijelzéséhez. Kérünk, add meg újra az engedélyt, hogy az\nAudi assistant ismét használható lehessen.", it_IT="L'Audi assistant è stata disattivata perché l'autorizzazione è necessaria, tra\nl'altro, per la visualizzazione di notifiche. Concedere nuovamente l'autorizzazione\nper poter utilizzare ancora l'Audi assistant.", nl_NL="De Audi assistant is gedeactiveerd omdat de autorisatie onder meer nodig is om\nmeldingen weer te geven. Geef opnieuw toestemming om de Audi assistant weer\nte kunnen gebruiken.", no_NO="Audi assistant er deaktivert fordi blant annet visning av varsler krever\ntilgangsrettigheter. Gi tilgangsrettigheter på nytt for å fortsette å bruke Audi\nassistant.", pl_PL="Audi assistant został wyłączony, ponieważ uprawnienie jest wymagane, między\ninnymi, do powiadomień. Aby ponownie korzystać z Audi assistant, przydziel\nuprawnienie ponownie.", pt_PT="O Audi assistant foi desativado, pois é necessária permissão para a apresentação\nde notificações, entre outras. Por favor, volta a dar permissão para poderes\nutilizar novamente o Audi assistant.", ru_RU="Audi assistant был дезактивирован, поскольку для отображения уведомлений,\nв частности, требуется авторизация. Чтобы снова иметь возможность\nпользоваться Audi assistant, повторно предоставьте авторизацию.", sv_SE="Audi assistant har avaktiverats eftersom behörigheten krävs för bland annat\nvisning av notifikationer. Tilldela behörigheten på nytt för att kunna använda\nAudi assistant igen.", tr_TR="Audi assistant devre dışı bırakıldı, çünkü diğer şeylerin yanı sıra, bildirimlerin\ngörüntülenmeai için yetkilendirme gereklidir. Audi assistant'ı tekrar\nkullanabilmek için, lütfen yeniden yetki ver.")
notification_revoked_permission_subtitle = TextObject(cs_CZ="Oprávnění %1 odebráno", da_DK="Autorisationen %1 inddraget", de_DE="Berechtigung %1 entzogen", el_GR="Το δικαίωμα %1 αφαιρέθηκε", en_GB="%1 authorisation revoked", es_ES="Se ha retirado el permiso %1", fi_FI="Oikeus %1 peruutettu", fr_FR="Autorisation retirée: %1", hu_HU="%1 engedély visszavonva", it_IT="Autorizzazione %1 revocata", nl_NL="Autorisatie %1 ingetrokken", no_NO="Tilgangstillatelsen %1 er trukket tilbake", pl_PL="Cofnięto uprawnienie %1", pt_PT="Permissão %1 retirada", ru_RU="Авторизация %1 отозвана", sv_SE="Behörigheten %1 har dragits tillbaka", tr_TR="%1 yetkisi iptal edildi")
notification_update_install_data_failed_text = TextObject(bs_BA="Instaliranje aktualizacija za jezičke podatke je bilo neuspješno. Već preuzeti\npodaci će biti izbrisani. Sistem će se resetovati na prethodno stanje.", cs_CZ="Instalace updatu hlasových dat se nezdařila. Stažená data se smažou. Obnoví\nse předchozí stav systému.", da_DK="Installation af opdateringer til talte data blev ikke gennemført korrekt.\nDownloadede data slettes. System nulstilles til forrige version.", de_DE="Installation des Sprachdatenupdates nicht erfolgreich. Heruntergeladene\nDaten werden gelöscht. System wird auf vorherigen Stand zurückgesetzt.", el_GR="Η εγκατάστ. τ. αναβάθμ. δεδομέν. ομιλίας δεν ήταν επιτυχής. Τα ήδη ληφθέντα\nδεδομ. θα διαγραφούν. Θα γίνει επαναφ. συστήμ. στην προηγούμ. κατάσταση.", en_GB="The installation of the speech data update was not successful. Data already\ndownloaded will be deleted. The system will be reset to the previous status.", es_ES="Los datos de voz no se han podido actualizar. Los datos que ya se hayan\ndescargado se borrarán. El sistema volverá a la versión anterior.", fi_FI="Puhetietojen päivityksen asennus epäonnistui. Jo ladatut tiedot poistetaan.\nJärjestelmä palautetaan aiempaan tilaan.", fr_FR="Échec installation de la mise à jour des données linguistiques. Effacement\ndes données téléchargées. Rétablissem. de la version précédente du système", hr_HR="Instalacija updatea za jezične podatke nije bila uspješna. Već preuzeti podaci\nće se izbrisati. Sustav će se vratiti na prethodno stanje.", hu_HU="A nyelvi adatfrissítés telepítése sikertelen volt. A már letöltött adatok\ntörlődnek. A rendszer visszaáll az előző állapotba.", it_IT="L'installazione dell'update dei dati vocali non è riuscita. I dati già scaricati\nvengono cancellati. Viene ripristinato lo stato precedente del sistema.", nl_NL="Installatie van taalgegevensupdates is niet gelukt. Gedownloade gegevens\nworden gewist. Het systeem wordt naar de vorige stand teruggezet.", no_NO="Installering av stemmedataoppdateringen mislyktes. Dataene som er lastet\nned, slettes. Systemet tilbakestilles til forrige versjon.", pl_PL="Instalowanie aktualizacji danych języka nie powiodło się. Pobrane już dane\nzostaną usunięte. System zostanie przywrócony do poprzedniego stanu.", pt_PT="Instalação da atualização dos dados de voz não foi realizada com sucesso.\nDados descarregados são apagados. Foi reposto o estado anterior do sist.", ro_RO="Instalarea actualizărilor datelor lingvistice nu s-a încheiat cu succes. Datele\ndeja descărcate sunt şterse. Sistemul este resetat la versiunea anterioară.", ru_RU="Установка не удалась. Уже загруженные данные удаляются. Происходит\nсброс системы.", sk_SK="Inštalácia aktualizácie jazykových údajov sa nepodarila. Už stiahnuté údaje sa\nvymažú. Systém sa vráti do predchádzajúceho stavu.", sl_SI="Namestitev posodobitve govorjenih podatkov ni bila uspešna. Že preneseni\npodatki bodo izbrisani. Sistem bo resetiran na predhodno stanje.", sr_RS="Instalacija ažuriranja za govorne podatke nije bila uspešna. Već preuzeti\npodaci će biti izbrisani. Sistem će se resetovati na prvobitno stanje.", sv_SE="Installationen misslyckades. Nedladdade data raderas. Systemet återställs.", tr_TR="Ses verileri güncellemesinin yüklenmesi başarılı olmadı. Önceden indirilmiş\nolan veriler silinecektir. Sistem önceki durumuna geri yüklenecektir.", uk_UA="Інсталяція оновлення мовних даних не вдалася. Вже завантажені дані\nвидалено. Систему скинуто до попереднього стану.")
notification_update_install_data_failed_title = TextObject(bs_BA="Instaliranje jezičkih podataka neuspješno", cs_CZ="Instalace hlasových dat nebyla úspěšná", da_DK="Installation af talte data blev ikke gennemført korrekt.", de_DE="Installation der Sprachdaten nicht erfolgreich", el_GR="Η εγκατάσταση των δεδομένων ομιλίας δεν ήταν επιτυχής", en_GB="Speech data installation not successful", es_ES="Los datos de voz no se han instalado correctamente", fi_FI="Puhetietojen asennus epäonnistui", fr_FR="Échec de l'installation des données linguistiques", hr_HR="Instalacija jezičnih podataka nije bila uspješna", hu_HU="A beszédadatok telepítése sikertelen", it_IT="L'installazione dei dati vocali non è riuscita", nl_NL="Installatie van de taalgegevens niet succesvol", no_NO="Installering av stemmedata mislyktes", pl_PL="Instalowanie danych języka nie powiodło się", pt_PT="Instalação dos dados de voz não foi bem sucedida", ro_RO="Instalare date lingvistice fără succes", ru_RU="Установка голосовых данных не удалась", sk_SK="Inštalácia jazykových údajov sa nepodarila", sl_SI="Namestitev govorjenih podatkov ni bila uspešna", sr_RS="Instalacija govornih podataka nije bila uspešna", sv_SE="Installationen av språkdata misslyckades", tr_TR="Dil verilerinin kurulumu başarılı değil", uk_UA="Інсталяція мовних даних не вдалася")
notification_update_install_data_success_text = TextObject(cs_CZ="Instalace hlasových dat byla úspěšná.", da_DK="Installation af talte data blev gennemført korrekt.", de_DE="Die Installation der Sprachdaten war erfolgreich.", el_GR="Η εγκατάσταση των δεδομένων ομιλίας ήταν επιτυχής.", en_GB="The speech data installation was successful.", es_ES="Los datos de voz se han instalado correctamente.", fi_FI="Puhetietojen asennus onnistui.", fr_FR="Les données linguistiques ont été installées avec succès.", hu_HU="A beszédadatok telepítése sikeres volt.", it_IT="L'installazione dei dati vocali è riuscita.", nl_NL="De installatie van de taalgegevens was succesvol.", no_NO="Stemmedataene er installert.", pl_PL="Instalowanie danych języka powiodło się.", pt_PT="A instalação dos dados de voz foi bem sucedida.", ru_RU="Установка голосовых данных прошла успешно.", sv_SE="Installationen av språkdata lyckades.", tr_TR="Ses verilerinin yüklenmesi başarılı oldu.")
notification_update_language_load_data_accept_download = TextObject(cs_CZ="Stáhnout hlasová data", da_DK="Download talte data", de_DE="Sprachdaten herunterladen", el_GR="Λήψη (download) δεδομένων\nομιλίας", en_GB="Download speech data", es_ES="Descargar datos de voz", fi_FI="Lataa puhetiedot", fr_FR="Télécharger les données\nlinguistiques", hu_HU="Beszédadatok letöltése", it_IT="Scarica dati vocali", nl_NL="Taalgegevens downloaden", no_NO="Last ned stemmedata", pl_PL="Pobierz dane języka", pt_PT="Descarregar dados de voz", ru_RU="Загрузка голосовых данных", sv_SE="Ladda ned språkdata", tr_TR="Ses verilerini indir")
notification_update_language_load_data_ask_again = TextObject(cs_CZ="Znovu vyžádat", da_DK="Spørg igen", de_DE="Erneut nachfragen", el_GR="Ερώτηση εκ νέου", en_GB="Ask again", es_ES="Volver a preguntar", fi_FI="Kysy uudelleen", fr_FR="Redemander", hu_HU="Kérdezzen újra", it_IT="Chiedi di nuovo", nl_NL="Opnieuw opvragen", no_NO="Ny forespørsel", pl_PL="Zapytaj ponownie", pt_PT="Perguntar de novo", ru_RU="Спроси еще раз", sv_SE="Fråga igen", tr_TR="Tekrar sor")
notification_update_language_load_data_text = TextObject(cs_CZ="Jsou k dispozici aktualizovaná hlasová data pro zvolený jazyk. Chcete nyní\nstáhnout data?", da_DK="Opdaterede talte data er klar for valgt sprog. Vil du downloade dataene nu?", de_DE="Aktualisierte Sprachdaten für die ausgewählte Sprache stehen bereit.\nMöchtest du die Daten jetzt herunterladen?", el_GR="Υπάρχουν έτοιμα ενημερωμένα δεδομένα ομιλίας για την επιλεγμένη γλώσσα.\nΘέλετε να κατεβάσετε (download) τώρα τα δεδομένα;", en_GB="Updated speech data for the selected language is available. Would you like to\ndownload the data now?", es_ES="Hay datos de voz actualizados para el idioma seleccionado. ¿Desea\ndescargarlos ahora?", fi_FI="Valitulle kielelle on valmiina päivitettyjä puhetietoja. Haluatko ladata tiedot\nnyt?", fr_FR="De nouvelles données linguistiques sont disponibles pour la langue\nsélectionnée. Souhaitez-vous télécharger maintenant les données?", hu_HU="Készen állnak a frissített beszédadatok a kiválasztott nyelvhez. Le szeretnéd\nmost tölteni az adatokat?", it_IT="Sono disponibili dati vocali aggiornati per la lingua selezionata. Scaricarli\nadesso?", nl_NL="Geactualiseerde taalgegevens voor de geselecteerde taal staan klaar. Wil je\nde gegevens nu downloaden?", no_NO="Oppdaterte stemmedata er tilgjengelige for valgt språk. Vil du laste ned\ndataene nå?", pl_PL="Zaktualizowane dane wybranego języka są przygotowane. Czy chcesz pobrać\nje teraz?", pt_PT="Estão disponíveis dados de voz atualizados para o idioma selecionado.\nQueres descarregar agora os dados?", ru_RU="Доступны обновленные голосовые данные для выбранного языка.\nЗагрузить данные сейчас?", sv_SE="Uppdaterade språkdata för det valda språket finns redo. Ladda ned datan\nnu?", tr_TR="Seçilen dil için güncellenmiş dil verileri hazırdır. Verileri şimdi indirmek ister\nmisin?")
notification_update_language_load_data_title = TextObject(cs_CZ="Aktualizace hlasových dat", da_DK="Opdatering af talte data", de_DE="Aktualisierung der Sprachdaten", el_GR="Ενημέρωση των δεδομένων ομιλίας", en_GB="Speech data update", es_ES="Actualizar datos de voz", fi_FI="Puhetietojen päivitys", fr_FR="Actualisation des données linguistiques", hu_HU="Beszédadatok frissítése", it_IT="Aggiornamento dei dati vocali", nl_NL="Actualisering van taalgegevens", no_NO="Oppdatering av stemmedata", pl_PL="Aktualizacja danych językowych", pt_PT="Atualização dos dados de voz", ru_RU="Обновление голосовых данных", sv_SE="Uppdatering av språkdata", tr_TR="Ses verilerinin güncellenmesi")
notification_update_load_data_failed_text = TextObject(cs_CZ="Download hlasových dat byl přerušen. Vytvořte prosím datové spojení.", da_DK="Downloading af talte data blev pauset. Opret en dataforbindelse.", de_DE="Der Download der Sprachdaten wurde unter­brochen. Bitte stelle eine\nDatenverbindung her.", el_GR="Η λήψη (download) των δεδομένων ομιλίας διακόπηκε. Δημιουργήστε μια\nσύνδεση δεδομένων.", en_GB="The speech data download was interrupted. Please establish a data\nconnection.", es_ES="La descarga de los datos de voz se ha interrumpido. Establezca una conexión\nde datos.", fi_FI="Puhetietojen lataaminen on keskeytynyt. Muodosta datayhteys.", fr_FR="Le téléchargement des données linguistiques a été interrompu. Veuillez\nétablir une connexion de données.", hu_HU="A beszédadatok letöltése megszakadt. Kérünk, hozd létre az\nadatkapcsolatot.", it_IT="Il download dei dati vocali è stato interrotto. Stabilire un collegamento dati.", nl_NL="De download van de taalgegevens is onderbroken. Breng gegevensverbinding\ntot stand.", no_NO="Nedlasting av stemmedata er avbrutt. Opprett dataforbindelse.", pl_PL="Pobieranie danych językowych zostało przerwane. Proszę nawiązać\npołączenie danych.", pt_PT="O download dos dados de voz foi interrompido. Por favor, estabelece uma\nligação de daqdos.", ru_RU="Загрузка голосовых данных была прервана. Пожалуйста, установите\nсоединение для передачи данных.", sv_SE="Nedladdningen av språkdata har avbrutits. Upprätta en dataanslutning.", tr_TR="Ses verilerinin indirilmesi yarıda kesildi. Lütfen bir veri bağlantısı kur.")
